window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q08"]=window.__LIBQ["tien-nghich"]["q08"]||{};window.__LIBQ["tien-nghich"]["q08"]["artifacts"]={"updatedAt":"2026-07-09","count":166,"artifacts":[{"id":"binh-tro-cot-ton-thai","name":"Bình tro cốt Tôn Thái","cn":"","category":"khac","categoryLabel":"Vật phẩm mai táng","phamCap":"Phàm vật","soHuu":["Vương Lâm"],"trangThai":"Đã an táng","blurb":"Bình nhỏ chứa tro cốt Tôn Thái được Vương Lâm mang về quê nhà. Nó được đặt xuống đất để hoàn thành việc an táng người chết tha hương.","detail":"Vương Lâm đem bình tro cốt của Tôn Thái chôn xuống đất, sau đó dựng bia “Tôn Thái chi mộ”. Vật này gắn với cảm khái của Vương Lâm về sinh tử, cố hương và nỗi chua xót của người tu đạo.","nguon":["@c0888"]},{"id":"mo-bia-ton-thai","name":"Mộ bia Tôn Thái","cn":"","category":"khac","categoryLabel":"Mộ bia","phamCap":"Không rõ","soHuu":["Tôn Thái"],"trangThai":"Đã dựng","blurb":"Mộ bia do Vương Lâm tạo ra sau khi chôn tro cốt Tôn Thái. Trên bia ghi “Tôn Thái chi mộ”.","detail":"Sau khi đặt bình tro cốt xuống đất, Vương Lâm vẽ tinh quang trên hư không để lập bia mộ cho Tôn Thái. Mộ bia đánh dấu việc Tôn Thái được đưa về quê sau khi chết nơi đất khách.","nguon":["@c0888"]},{"id":"muoi-ba-huyet-cau-la-phu","name":"Mười ba huyết cầu La Phù","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Liệt Vân Tử","Vương Lâm"],"trangThai":"Một huyết cầu đã giao cho Vương Lâm","blurb":"Mười ba huyết cầu La Phù lơ lửng quanh Liệt Vân Tử, giúp lão tăng thần thức và trấn giữ tiền tuyến. Vương Lâm đòi một huyết cầu làm điều kiện trước khi xem Đệ Nhị Phúc Chiến Tự Thiếp.","detail":"La Phù được Liệt Vân Tử dùng để dung nhập thần thức, mở rộng phạm vi cảm ứng và phòng bị Liên Minh Tu Chân tấn công. Sau màn Vương Lâm chấn nhiếp Hứa Đình, hắn dùng tư cách mới để mặc cả, nhắc tới sư huynh làm sức ép, buộc Liệt Vân Tử giao một huyết cầu cho mình.","nguon":["@c0888"]},{"id":"chien-tu-thiep-de-nhi-phuc","name":"Chiến Tự Thiếp — Đệ Nhị Phúc","cn":"","aliases":["Đệ Nhị Phúc Chiến Tự Thiếp"],"category":"phap-bao","categoryLabel":"Tranh pháp bảo","phamCap":"Bảo vật trọng yếu Chiến Gia","soHuu":["Liệt Vân Tử"],"trangThai":"Được mở trước mặt Hứa Đình","blurb":"Bức tranh màu đen thuộc Tam Phúc Chiến Tự Thiếp của Chiến Gia. Khi mở ra, chiến ý trong tranh bùng lên dữ dội như hung thú viễn cổ phá phong ấn.","detail":"Liệt Vân Tử lấy Đệ Nhị Phúc ra theo lời hứa cũ với Vương Lâm, nhưng Vương Lâm không mở ngay mà chuyển cho Hứa Đình xem trước. Chiến ý từ tranh gầm rống phóng ra, khiến Liệt Vân Tử căng thẳng vì nhiều thiên tài Chiến Gia từng trọng thương, tàn phế hoặc hình thần câu diệt khi tiếp xúc bức tranh này.","nguon":["@c0888"]},{"id":"chien-tu-thiep-de-nhat-phuc","name":"Chiến Tự Thiếp — Đệ Nhất Phúc","cn":"","category":"phap-bao","categoryLabel":"Tranh pháp bảo","phamCap":"Bảo vật trọng yếu Chiến Gia","soHuu":["Chiến Gia"],"trangThai":"Được nhắc lại","blurb":"Bức thứ nhất trong Chiến Tự Thiếp, từng được nhắc tới trong liên hệ với Hứa Đình và Vương Lâm. Chương này dùng Đệ Nhất Phúc làm đối chiếu trước khi Hứa Đình bị đẩy xem Đệ Nhị Phúc.","detail":"Đệ Nhất Phúc được nhắc lại là bức tranh năm xưa Hứa Đình từng xem trước, đồng thời Liệt Vân Tử từng cho Vương Lâm xem khi phong tiên. Chi tiết này trở thành lý do Vương Lâm đưa Đệ Nhị Phúc cho Hứa Đình mở trước.","nguon":["@c0888"]},{"id":"tam-phuc-chien-tu-thiep","name":"Tam Phúc Chiến Tự Thiếp","cn":"","category":"phap-bao","categoryLabel":"Bộ tranh pháp bảo","phamCap":"Bảo vật trọng yếu Chiến Gia","soHuu":["Chiến Gia"],"trangThai":"Đã xác nhận Đệ Nhị Phúc","blurb":"Bộ ba bức Chiến Tự Thiếp của Chiến Gia. Chương này xác nhận Đệ Nhị Phúc là một phần trong bộ pháp bảo này.","detail":"Tam Phúc Chiến Tự Thiếp là bộ bảo vật của Chiến Gia mà Liệt Vân Tử coi trọng. Đệ Nhị Phúc trong bộ được mang ra trước Vương Lâm và Hứa Đình, bộc lộ chiến ý nguy hiểm khi mở tranh.","nguon":["@c0888"]},{"id":"thu-linh-do-chien-y-hoa-thanh","name":"Thú linh do chiến ý hóa thành","cn":"","category":"khac","categoryLabel":"Linh thể trong tranh","phamCap":"không rõ","soHuu":["Chiến Tự Thiếp Đệ Nhị Phúc"],"trangThai":"ton-tai","blurb":"Linh thể do sương đen và chiến ý trong Chiến Tự Thiếp hóa thành. Nó thôn phệ Hứa Đình nhưng sợ khí tức Cổ Thần Vương Tộc Ngũ Tinh của Vương Lâm.","detail":"Khi Chiến Tự Thiếp Đệ Nhị Phúc được mở đến bảy phần, sương đen bên trong hóa thành thú khổng lồ lao ra. Thú linh khiến Hứa Đình trọng thương và hút mất bản nguyên hắn từng thu được, nhưng khi đối mặt Vương Lâm thì bị khí tức Cổ Thần Vương Tộc Ngũ Tinh áp chế phải rút về tranh.","nguon":["@c0889"]},{"id":"khoi-ngoc-gian-cua-chien-tinh","name":"Khối ngọc giản của Chiến Tinh","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Chiến Tinh","Chiến Gia"],"trangThai":"được Chiến Gia lưu giữ","blurb":"Khối ngọc giản do Chiến Tinh để lại khi mất tích sau bế quan. Bên trong có lời nhắn về truyền thừa khiến người Chiến Gia đủ liệt vào hàng đỉnh phong.","detail":"Sau nghìn năm bế quan của Chiến Tinh, tộc nhân Chiến Gia chỉ thấy Đệ Tam Phúc Chiến Tự Thiếp và khối ngọc giản này, không thấy tiên tổ. Nội dung ngọc giản cho biết nếu Chiến Gia có người nhận được truyền thừa thì đủ đứng vào đỉnh phong.","nguon":["@c0890"]},{"id":"ngoc-gian-khau-quyet-u-minh-dan-lo","name":"Ngọc giản khẩu quyết U Minh Dẫn Lộ","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Thanh Thủy","Vương Lâm"],"trangThai":"đã giao cho Vương Lâm","blurb":"Ngọc giản chứa khẩu quyết pháp thuật U Minh Dẫn Lộ do Thanh Thủy khắc lại. Thanh Thủy ném ngọc giản này cho Vương Lâm trước khi bước vào vòng xoáy.","detail":"Trước khi xâm nhập Sát Vực Giới, Thanh Thủy khắc khẩu quyết pháp thuật vào ngọc giản rồi ném cho Vương Lâm. Vật này ghi lại cách vận dụng U Minh Dẫn Lộ, pháp thuật dùng ý niệm và ký ức của tu sĩ Sát Vực Giới để dẫn đường.","nguon":["@c0890"]},{"id":"chin-muoi-chin-thanh-kinh-thien-kiem","name":"Chín mươi chín thanh Kình Thiên Kiếm","cn":"","category":"phap-bao","categoryLabel":"Kiến trúc pháp bảo giới địa","phamCap":"không rõ","soHuu":["Sát Vực Giới","Tu Chân Liên Minh"],"trangThai":"ton-tai","blurb":"Chín mươi chín thanh đại kiếm chống trời tạo thành kiến trúc đặc thù của Sát Vực Giới. Chúng do Giáo Chủ đời đầu Tu Chân Liên Minh thu thập sắt thép thiên hạ rèn nên.","detail":"Kình Thiên Kiếm là nền kiến trúc biểu tượng của Sát Vực Giới, gắn với cơ cấu chín mươi chín tu sĩ hạch tâm. Khi Thanh Thủy đánh tới, các kiến trúc đại kiếm bị chấn vỡ, đá vụn và sắt thép cuốn thành bão trong giới địa.","nguon":["@c0891"]},{"id":"phi-kiem-ban-menh-cua-tu-si-khuy-niet-trung-ky","name":"Phi kiếm bản mệnh của tu sĩ Khuy Niết trung kỳ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo bản mệnh","phamCap":"không rõ","soHuu":["Tu sĩ Khuy Niết trung kỳ Sát Vực Giới","Vương Lâm"],"trangThai":"bi-doat","blurb":"Phi kiếm bản mệnh trong hồng quang của tu sĩ Khuy Niết trung kỳ Sát Vực Giới. Trên kiếm có nhiều hồn phách bao phủ và bị Vương Lâm dùng bàn tay Cổ Thần đoạt lấy.","detail":"Trong trận đối đầu tại Sát Vực Giới, tu sĩ Khuy Niết trung kỳ phun phi kiếm bản mệnh ra công kích Vương Lâm. Vương Lâm dùng bàn tay Cổ Thần chụp lấy, cắt đứt liên hệ tâm thần giữa phi kiếm và chủ cũ, khiến đối phương bị phản chấn nặng nề.","nguon":["@c0891"]},{"id":"khong-niet-phap-bao-cua-sat-vuc-gioi","name":"Không Niết pháp bảo của Sát Vực giới","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo trấn giới","phamCap":"Không Niết pháp bảo","soHuu":["Sát Vực Giới","Lăng Vân Tử"],"trangThai":"bị tổn hại nghiêm trọng","blurb":"Pháp bảo trấn giới của Sát Vực Giới, do đại trưởng lão Tu Chân Liên Minh từng tặng giới chủ thứ nhất.","detail":"Pháp bảo này đã bị tổn hại nghiêm trọng nhưng vẫn còn hùng mạnh, được Lăng Vân Tử xem là chỗ dựa để giao chiến với Thanh Thủy và lập công lớn trong biến cố Sát Vực Giới.","nguon":["@c0892"]},{"id":"muoi-mot-phi-kiem-mau-bac-cua-sat-vuc-gioi","name":"Mười một phi kiếm màu bạc của Sát Vực giới","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"Không rõ","soHuu":["Sát Vực Giới"],"trangThai":"đang truy kích Vương Lâm","blurb":"Mười một thanh phi kiếm nằm trong tinh quang, mang sát khí và vô số hồn phách của Sát Vực Giới.","detail":"Bộ phi kiếm do giới chủ thứ nhất Sát Vực Giới sưu tầm tinh thiết thiên hạ rèn thành, được tế luyện vô số vạn năm. Các phi kiếm cùng nhập hư vô truy kích Vương Lâm, khiến hắn nảy ý thu gom đủ chín mươi chín thanh để làm chỗ dựa đối đầu Lăng Thiên Hậu.","nguon":["@c0892"]},{"id":"truong-kiem-mau-bac-khac-chu-chin","name":"Trường kiếm màu bạc khắc chữ “Chín”","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã khuất phục Vương Lâm","blurb":"Một trong mười một phi kiếm Sát Vực Giới, thân kiếm dài bảy thước và khắc chữ “Chín”.","detail":"Thanh kiếm này bị Vương Lâm dùng bàn tay Cổ Thần bắt giữ rồi dùng nguyên thần Thái Cổ Lôi Long dẫn lôi đình trấn áp tàn hồn bên trong. Sau khi tinh quang tan vỡ, nó lộ thân kiếm bạc và khuất phục Vương Lâm.","nguon":["@c0892"]},{"id":"phong-tien-an-muoi-tam-tang-dia-nguc","name":"Phong Tiên Ấn mười tám tầng địa ngục","cn":"","aliases":["Phong Tiên Ấn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Phong Tiên Ấn dạng mười tám tầng địa ngục, được Vương Lâm mở ra để thả vô số oan hồn.","detail":"Trong vòng vây Sát Vực Giới, Vương Lâm phun ra Phong Tiên Ấn, mở cánh cửa mười tám tầng địa ngục và phối hợp Tát Đậu Thành Binh để vô số hồn phách tấn công bốn phía.","nguon":["@c0892"]},{"id":"bon-bach-ngoc-ho-lo","name":"Bốn Bạch Ngọc Hồ Lô","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão nhân Khuy Niết hậu kỳ"],"trangThai":"đang dùng","blurb":"Bốn hồ lô trong suốt do lão nhân Khuy Niết hậu kỳ của Sát Vực Giới sử dụng.","detail":"Khi lão nhân Khuy Niết hậu kỳ mời Bảo Hồ Lô Tiên, bốn Bạch Ngọc Hồ Lô phun khí trắng ngà, hóa thành bốn hư ảnh nữ nhân tấn công Vương Lâm.","nguon":["@c0892"]},{"id":"bao-ho-lo-tien","name":"Bảo Hồ Lô Tiên","cn":"","category":"khac","categoryLabel":"Linh trong pháp bảo","phamCap":"Không rõ","soHuu":["Lão nhân Khuy Niết hậu kỳ"],"trangThai":"được triệu ra","blurb":"Linh hoặc hiện tượng pháp bảo được lão nhân Khuy Niết hậu kỳ mời ra từ bốn Bạch Ngọc Hồ Lô.","detail":"Bảo Hồ Lô Tiên biểu hiện thành bốn hư ảnh nữ nhân từ bốn Bạch Ngọc Hồ Lô, được gọi ra để phối hợp cuộc vây công Vương Lâm tại Sát Vực Giới.","nguon":["@c0892"]},{"id":"bon-nguyen-than-chi-kiem-cua-lang-thien-hau","name":"Bốn nguyên thần chi kiếm của Lăng Thiên Hậu","cn":"","aliases":["Bốn thanh nguyên thần chi kiếm","Bốn thanh kiếm hư ảo sau lưng Lăng Thiên Hậu"],"category":"phap-bao","categoryLabel":"Nguyên thần chi kiếm","phamCap":"Không rõ","soHuu":["Lăng Thiên Hậu"],"trangThai":"đang thuộc Lăng Thiên Hậu","blurb":"Bốn đạo nguyên thần chi kiếm của Lăng Thiên Hậu, từng được Vương Lâm lấy làm chuẩn so sánh khi đánh giá bộ phi kiếm Sát Vực Giới.","detail":"Theo đối chiếu, bốn đạo nguyên thần chi kiếm này do Lăng Thiên Hậu luyện hóa bốn tiểu thiên địa ngưng thành. Vương Lâm cho rằng nếu gom đủ chín mươi chín phi kiếm Sát Vực Giới, phẩm chất và thần thông của bộ kiếm ấy còn có thể cao hơn không ít.","nguon":["@c0892"]},{"id":"truong-kiem-bay-thuoc","name":"Trường kiếm bảy thước","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"bị Vương Lâm thu phục","blurb":"Thanh trường kiếm dài bảy thước, rộng ba tấc, mũi kiếm màu bạch ngân như ánh trăng. Vương Lâm đóng lạc ấn thần thức lên nó và khen là kiếm tốt.","detail":"Trường kiếm bảy thước xuất hiện giữa chiến trường Sát Vực giới. Vương Lâm vỗ tay lên kiếm, đưa lạc ấn thần thức vào sâu bên trong, khiến kiếm khí lao ra và trường kiếm xoay quanh hắn trước khi bị thu phục.","nguon":["@c0893"]},{"id":"chin-thanh-phi-kiem-hop-nhat","name":"Chín thanh phi kiếm hợp nhất","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"không rõ","soHuu":["Huyễn Hư Tử"],"trangThai":"đang hoạt động","blurb":"Chín thanh phi kiếm còn lại đồng loạt phát kiếm minh và hợp nhất thành một kiếm lớn. Kiếm lớn mang kiếm quang âm hàn, đâm tới Vương Lâm rồi thần phục bên cạnh Huyễn Hư Tử.","detail":"Khi Vương Lâm đoạt một thanh kiếm khác, chín thanh kiếm còn lại cùng phát kiếm minh rồi dung hợp thành một đại kiếm có kiếm mang lăng lệ và khí âm hàn. Sau đó đại kiếm này xuất hiện bên cạnh Huyễn Hư Tử, cho thấy nó gắn với thế công của hắn trong Sát Vực giới.","nguon":["@c0893"]},{"id":"tram-cai-toc-mau-tim","name":"Trâm cài tóc màu tím","cn":"","aliases":["phượng trâm màu tím"],"category":"phap-bao","categoryLabel":"Di vật","phamCap":"Không rõ","soHuu":["Thanh Thủy","Hàm Yên"],"trangThai":"Thanh Thủy giữ","blurb":"Chiếc trâm cài tóc màu tím là di vật gắn với Hàm Yên, thê tử đã mất của Thanh Thủy. Nó gợi lại hồi ức bi thương và lời thề truy tìm nguyên nhân bi kịch của hắn.","detail":"Thanh Thủy thu sương tím, bên cạnh hiện ra chiếc phượng trâm màu tím. Khi nhìn trâm, hắn lộ vẻ dịu dàng, xem những kẻ bị giết như sẽ làm bạn với di vật của thê tử mình. Về cuối chương, trâm cài tóc dẫn Thanh Thủy trở lại hồi ức về Hàm Yên, chuyện hắn từng tặng trâm cho nàng và nỗi đau khi nàng tự tuyệt trong lúc hắn điên cuồng.","nguon":["@c0894"]},{"id":"muoi-tam-dao-ngan-quang","name":"Mười tám đạo ngân quang","cn":"","aliases":["ngân đoàn"],"category":"phap-bao","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm nhận từ Thanh Thủy","blurb":"Mười tám đạo ngân quang được Thanh Thủy thu từ dung nham rồi nhập lại thành một đoàn. Hắn ném vật này cho Vương Lâm vì biết Vương Lâm thích nó.","detail":"Sau khi Sát Vực Giới bị Sơn Băng tàn phá, Thanh Thủy lấy mười tám đạo ngân quang từ dưới dung nham, hợp thành một đoàn rồi giao cho Vương Lâm. Vật phẩm được nhấn mạnh riêng trong lúc hai người chia tay.","nguon":["@c0894"]},{"id":"no-an-tien-gioi","name":"Nô ấn tiên giới","cn":"","aliases":["nô ấn"],"category":"khac","categoryLabel":"Ấn ký","phamCap":"Tiên giới","soHuu":["Thanh Thủy"],"trangThai":"Đặt lên Huyễn Hư Tử và Lăng Vân Tử","blurb":"Nô ấn tiên giới là ấn ký xuất hiện trên mi tâm Huyễn Hư Tử và Lăng Vân Tử sau khi bị Thanh Thủy bắt giữ. Nó thể hiện hai người đã bị chế thành nô.","detail":"Khi Thanh Thủy hóa hắc phong cuốn Huyễn Hư Tử và giới chủ Sát Vực Giới rời đi, trên mi tâm hai người xuất hiện ấn độc đáo của tiên giới. Chương gọi rõ đó là nô ấn, đánh dấu kết cục hai kẻ sống sót sau khi Sát Vực Giới bị diệt.","nguon":["@c0894"]},{"id":"xa-than-xa-thu-ba","name":"Xạ Thần Xa thứ ba","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Một chiếc Xạ Thần Xa của Vương Lâm, đã lâu không dùng và được lấy ra khi lực tự bạo chặn đường.","detail":"Khi đại hán Cự Ma Tộc thứ hai tự bạo nguyên thần để chặn truy kích, Vương Lâm bình tĩnh vỗ túi trữ vật lấy Xạ Thần Xa thứ ba. Pháp bảo vừa xuất hiện liền hóa thành một con bướm nhiều màu sắc.","nguon":["@c0896"]},{"id":"anh-dao-cua-thanh-nien-ao-lam","name":"Anh đào của thanh niên áo lam","cn":"","category":"khac","categoryLabel":"Vật phẩm công kích","phamCap":"không rõ","soHuu":["Thanh niên áo lam nội tông đệ tử Thi Âm Tông"],"trangThai":"đã dùng","blurb":"Quả anh đào được thanh niên áo lam ném ra khi muốn cứu Tôn Cẩu Tử.","detail":"Quả anh đào vỡ thành dịch đỏ thẫm rồi hóa thành công kích quỷ dị bằng mũi xương khô. Vương Lâm dùng thân thể Cự Ma Tộc bị Tôn Cẩu Tử đoạt xá làm vật chắn, khiến thân thể ấy bị phá nát và huyết nhục bị hút sạch.","nguon":["@c0896"]},{"id":"mui-xuong-kho-mau-luc-lam","name":"Mũi xương khô màu lục lam","cn":"","category":"khac","categoryLabel":"Thần thông hóa vật","phamCap":"không rõ","soHuu":["Thanh niên áo lam nội tông đệ tử Thi Âm Tông"],"trangThai":"đã dùng","blurb":"Công kích quỷ dị do anh đào của thanh niên áo lam biến hóa, có dịch đỏ thẫm vờn quanh.","detail":"Mũi xương khô màu lục lam xuất hiện sau khi quả anh đào vỡ ra, kèm tiếng gào rít thê lương. Nó phá nát thân thể Cự Ma Tộc bị Vương Lâm đá tới và hấp thu huyết nhục tản ra.","nguon":["@c0896"]},{"id":"doc-thu-an-tren-dai-dau","name":"Độc thủ ấn trên Đại Đầu","cn":"","category":"khac","categoryLabel":"Ấn độc","phamCap":"không rõ","soHuu":["Đại Đầu"],"trangThai":"đã hóa giải","blurb":"Dấu tay đen trên người Đại Đầu, chứa năm tàn hồn màu đen và khiến hắn bị tử khí xâm nhiễm.","detail":"Độc thủ ấn lưu trên ngực Đại Đầu, khiến thân thể hắn tràn tử khí. Vương Lâm dùng nguyên lực ép thủ ấn hóa thành năm tàn hồn màu đen rồi dùng thần niệm đánh tan, khiến hắc khí và máu đen bị đẩy ra ngoài.","nguon":["@c0896"]},{"id":"huyet-yen","name":"Huyết yến","cn":"","category":"khac","categoryLabel":"Linh vật / vật phẩm","phamCap":"chưa rõ","soHuu":["Con bướm nhiều màu"],"trangThai":"bị con bướm nhiều màu cướp từ Huyết Thần Tử","blurb":"Huyết yến là vật năm đó của Huyết Thần Tử nhưng đã bị con bướm nhiều màu cướp đi. Trong chương này nó xuất hiện đi cùng con bướm nhiều màu.","detail":"Huyết yến được nhắc rõ là vật cũ của Huyết Thần Tử. Hiện nó không còn thuộc Huyết Thần Tử mà ở bên con bướm nhiều màu, cho thấy giữa con bướm và tuyến Huyết Thần Tử từng có va chạm trước đó.","nguon":["@c0897"]},{"id":"o-quang-bao-menh","name":"Ô quang bảo mệnh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo giữ mạng","phamCap":"chưa rõ","soHuu":["Thanh niên áo lam"],"trangThai":"đã kích phát cứu chủ","blurb":"Ô quang bảo mệnh là thủ đoạn giữ mạng trên người thanh niên áo lam. Nó hóa giải một nửa công kích của con bướm nhiều màu, giúp hắn trọng thương nhưng chưa chết.","detail":"Khi thanh niên áo lam bị công kích qua lốc xoáy, trên người hắn có một đạo ô quang bùng ra. Vương Lâm nhận ra ô quang này đã hóa giải một nửa lực tấn công, nhờ vậy nguyên thần thanh niên áo lam còn có thể trốn về hồn hải bí mật trong Liên Minh Tinh Vực.","nguon":["@c0897"]},{"id":"lenh-bai-tien-phu","name":"Lệnh bài tiên phủ","cn":"","aliases":["Lệnh bài vào Yêu Linh Chi Địa"],"category":"khac","categoryLabel":"Vật phẩm then chốt","phamCap":"liên quan tiên phủ Triều Tịch Chi Địa","soHuu":["Vương Lâm"],"trangThai":"đang là tâm điểm tranh đoạt","blurb":"Lệnh bài tiên phủ là vật phẩm khiến nhiều thế lực và lão quái nhắm vào Vương Lâm. Chương này xác nhận nó là căn nguyên nguy cơ trong chuyến trở về Thiên Vận tinh.","detail":"Vương Lâm tự nhận định khối lệnh bài tiên phủ năm đó là thứ nhiều bên muốn đoạt, kéo theo Huyết Tổ, Thiên Vận Tử và việc hắn phải rời đi khi tu vi còn yếu. Ngoài Thiên Vận Tông, Lăng Thiên Hậu cũng truy vấn Thiên Vận Tử vì lệnh bài mà Vương Lâm từng lấy đi, khiến vật này tiếp tục là trung tâm xung đột.","nguon":["@c0897"]},{"id":"hoa-hong-ky-lan","name":"Hỏa Hồng Kỳ Lân","cn":"","category":"khac","categoryLabel":"Tọa kỵ","phamCap":"chưa rõ","soHuu":["Lăng Thiên Hậu"],"trangThai":"đang được Lăng Thiên Hậu cưỡi","blurb":"Hỏa Hồng Kỳ Lân là tọa kỵ thần võ của Lăng Thiên Hậu khi xuất hiện ngoài Thiên Vận Tông. Nó toàn thân phát lửa và mũi phun bạch khí.","detail":"Lăng Thiên Hậu cưỡi Hỏa Hồng Kỳ Lân khi dẫn đệ tử Đại La Kiếm Tông tới vây ngoài Thiên Vận Tông. Tọa kỵ này làm nổi bật uy thế của Kiếm Tôn trong buổi chờ thiên cơ liên quan Vương Lâm và lệnh bài tiên phủ.","nguon":["@c0897"]},{"id":"chu-tuoc-an-ky-vat-pham","name":"Chu tước ấn ký","cn":"","aliases":[],"category":"khac","categoryLabel":"Ấn ký","phamCap":"khong-ro","soHuu":["Vương Lâm"],"trangThai":"đang hiện trên mi tâm Vương Lâm","blurb":"Ấn ký trên mi tâm Vương Lâm, được mỹ phụ thôn nữ trung niên nhận ra là Chu tước ấn ký.","detail":"Khi Vương Lâm trở lại Thiên Vận Tông, ấn ký trên mi tâm hắn khiến mỹ phụ thôn nữ trung niên khẽ kêu nhận ra. Lăng Thiên Hậu cũng chú ý tới ấn ký này cùng các lực lượng khác trong mi tâm Vương Lâm.","nguon":["@c0898"]},{"id":"bon-muoi-lam-phi-kiem-cua-vuong-lam","name":"Bốn mươi lăm phi kiếm của Vương Lâm","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bốn mươi lăm phi kiếm của Vương Lâm là nhóm phi kiếm vốn liên quan Sát Vực giới, đã được hắn tế luyện và cải biến hình dạng. Chúng mang sát khí vô tận, lập thành Tam Cửu Chi Kiếm rồi Ngũ Cửu Kiếm Trận.","detail":"Trên đường tới Thiên Vận Tông, Vương Lâm đã tế luyện và thay đổi hình dạng nhóm phi kiếm này khiến người ngoài Sát Vực giới khó nhận ra lai lịch. Trong trận với Lăng Thiên Hậu, hai mươi bảy phi kiếm ban đầu lập Tam Cửu Chi Kiếm, sau đó tăng thành bốn mươi lăm thanh tạo Ngũ Cửu Kiếm Trận để chống Huyết Chú Kiếm.","nguon":["@c0899"]},{"id":"quy-nhan-ngoc-gian","name":"Quỷ Nhãn ngọc giản","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Lý sư huynh"],"trangThai":"đang được Lý sư huynh giữ @c0900","blurb":"Khối ngọc giản màu tối liên quan tới Quỷ Nhãn phường thị. Trung tâm ngọc giản có hồng quang quỷ dị, được Lý sư huynh lấy ra khi nói về cơ hội giao dịch.","detail":"Lý sư huynh lấy Quỷ Nhãn ngọc giản ra trong lúc nói với sư muội về Quỷ Nhãn phường thị sắp mở lại. Sư muội nhận ra vật này, cho thấy nó là tín vật hoặc vật dẫn thông tin gắn với phường thị và khu giao dịch bên ngoài.","nguon":["@c0900"]},{"id":"bo-tien-thuat-day-du-dau-gia-quy-nhan-thanh","name":"Bộ tiên thuật đầy đủ từng được bán đấu giá","cn":"","category":"khac","categoryLabel":"Công pháp đấu giá","phamCap":"Không rõ","soHuu":["Quỷ Nhãn Thành"],"trangThai":"khong-ro","blurb":"Bộ tiên thuật đầy đủ từng được Quỷ Nhãn Thành bán đấu giá nhiều năm trước, làm nên danh tiếng của thành.","detail":"Quỷ Nhãn Thành nổi danh nhiều năm trước vì từng bán đấu giá một bộ tiên thuật đầy đủ, khiến mỗi lần mở thành đều hấp dẫn lượng lớn tu sĩ tới đấu giá và giao dịch.","nguon":["@c0904"]},{"id":"tu-ngoc-dich","name":"Tử Ngọc Dịch","category":"khac","categoryLabel":"Bảo vật","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Một bình bảo dịch sắp được đấu giá tại Quỷ Nhãn thành, khiến Vương Lâm có hứng thú và nhận lời lưu lại.","detail":"Nhất Trần Tử cho rằng Vương Lâm tới Quỷ Nhãn thành có lẽ vì bình Tử Ngọc Dịch sắp đấu giá còn vài ngày nữa. Vương Lâm nghe tên thấy quen tai và có hứng thú nên đồng ý ở lại chờ cuộc đấu giá.","nguon":["@c0905"]},{"id":"mu-rom-cua-co-nhan","name":"Mũ rơm của cố nhân","cn":"","category":"khac","categoryLabel":"Vật phẩm cấm chế","phamCap":"Không rõ","soHuu":["Linh Nhi","Vương Lâm"],"trangThai":"Linh Nhi đang giữ","blurb":"Mũ rơm của cố nhân là vật Vương Lâm từng nhận được, có khả năng che giấu hết thảy khí tức. Hắn trao vật này cho Linh Nhi để giúp nàng che giấu Thủy Linh thể.","detail":"Vương Lâm lấy mũ rơm đặt lên bàn khi nghe về thể chất Thủy Linh thể của Linh Nhi, đồng thời nhớ tới bóng dáng cố nhân. Vật này không phải tiên bảo thông thường nhưng chứa nhiều cấm chế tinh diệu, có thể che giấu khí tức và sau khi Nhất Trần Tử tế luyện sẽ trở thành vật bảo hộ thích hợp cho Linh Nhi.","nguon":["@c0906"]},{"id":"ba-cai-chuong","name":"Ba cái chuông","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Linh Nhi","Vương Lâm"],"trangThai":"Linh Nhi đang giữ","blurb":"Ba cái chuông là vật Vương Lâm lấy ra tặng Linh Nhi trong đình. Tiếng chuông trong trẻo khiến nàng vui thích, còn Nhất Trần Tử nhìn ra chúng không tầm thường.","detail":"Sau khi tặng mũ rơm, Vương Lâm lại lấy ba cái chuông từ túi trữ vật đưa cho Linh Nhi. Nàng lắc thử, tiếng chuông trong trẻo vang lên khắp nơi, biểu hiện rõ sự vui mừng trước món quà.","nguon":["@c0906"]},{"id":"thien-minh-thach","name":"Thiên Minh Thạch","cn":"","category":"nguyen-lieu","categoryLabel":"Bảo vật","phamCap":"Không rõ","soHuu":["Vương Lâm","Nhất Trần Tử"],"trangThai":"Vương Lâm đang giữ","blurb":"Thiên Minh Thạch là khối đá đen Nhất Trần Tử tặng Vương Lâm để đáp lễ. Nó có thể ký thác nguyên thần, biến ảo phân thân hoặc chứa đựng đại thần thông.","detail":"Nhất Trần Tử lấy Thiên Minh Thạch ra vì hổ thẹn trước việc từng trêu chọc Vương Lâm mà nay lại nhận hậu lễ cho hậu nhân. Vương Lâm dùng thần thức kiểm tra và nhận ra khối đá có khả năng hấp thu, bảo tồn thần thức, nhập thần thông, đồng thời biến hóa thành hư ảo phân thân theo tâm niệm.","nguon":["@c0906"]},{"id":"tia-chi-duong-trong-co-the-bach-nguy","name":"Tia chí dương trong cơ thể Bạch Nguy","cn":"","category":"khac","categoryLabel":"Khí đặc thù","phamCap":"không rõ","soHuu":["Bạch Nguy"],"trangThai":"được Bạch Nguy định trao cho Vương Lâm","blurb":"Tia chí dương là thứ nghìn năm luyện thành trong cơ thể Bạch Nguy. Đây là vật Thiên Vận Tử cực kỳ mong muốn và Bạch Nguy muốn dùng để phá tính toán của hắn.","detail":"Bạch Nguy nói trước khi chết muốn đem tia chí dương trong cơ thể tặng cho Vương Lâm. Nếu Vương Lâm nhận, Thiên Vận Tử sẽ bị kéo vào một sai lệch ngoài tính toán; nếu không nhận, bóng ma về sự tính toán không sai của Thiên Vận Tử sẽ đè lên đạo tâm Vương Lâm.","nguon":["@c0908"]},{"id":"an-ky-quy-di-tren-nguoi-bach-nguy","name":"Ấn ký quỷ dị trên người Bạch Nguy","cn":"","category":"khac","categoryLabel":"Ấn ký","phamCap":"không rõ","soHuu":["Bạch Nguy"],"trangThai":"đang phát tác","blurb":"Ấn ký quỷ dị trên người Bạch Nguy phát tác mỗi khi hắn nói chuyện liên quan tới bản thân. Nó khiến âm khí tăng mạnh và Âm Dương Song Dục quyết tự vận chuyển.","detail":"Bạch Nguy cho biết mỗi lần nhắc tới chuyện của mình, ấn ký trên người sẽ phát tác, làm âm khí trong cơ thể tăng lên và công pháp tự vận hành. Hiện tượng này gắn trực tiếp với dị biến do Âm Dương Song Dục quyết và mưu tính của Thiên Vận Tử.","nguon":["@c0908"]},{"id":"hoan-vu-chi-tinh","name":"Hoán vũ chi tinh","cn":"","category":"phap-bao","categoryLabel":"Vật phẩm bảo mệnh","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Vật do Thanh Thủy tặng Vương Lâm, bên trong phong ấn ba đạo Hoán Vũ Thuật.","detail":"Khi một chỉ của Thiên Vận Tử giáng xuống thung lũng, Vương Lâm lấy hoán vũ chi tinh ra để làm thủ đoạn bảo mệnh. Vật này chứa ba đạo Hoán Vũ Thuật do chính Thanh Thủy thi triển và phong ấn.","nguon":["@c0910"]},{"id":"mot-tia-cuc-duong","name":"Một tia cực dương","cn":"","category":"khac","categoryLabel":"Năng lượng","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tia cực dương được Vương Lâm nắm trong tay trước khi đối mặt thần thông Thiên Vận Tử.","detail":"Khi Vương Lâm nắm một tia cực dương, Thiên Nghịch trong nguyên thần hơi run lên. Do uy áp của một chỉ đang giáng xuống, hắn chưa kịp suy xét biến hóa này mà thu tia cực dương vào túi trữ vật.","nguon":["@c0910"]},{"id":"tien-gioi-toai-phien","name":"Tiên giới toái phiến","cn":"","category":"phap-bao","categoryLabel":"Vật phẩm bảo mệnh","phamCap":"Tiên giới toái phiến","soHuu":["Vương Lâm"],"trangThai":"Đang được dùng, đã nứt nhưng chưa sụp","blurb":"Tiên giới toái phiến là mảnh vỡ do Viêm Lôi Tử từng tặng Vương Lâm sau công lao ở La Thiên. Trong chương này, nó được phóng đại thành một đại lục khổng lồ để chặn một chỉ của Thiên Vận Tử.","detail":"Khi một chỉ của Thiên Vận Tử ép xuống như trời sập, Vương Lâm lấy mảnh tiên giới toái phiến từng được Viêm Lôi Tử nói có tác dụng bảo mệnh. Mảnh toái phiến phóng đại thành một lục địa khổng lồ, ngăn cách Vương Lâm với đầu ngón tay; một chỉ đánh xuống khiến đại lục nứt vỡ nhưng chưa sụp đổ, tạo cơ hội để Vương Lâm phản kích.","nguon":["@c0911"]},{"id":"binh-dan-duoc-cua-thanh-chu-quy-nhan-thanh","name":"Bình đan dược của thành chủ Quỷ Nhãn thành","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Thành chủ Quỷ Nhãn thành"],"trangThai":"Đã dùng","blurb":"Bình đan dược này được thành chủ Quỷ Nhãn thành lấy ra sau khi bị cường quang từ Hoán Vũ Chi Tinh làm tổn thương mắt. Hắn nuốt đan dược rồi dùng thần thức tiếp tục quan sát trận chiến.","detail":"Trong lúc mạo hiểm quan sát trận chiến giữa Vương Lâm và một chỉ của Thiên Vận Tử, thành chủ Quỷ Nhãn thành bị cường quang từ Hoán Vũ Chi Tinh làm đau mắt phải lui lại. Hắn lấy một bình đan dược lớn từ túi trữ vật, nuốt vào để ổn định thương tổn rồi nhắm mắt tản thần thức theo dõi tiếp.","nguon":["@c0911"]},{"id":"vuong-mien","name":"Vương miện","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm giữ trong túi trữ vật","blurb":"Pháp bảo Vương Lâm định lấy ra để đối phó Phong Long bảy màu.","detail":"Vương Lâm nhớ lại lần dùng vương miện thu Hoàng bào Chân Long trong cơ thể Vọng Nguyệt, nên khi nhận ra bên trong Phong Long bảy màu có linh hồn rồng thật, hắn đặt tay lên túi trữ vật định lấy vương miện ra để khắc chế Long Linh.","nguon":["@c0912"]},{"id":"manh-vo-tien-gioi","name":"Mảnh vỡ Tiên Giới","aliases":["Đại lục Tiên Giới"],"cn":"","category":"khac","categoryLabel":"Địa khối phòng hộ","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang bảo hộ quanh Vương Lâm","blurb":"Mảnh đại lục Tiên Giới nơi Vương Lâm đứng khi giao chiến với ngón tay khổng lồ.","detail":"Trong lúc đối quyền với một chỉ của Thiên Vận Tử, Vương Lâm bị phản chấn lùi trên mảnh vỡ Tiên Giới và để lại dấu chân. Sau đó hắn đạp xuống khiến mảnh vỡ thu nhỏ lại, xoay quanh ngoài thân để bảo hộ mình khi đối diện Phong Long bảy màu và cuộc can thiệp của Lăng Thiên Hậu.","nguon":["@c0912"]},{"id":"vu-tien-kiem-hinh-ran","name":"Vũ Tiên Kiếm hình rắn","cn":"","aliases":["Vũ Kiếm","Tiên Kiếm hình rắn"],"category":"phap-bao","categoryLabel":"Tiên kiếm","phamCap":"không rõ","soHuu":["Lăng Thiên Hậu"],"trangThai":"đang dùng","blurb":"Thanh kiếm tím hình rắn do Lăng Thiên Hậu nắm giữ, vốn thuộc bốn thanh Vũ Tiên Kiếm ở Vũ Tiên Giới.","detail":"Trong Phá Thiên thức thứ hai, thanh kiếm xuất hiện sau lưng kiếm đồng bảy tám tuổi rồi hóa thành rắn lớn nghìn trượng cuốn gió tanh đánh tới. Vương Lâm nhận ra đây là thanh Vũ Tiên Kiếm từng bị Lăng Thiên Hậu cướp đi ở Vũ Tiên Giới.","nguon":["@c0913"]},{"id":"kiem-nho-mau-den","name":"Kiếm nhỏ màu đen","cn":"","category":"phap-bao","categoryLabel":"Vũ khí do thần thông ngưng tụ","phamCap":"không rõ","soHuu":["Thiên Vận Tử áo xám"],"trangThai":"do thần thông ngưng tụ","blurb":"Thanh kiếm nhỏ bằng ngón tay do Thiên Vận Tử áo xám ngưng tụ từ hắc ám trong trời đất.","detail":"Kiếm được tạo thành khi lực lượng ánh sáng bị hút đi và hắc ám tụ vào tay Thiên Vận Tử áo xám. Ông ta quét ngang thanh kiếm này để phóng ra mười đạo Sát Lục khí chân chính.","nguon":["@c0913"]},{"id":"thanh-kiem-sat-luc","name":"Thanh kiếm Sát Lục","cn":"","category":"phap-bao","categoryLabel":"Kiếm do thần thông ngưng tụ","phamCap":"Không rõ","soHuu":["Thiên Vận Tử áo xám"],"trangThai":"Được ngưng tụ trong giao chiến","blurb":"Thanh kiếm đỏ thẫm do vô số khí Sát Lục hội tụ trước người Thiên Vận Tử áo xám. Nó được dùng để đối đầu với Vũ Kiếm hình rắn và nguyên thần kiếm của Lăng Thiên Hậu.","detail":"Thanh kiếm Sát Lục dài bảy thước, rộng ba thước, do Thiên Vận Tử áo xám dùng Sát Lục Hóa Kiếm ngưng tụ. Trong trận, hắn tiếp tục bổ sung khí Sát Lục vào kiếm để nâng uy lực trước khi hai kiếm va chạm, tạo sấm sét, kiếm khí và gió xoáy bảy màu.","nguon":["@c0914"]},{"id":"thiep-moi-con-hu","name":"Thiệp mời Côn Hư","cn":"","category":"khac","categoryLabel":"Thiệp mời tu luyện","phamCap":"Không rõ","soHuu":["Tu chân tông Côn Hư"],"trangThai":"được phát theo chu kỳ ba ngàn năm","blurb":"Thiệp mời Côn Hư là vật do tu chân tông Côn Hư phát ra để mời tu sĩ vào Côn Hư địa vực tu luyện. Mỗi ba ngàn năm chỉ có ba thiệp mời được phát ra.","detail":"Lăng Thiên Hậu kể rằng tu chân tông Côn Hư cứ ba ngàn năm phát ba thiệp mời cho tu sĩ được phép vào Côn Hư địa vực tu luyện. Năm xưa Lăng Thiên Hậu và Thiên Vận tử từng nhận lời mời này, qua đó tiếp xúc với thế lực Côn Hư.","nguon":["@c0915"]},{"id":"hu-anh-thanh-kiem-o-mi-tam-lang-thien-hau","name":"Hư ảnh thanh kiếm ở mi tâm Lăng Thiên Hậu","cn":"","category":"phap-bao","categoryLabel":"Hư ảnh kiếm","phamCap":"không rõ","soHuu":["Lăng Thiên Hậu"],"trangThai":"dang-co","blurb":"Hư ảnh kiếm được Lăng Thiên Hậu triệu ra từ mi tâm để chống ánh sáng vô hình.","detail":"Khi quan sát biến cố Thiên Nghịch và cảm thấy nguy cơ sinh tử, Lăng Thiên Hậu triệu hư ảnh thanh kiếm từ mi tâm để chống đỡ. Sau va chạm với ánh sáng vô hình, hư ảnh kiếm gần như sụp đổ rồi quay lại mi tâm, còn Lăng Thiên Hậu bị đánh thổ huyết.","nguon":["@c0916"]},{"id":"la-ban-hu-ao-khong-lo","name":"La bàn hư ảo khổng lồ","cn":"","category":"khac","categoryLabel":"Pháp tướng thần thông","phamCap":"không rõ","soHuu":["Thiên Vận Tử"],"trangThai":"dang-co","blurb":"La bàn hư ảo xuất hiện trong tinh không khi Thiên Vận tử thi triển Thiên Vận thuật.","detail":"La bàn hư ảo khổng lồ mang vô số phù văn ấn ký, được Thiên Vận tử triệu ra để suy diễn và chống đỡ bàn tay hư vô. Dưới Phụng Thiên Thừa Vận và Thiên Vật Thuật, nó xoay chuyển rồi tiếp tục bành trướng không ngừng.","nguon":["@c0916"]},{"id":"thien-van-kich","name":"Thiên Vận Kích","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thiên Vận Tử"],"trangThai":"dang-co","blurb":"Đinh ba bạc dài khoảng mười trượng được Thiên Vận Tử giấu trong ba ngọn núi hình chĩa ba trên Thiên Vận tinh.","detail":"Thiên Vận Kích được triệu ra khi ba ngọn núi hình chĩa ba sụp đổ, lộ ra một thanh đinh ba bạc dài khoảng mười trượng. Thiên Vận Tử dùng nó xuyên thủng bàn tay khổng lồ để ép nguyên lực tràn ra, nhưng bàn tay nghịch chuyển bắt lấy pháp bảo và hút ánh bạc từ đó.","nguon":["@c0917"]},{"id":"ba-ngon-nui-giong-chia-ba","name":"Ba ngọn núi giống chĩa ba","cn":"","category":"khac","categoryLabel":"Vật chứa phong tàng","phamCap":"Không rõ","soHuu":["Thiên Vận Tử"],"trangThai":"hong","blurb":"Ba ngọn núi trên Thiên Vận tinh là nơi phong tàng Thiên Vận Kích.","detail":"Ba ngọn núi giống chĩa ba sụp đổ khi Thiên Vận Tử triệu ra Thiên Vận Kích từ bên trong. Chúng vừa là địa hình đặc biệt trên Thiên Vận tinh, vừa đóng vai trò nơi cất giấu pháp bảo đinh ba bạc.","nguon":["@c0917"]},{"id":"canh-cua-thien-nghich","name":"Cánh cửa Thiên Nghịch","cn":"","category":"phap-bao","categoryLabel":"Không gian pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã mở khe cửa @c0918","blurb":"Cánh cửa Thiên Nghịch là cánh cửa lớn trong không gian hư vô của Thiên Nghịch. Khi khe cửa mở, lực xung kích khiến Vương Lâm suýt mê lạc như năm xưa.","detail":"Sau khi lực bổn nguyên dung nhập hạt châu Thiên Nghịch, thần thức Vương Lâm bị cuốn vào không gian hư vô và nhìn thấy cánh cửa lớn đỉnh chạm trời. Khe cửa mở ra tạo lực xung kích khiến hắn suýt mất phương hướng, nhưng khí tức cực dương đã dung nhập thân thể giúp tâm thần hắn tỉnh lại, từ đó hắn bước vào khe cửa để truy tìm bí mật chân chính của Thiên Nghịch.","nguon":["@c0918"]},{"id":"chien-tu-thiep","name":"Chiến tự thiếp","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Chiến tự thiếp là nguồn cung cấp phần lớn lực bổn nguyên trong con mắt thứ ba của Vương Lâm. Lực này được dùng để mở lại Thiên Nghịch ở chương 918.","detail":"Khi con mắt thứ ba của Vương Lâm tự mở, phần lớn lực bổn nguyên bên trong đến từ Chiến tự thiếp, phần còn lại đến từ cảm ngộ ở phù tộc trên Chu Tước tinh. Lực bổn nguyên này dung nhập Thiên Nghịch như chìa khóa, mở ra không gian cánh cửa lớn.","nguon":["@c0918"]},{"id":"hoa-chu-tuoc-mau-den","name":"Hỏa chu tước màu đen","cn":"","category":"khac","categoryLabel":"Tế hỏa","phamCap":"không rõ","soHuu":[],"trangThai":"xuất hiện trước Lăng Thiên Hậu @c0918","blurb":"Hỏa chu tước màu đen là hỏa tượng xuất hiện ở nơi có tế hỏa mà Lăng Thiên Hậu cố lao tới. Trước khi chạm được nơi này, hắn bị bàn tay hư ảo bắt lấy.","detail":"Trong lúc bỏ chạy, Lăng Thiên Hậu nhìn thấy phía trước có một Hỏa chu tước màu đen ở nơi ẩn chứa tế hỏa. Đây là đích hắn muốn tiếp cận, nhưng bàn tay hư ảo phía sau đã cách không nắm lấy hắn và hút đi máu thịt, nguyên lực, nguyên thần cùng linh hồn.","nguon":["@c0918"]},{"id":"bon-tien-phu-o-dat-yeu-linh","name":"Bốn tiên phủ ở đất Yêu Linh","cn":"","category":"khac","categoryLabel":"Tiên phủ","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang tồn tại","blurb":"Bốn tiên phủ tại vùng đất Yêu Linh, trong đó Vương Lâm đã chiếm một chỗ.","detail":"Vương Lâm nhắc rằng mình chiếm một trong bốn tiên phủ ở đất Yêu Linh và có thể mang theo vài người cùng đi, nên quyết định trở về vùng đất Yêu Linh để chuẩn bị.","nguon":["@c0919"]},{"id":"con-thuyen-den-dai-ba-muoi-truong","name":"Con thuyền đen dài ba mươi trượng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phi hành","phamCap":"khong-ro","soHuu":["Phù Phong tử"],"trangThai":"dang-co","blurb":"Pháp bảo hình thuyền màu đen chở Phù Phong tử và đoàn tùy tùng trong tinh không.","detail":"Con thuyền dài chừng ba mươi trượng, toàn thân tối đen, tỏa dao động pháp bảo và linh lực nồng đậm. Trên thuyền có Phù Phong tử, các cô gái hầu hạ, bảy hộ vệ áo đen, còn bên ngoài là hơn trăm tu sĩ áo xanh cưỡi kiếm quang bảo vệ.","nguon":["@c0920"]},{"id":"hac-mang-cua-lao-gia-nui-thit","name":"Hắc mang của lão già núi thịt","cn":"","category":"khac","categoryLabel":"Đòn hoặc pháp bảo chưa xác định","phamCap":"khong-ro","soHuu":["Phù Phong tử"],"trangThai":"da-dung","blurb":"Đạo hắc mang Phù Phong tử phóng ra nhằm can thiệp vào trận của Đầu to.","detail":"Khi Đầu to lao vào bảy hộ vệ áo đen, Phù Phong tử ngồi trên thuyền chỉ tay phóng ra một đạo hắc mang cực nhanh nhắm vào Đầu to. Vương Lâm xuất hiện bên cạnh Đầu to và phất tay đánh tan hắc mang này.","nguon":["@c0920"]},{"id":"thanh-quang-thuan","name":"Thanh quang thuẫn","cn":"","aliases":["thanh quang tiểu thuẫn","tấm thuẫn Cổ Thần","khiên nhỏ ánh sáng xanh","pháp khí Cổ Thần"],"category":"phap-bao","categoryLabel":"Pháp bảo phòng ngự","phamCap":"mang khí tức Cổ Thần","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Pháp bảo phòng ngự màu xanh của Trần Phong, có khí tức Cổ Thần mỏng manh và chặn được Diệt Thần Mâu. Sau khi bại trận, Trần Phong xóa lạc ấn và dâng nó cho Vương Lâm.","detail":"Thanh quang thuẫn xuất hiện khi Trần Phong bị Diệt Thần Mâu truy sát. Pháp bảo không nứt trước đòn đánh, để lộ khí tức Cổ Thần khiến Vương Lâm chú ý và được thu vào túi trữ vật sau khi Trần Phong xin tha.","nguon":["@c0921","@c0974"],"tabs":{"tienTrinh":[{"chuong":"@c0974","loai":"dùng","importance":"normal","giaiDoan":"Chặn giọt nước phản kích","text":"Thanh Quang Thuẫn hiện ra trước mặt Vương Lâm và chặn được giọt nước phản kích cuối cùng của người khổng lồ biển cả.","anchor":"ngay khi giọt nước kia tới gần, lập tức ở phía trước hiện ra Thanh Quang Thuẫn!"}]},"congNang":["Phòng ngự trước đòn phản kích tốc độ cao của giọt nước cấm chế @c0974"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0974","denChuong":"","cachCoDuoc":"đã sở hữu khi bước vào cấm chế giọt sương","trangThai":"đang giữ"}]},{"id":"chia-khoa-tien-phu","name":"Chìa khóa Tiên Phủ","cn":"","aliases":["chìa khóa động phủ","chìa khóa của tòa động phủ thứ tư"],"category":"khac","categoryLabel":"Vật phẩm then chốt","phamCap":"liên quan Tiên Phủ","soHuu":["Vương Lâm"],"trangThai":"đã dùng để kích hoạt đại trận","blurb":"Chìa khóa liên quan tới Tiên Phủ mà Trần Phong muốn đoạt từ Vương Lâm. Hắn cho rằng có một tòa Tiên Phủ sẽ giúp ích lớn cho chuyến vào vùng đất Yêu Linh.","detail":"Trong chương này, lòng tham chìa khóa Tiên Phủ là một trong những nguyên nhân khiến Trần Phong ra tay với Vương Lâm. Sau khi thất bại, ý đồ đoạt vật của hắn chấm dứt và hắn phải quy phục tạm thời.","nguon":["@c0921","@c0949"],"congNang":["Kích hoạt khối đá màu đen và đại trận trong động phủ thứ tư."],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0949","denChuong":"","cachCoDuoc":"Đã thu được trước đó và dùng tại đại trận trong chương này.","trangThai":"đã dùng"}]},{"id":"manh-vo-khac-thanh-long","name":"Mảnh vỡ khắc thanh long","cn":"","category":"nguyen-lieu","categoryLabel":"Toái phiến","phamCap":"liên quan Thanh Long Thánh Tông","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Mảnh vỡ xuất hiện sau khi Vương Lâm bóp tan bản thể thanh long ấn ký trên Thanh quang thuẫn. Trên mảnh có khắc thanh long và mang khí tức giống ấn ký Chu Tước ở mi tâm Vương Lâm.","detail":"Sau khi phân thân thanh long bị con mắt thứ ba hút vào và bản thể ấn ký bị Vương Lâm bóp tan, một mảnh vỡ bằng ngón tay cái xuất hiện trong tay hắn. Khí tức trên mảnh vỡ giống ấn ký Chu Tước, khiến Vương Lâm suy đoán nó có liên hệ với Thanh Long Thánh Tông trong Tứ Thánh Tông.","nguon":["@c0923"]},{"id":"doi-chuong-cua-thieu-nu-thuy-linh","name":"Đôi chuông của thiếu nữ Thủy Linh","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"chưa rõ","soHuu":["Linh nhi"],"trangThai":"dang-co","blurb":"Đôi chuông được đặt trước mặt Linh nhi khi nàng tĩnh tọa trên Thủy Linh tinh. Chương này chỉ cho thấy nàng càng nhìn càng yêu thích, chưa nêu công dụng.","detail":"Khi uy áp từ Thanh quang thuẫn lan ra, Linh nhi đang ngồi khoanh chân tĩnh tọa trước một đôi chuông. Đôi chuông khiến nàng thích thú, nhưng chương chưa mô tả năng lực hay lai lịch cụ thể.","nguon":["@c0923"]},{"id":"lam-quang-tu-nguc-linh-nhi","name":"Lam quang từ ngực Linh nhi","cn":"","category":"khac","categoryLabel":"Vật bảo hộ","phamCap":"chưa rõ","soHuu":["Linh nhi"],"trangThai":"dang-co","blurb":"Lam quang dịu dàng phát ra từ ngực Linh nhi khi uy áp Thanh quang thuẫn lan tới. Nó tràn khắp thân thể nàng để chống lại áp lực từ pháp khí Cổ Thần.","detail":"Khi uy áp của Thanh quang thuẫn bao phủ Thủy Linh tinh, một luồng lam quang từ ngực Linh nhi tự động lan ra toàn thân, giúp nàng chống đỡ áp lực. Nguồn gốc và hình thái thật của vật hoặc lực lượng này chưa được nêu trong chương.","nguon":["@c0923"]},{"id":"kim-long-chi-hon","name":"Kim long chi hồn","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh hồn trong pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"ở trong vương miện","blurb":"Kim long chi hồn hiện trong vương miện của Vương Lâm. Nó hóa thành sợi tơ vàng thu nhỏ lượn quanh hồng ảnh và tỏ vẻ e ngại hồng ảnh ấy.","detail":"Khi Vương Lâm kiểm tra vương miện, kim long chi hồn không hiện thành hình rồng lớn mà hóa thành sợi tơ vàng nhỏ quanh hồng ảnh. Biểu hiện của nó cho thấy hồng ảnh trong vương miện có vị trí đặc biệt, nhưng chương chưa xác nhận bản chất của hồng ảnh.","nguon":["@c0925"]},{"id":"nu-luyen-thi-ao-bac-cua-hai-nguc-gioi","name":"Nữ luyện thi áo bạc của Hài Ngục Giới","cn":"","aliases":["nữ luyện thi áo bạc","luyện thi áo bạc"],"category":"khac","categoryLabel":"Luyện thi","phamCap":"chiến lực Tinh Niết sơ kỳ nếu khống chế thành công","soHuu":["Vương Lâm"],"trangThai":"chưa tế luyện hoàn toàn","blurb":"Luyện thi nữ áo bạc do Vương Lâm đoạt được trong đại chiến La Thiên và Liên Minh. Thi thể mang âm khí, độc tố và xiềng xích đen, được hắn định tế luyện làm trợ lực cho chuyến tới Yêu Linh chi địa.","detail":"Vương Lâm lấy nữ luyện thi áo bạc ra trong cung điện trên Thủy Linh Tinh, cho rằng nếu có thể khống chế thì sẽ có thêm trợ lực Tinh Niết sơ kỳ. Luyện thi này bắt nguồn từ Hài Ngục Giới, từng rơi vào tay phía Liên Minh, rồi bị Vương Lâm đoạt được trong đại chiến với La Thiên.","nguon":["@c0925"]},{"id":"thiet-lien-den-tren-nu-luyen-thi","name":"Thiết liên đen trên nữ luyện thi","cn":"","aliases":["dây xích đen trên nữ luyện thi"],"category":"khac","categoryLabel":"Vật phong tỏa","phamCap":"không rõ","soHuu":["Nữ luyện thi áo bạc của Hài Ngục Giới"],"trangThai":"đang khóa luyện thi","blurb":"Hai dây xích đen khóa trên thân nữ luyện thi áo bạc. Chúng xuyên qua xương tỳ bà và bồn cốt, tỏa mùi tanh độc nguy hiểm với phàm nhân và tu sĩ tu vi thấp.","detail":"Thiết liên đen là vật phong tỏa đi kèm nữ luyện thi áo bạc, khóa các vị trí trọng yếu trên thân luyện thi. Khi Vương Lâm lấy luyện thi ra, dây xích cùng âm khí và độc tố khiến không gian trong cung điện trở nên nguy hiểm, buộc hắn phải thu lại khi cảm ứng Linh nhi tới gần.","nguon":["@c0925"]},{"id":"bao-binh","name":"Bảo bình","cn":"","category":"khac","categoryLabel":"Vật phẩm nghi lễ","phamCap":"","soHuu":["Linh nhi"],"trangThai":"","blurb":"Bảo bình nghi lễ trong ảo cảnh Nguyệt tộc, dùng tiếp nhận thiên địa lực rồi dâng lên Cổ Thần.","detail":"Trong ảo cảnh luân hồi, Mộc Linh cầm bảo bình tiếp nhận thiên địa lực do dân chúng Nguyệt tộc dâng lên. Sau khi hấp thu đủ, bảo bình hóa thành khí xoáy bay lên nhập vào mi tâm Cổ Thần hình dáng Vương Lâm.","nguon":["@c0927"]},{"id":"khi-xoay-thien-dia-luc","name":"Khí xoáy thiên địa lực","cn":"","category":"khac","categoryLabel":"Năng lượng tế hiến","phamCap":"","soHuu":[],"trangThai":"","blurb":"Khối khí xoáy do bảo bình hấp thu thiên địa lực hóa thành, nhập vào mi tâm Cổ Thần.","detail":"Khí xoáy thiên địa lực hình thành khi bảo bình hấp thu đủ thiên địa lực của dân chúng Nguyệt tộc. Nó bay vào mi tâm Cổ Thần hình dáng Vương Lâm, khiến hắn cảm nhận một đạo lực lượng vương tộc Cổ Thần dung nhập cơ thể.","nguon":["@c0927"]},{"id":"tri-nho-ket-tinh-cua-co-than-do-ti","name":"Trí nhớ kết tinh của Cổ Thần Đồ Ti","cn":"","category":"khac","categoryLabel":"Ký ức truyền thừa","phamCap":"","soHuu":[],"trangThai":"mat","blurb":"Phần ký ức kết tinh còn thiếu trong truyền thừa Cổ Thần Đồ Ti mà Vương Lâm chưa có được.","detail":"Vương Lâm nghi truyền thừa ký ức Cổ Thần Đồ Ti trong đầu mình vẫn còn phần bị phong ấn hoặc thiếu một kết tinh ký ức. Nếu đạt được kết tinh ấy thì truyền thừa ký ức của hắn mới đại viên mãn.","nguon":["@c0927"]},{"id":"tui-tru-vat-cua-phu-phong-tu","name":"Túi trữ vật của Phù Phong tử","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm chứa đồ","phamCap":"Không rõ","soHuu":["Phù Phong tử"],"trangThai":"đang sử dụng","blurb":"Túi trữ vật Phù Phong tử dùng để lấy ra nhiều pháp bảo trong lúc chống lại Tàn Dạ.","detail":"Khi thân thể bị lực kỳ dị xé rách, Phù Phong tử lấy nhiều pháp bảo từ túi trữ vật này ra ngăn cản, nhưng các pháp bảo vừa xuất hiện đã lần lượt vỡ nát.","nguon":["@c0930"]},{"id":"tam-bia-da-mau-den","name":"Tấm bia đá màu đen","cn":"","aliases":["bia đá đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Phù Phong tử"],"trangThai":"bị phá hủy","blurb":"Bia đá lớn có phù văn ấn ký, được Phù Phong tử gọi ra để công kích Vương Lâm.","detail":"Tấm bia đá màu đen đi kèm con trăn lớn có sừng, được Phù Phong tử dùng để đè xuống Vương Lâm trong trận trên đỉnh núi. Dưới Tàn Dạ, bia đá bị đánh vỡ thành vô số đá vụn.","nguon":["@c0930"]},{"id":"con-tran-lon-co-sung-tren-bia-da","name":"Con trăn lớn có sừng trên bia đá","cn":"","aliases":["con trăn có sừng"],"category":"khac","categoryLabel":"Linh thể gắn pháp bảo","phamCap":"Không rõ","soHuu":["Phù Phong tử"],"trangThai":"bị phá hủy","blurb":"Linh thể hình trăn lớn gần hóa chân long, xuất hiện cùng tấm bia đá màu đen.","detail":"Con trăn lớn có sừng lao về phía Vương Lâm theo thế công của Phù Phong tử. Khi Tàn Dạ quét tới, nó bị xé thành mảnh nhỏ.","nguon":["@c0930"]},{"id":"la-ban-truyen-nhan-pha-diet-cam","name":"La bàn truyền nhân Phá Diệt Cấm","cn":"","aliases":["la bàn Phá Diệt Cấm"],"category":"phap-bao","categoryLabel":"Pháp bảo cấm chế","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"La bàn của truyền nhân Phá Diệt Cấm được Vương Lâm kích hoạt để phong tỏa cung điện và luyện hóa Ngân Y Luyện Thi.","detail":"Khi được thổi nguyên khí kích hoạt, la bàn phóng lớn hơn mười trượng, liên kết toàn bộ cấm chế trong cung điện và trở thành trung tâm trói buộc nữ thi.","dinhDanh":"goc","phanLoaiPhu":"cấm khí","hinhDang":"la bàn có thể phóng lớn hơn mười trượng","chuHienThoi":"Vương Lâm","congNang":["Liên kết cấm chế trong cung điện và tạo trung tâm vây khốn Ngân Y Luyện Thi @c0931"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0931","denChuong":"","cachCoDuoc":"giữ từ truyền thừa Phá Diệt Cấm","trangThai":"đang dùng"}],"capNhatToi":"@c0931","tabs":{"tienTrinh":[]},"nguon":["@c0931"]},{"id":"cay-keo-mau-do","name":"Cây kéo màu đỏ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Ngân Y Luyện Thi"],"trangThai":"đang dùng","blurb":"Pháp bảo do Ngân Y Luyện Thi phun ra khi phản kháng Vương Lâm.","detail":"Cây kéo màu đỏ được nữ thi dùng để cắt vỡ cấm chế phía trên cung điện, mở đường phá vây thoát ra ngoài.","dinhDanh":"goc","chuHienThoi":"Ngân Y Luyện Thi","congNang":["Cắt phá cấm chế phía trên cung điện khi nữ thi tìm đường thoát @c0931"],"chuSoHuu":[{"ten":"Ngân Y Luyện Thi","tuChuong":"@c0931","denChuong":"","cachCoDuoc":"vốn do nữ thi sử dụng","trangThai":"đang dùng"}],"capNhatToi":"@c0931","tabs":{"tienTrinh":[]},"nguon":["@c0931"]},{"id":"xich-sat-tren-xuong-ty-ba-va-xuong-chau","name":"Xích sắt trên xương tỳ bà và xương chậu","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phong tỏa","phamCap":"không rõ","soHuu":["Ngân Y Luyện Thi"],"trangThai":"bị bóp nát","blurb":"Hai đoạn xích phong tỏa trên thân Ngân Y Luyện Thi, nằm ở xương tỳ bà và xương chậu.","detail":"Vương Lâm kéo hai đoạn xích ra khỏi thân nữ thi; đoạn ở xương tỳ bà hóa thành rắn đen cắn tay hắn nhưng không phá được thân thể Cổ Thần, sau đó cả hai đoạn đều bị bóp nát.","dinhDanh":"goc","chuHienThoi":"Ngân Y Luyện Thi","congNang":["Phong tỏa thân thể Ngân Y Luyện Thi trước khi bị Vương Lâm rút ra và bóp nát @c0931"],"chuSoHuu":[{"ten":"Ngân Y Luyện Thi","tuChuong":"@c0931","denChuong":"@c0931","cachCoDuoc":"vốn gắn trên thân nữ thi","trangThai":"bị phá hủy"}],"capNhatToi":"@c0931","tabs":{"tienTrinh":[]},"nguon":["@c0931"]},{"id":"ba-lenh-bai-mau-den","name":"Ba lệnh bài màu đen","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Trận lệnh","phamCap":"chưa rõ","soHuu":["Trần Đạo Tam Tử"],"trangThai":"đã dùng","blurb":"Ba lệnh bài do Trần Đạo Tam Tử lấy ra để kích hoạt phòng hộ Thủy Linh tinh. Khi sụp đổ, chúng hóa thành sóng gợn đen tạo ba tầng hào quang bao phủ tinh cầu.","detail":"Nhất Trần tử, Nhất Tinh tử và Nhất Long tử cùng lấy lệnh bài màu đen từ túi trữ vật. Các lệnh bài sụp đổ và hợp thành ba tầng phòng hộ màu đen quanh Thủy Linh tinh để chống Tư Đồ Nam.","congNang":["Kích hoạt ba tầng hào quang màu đen bao phủ Thủy Linh tinh @c0932"],"chuSoHuu":[{"ten":"Trần Đạo Tam Tử","tuChuong":"@c0932","denChuong":"","cachCoDuoc":"đã có trong túi trữ vật khi mở trận","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0932","loai":"dùng","importance":"major","giaiDoan":"kích hoạt đại trận","text":"Trần Đạo Tam Tử dùng ba lệnh bài màu đen để tạo ba tầng phòng hộ quanh Thủy Linh tinh.","anchor":"Trong thời gian ngắn, toàn bộ bên ngoài Thủy Linh tinh liền có ba tầng hào quang màu đen như sóng gợn, bao phủ Thủy Linh tinh cực kỳ chặt chẽ!"}]},"capNhatToi":"@c0932","nguon":["@c0932"]},{"id":"phap-bao-ho-than-cua-tran-dao-tam-tu","name":"Pháp bảo hộ thân của Trần Đạo Tam Tử","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo hộ thân","phamCap":"chưa rõ","soHuu":["Triệu Tuyết","Linh nhi"],"trangThai":"đang dùng","blurb":"Pháp bảo Trần Đạo Tam Tử tặng cho Triệu Tuyết, Linh nhi và một số ít người. Nó giúp họ miễn cưỡng chịu được thần thức Tư Đồ Nam quét ngang Thủy Linh tinh.","detail":"Khi thần thức Tịnh Niết sơ kỳ của Tư Đồ Nam quét qua Thủy Linh tinh, nhiều tu sĩ yếu bị thương hoặc hôn mê. Chỉ số ít người như Triệu Tuyết và Linh nhi nhờ pháp bảo hộ thân này mới có thể miễn cưỡng chịu đựng.","congNang":["Giúp người mang miễn cưỡng chịu được áp lực thần thức Tư Đồ Nam @c0932"],"chuSoHuu":[{"ten":"Triệu Tuyết","tuChuong":"@c0932","denChuong":"","cachCoDuoc":"được Trần Đạo Tam Tử tặng","trangThai":"đang giữ"},{"ten":"Linh nhi","tuChuong":"@c0932","denChuong":"","cachCoDuoc":"được Trần Đạo Tam Tử tặng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0932","loai":"dùng","importance":"normal","giaiDoan":"chống thần thức","text":"Pháp bảo hộ thân của Trần Đạo Tam Tử giúp Triệu Tuyết, Linh nhi và một số ít người chống chịu áp lực thần thức Tư Đồ Nam.","anchor":"Chỉ có một số ít người như Triệu Tuyết, Linh nhi có Trần Đạo Tam Tử tặng pháp bảo hộ thân, mới miễn cưỡng chịu đựng được."}]},"capNhatToi":"@c0932","nguon":["@c0932"]},{"id":"cay-keo-cua-nu-thi","name":"Cây kéo của nữ thi","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"khong-ro","soHuu":["Ngân Y Luyện Thi"],"trangThai":"dang-co","blurb":"Cây kéo của nữ thi là pháp bảo do Ngân Y Luyện Thi phun ra trong lúc giao thủ với Tư Đồ Nam.","detail":"Cây kéo vờn quanh thân thể nữ thi áo bạc và phá tan từng tầng quầng sáng Khốn Tiên chỉ do Tư Đồ Nam thi triển.","hinhDang":"Cây kéo","chuHienThoi":"Ngân Y Luyện Thi","uyLuc":"Phá được các quầng sáng trói buộc của Khốn Tiên chỉ.","congNang":["Vờn quanh thân thể chủ nhân và phá tan quầng sáng trói buộc @c0933"],"chuSoHuu":[{"ten":"Ngân Y Luyện Thi","tuChuong":"@c0933","denChuong":"","cachCoDuoc":"Phun ra khi giao thủ","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c0933","loai":"dùng","importance":"normal","giaiDoan":"Phá Khốn Tiên chỉ","text":"Ngân Y Luyện Thi phun cây kéo vờn quanh thân thể để phá tan quầng sáng Khốn Tiên chỉ của Tư Đồ Nam.","anchor":"Nhưng người con gái này cũng không đơn giản, há mồm phun ra một cây kéo vờn quanh thân thể."}]},"capNhatToi":"@c0933","nguon":["@c0933"]},{"id":"ban-ngoc-trang","name":"Bàn ngọc trắng","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":[],"trangThai":"xuất hiện @c0934","blurb":"Bàn ngọc được đặt giữa Vương Lâm và Tư Đồ Nam trên đỉnh núi khi hai người uống rượu ôn chuyện.","detail":"Trong cuộc gặp lại sau luận bàn, bàn ngọc trắng xuất hiện như vật đặt giữa hai người trên đỉnh núi, làm nền cho cảnh uống rượu và kể chuyện nhiều năm xa cách.","dinhDanh":"goc","tabs":{"tienTrinh":[]},"capNhatToi":"@c0934","nguon":["@c0934"]},{"id":"bau-ruou-va-do-nham","name":"Bầu rượu và đồ nhắm","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Tư Đồ Nam"],"trangThai":"xuất hiện @c0934","blurb":"Vật phẩm Tư Đồ Nam mang tới để cùng Vương Lâm uống rượu sau khi tái ngộ.","detail":"Sau khi hai người nhận nhau là bạn cũ, Tư Đồ Nam lấy bầu rượu và đồ nhắm ra trên đỉnh núi, cùng Vương Lâm trò chuyện về những trải nghiệm mấy trăm năm.","dinhDanh":"goc","chuSoHuu":[{"ten":"Tư Đồ Nam","tuChuong":"@c0934","denChuong":"","cachCoDuoc":"Mang theo bên người","trangThai":"đang có"}],"tabs":{"tienTrinh":[]},"capNhatToi":"@c0934","nguon":["@c0934"]},{"id":"duc-tien-duc-tu","name":"Dục Tiên Dục Tử","cn":"","category":"dan-duoc","categoryLabel":"Độc dược","phamCap":"Độc Tiên Giới","soHuu":["Các nữ tu Phượng Loan tinh"],"trangThai":"đang ở trong người Tư Đồ Nam","blurb":"Độc dược Tiên Giới chuyên nhằm vào tiên nhân, hiện đang uy hiếp sinh mạng Tư Đồ Nam.","detail":"Dục Tiên Dục Tử là độc do Tiên Giới lưu lại, nhập vào cơ thể sẽ dung hợp nguyên thần. Độc khiến người trúng trải qua ba ngày Dục Tiên, ba ngày Dục Tử, đến ngày thứ bảy có thể hình thần câu diệt; Tư Đồ Nam phải dùng song tu lô đỉnh để kéo dài mạng sống.","dinhDanh":"goc","nguonGoc":"Tiên Giới lưu lại.","congNang":["Dung hợp với nguyên thần người trúng độc.","Sau ba ngày Dục Tiên và ba ngày Dục Tử, đến ngày thứ bảy có thể khiến người trúng độc hình thần câu diệt."],"chuSoHuu":[{"ten":"Các nữ tu Phượng Loan tinh","tuChuong":"@c0935","denChuong":"","cachCoDuoc":"Dùng để hạ độc Tư Đồ Nam","trangThai":"đã sử dụng"},{"ten":"Tư Đồ Nam","tuChuong":"@c0935","denChuong":"","cachCoDuoc":"Bị hạ độc trên Phượng Loan tinh","trangThai":"bị độc nhập thân"}],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"xuất hiện","importance":"major","giaiDoan":"Tiết lộ độc thương","text":"Tư Đồ Nam tiết lộ mình trúng Dục Tiên Dục Tử, loại độc Tiên Giới dung hợp nguyên thần và có thể khiến hình thần câu diệt.","anchor":"Loại độc này tên là Dục Tiên Dục Tử. Ba ngày Dục Tiên, ba ngày Dục Tử!"}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"tien-thap-cua-chu-dat","name":"Tiên tháp của Chu Dật","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang được Vương Lâm giữ","blurb":"Tòa tiên tháp Chu Dật từng đưa cho Vương Lâm, bên trong có xác Tiên quân Thanh Sương.","detail":"Tiên tháp do Chu Dật trao cho Vương Lâm năm xưa, bên trong chứa xác Tiên quân Thanh Sương của Vũ Tiên Giới. Ở chương này, nó trở thành đầu mối để Vương Lâm suy đoán nếu tìm được Thanh Lâm và khiến Thanh Sương sống lại thì có thể phá độc cho Tư Đồ Nam.","dinhDanh":"goc","congNang":["Cất giữ xác Tiên quân Thanh Sương."],"chuSoHuu":[{"ten":"Chu Dật","tuChuong":"@c0935","denChuong":"@c0935","cachCoDuoc":"Chủ cũ được nhắc qua lời Vương Lâm","trangThai":"đã trao cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c0935","denChuong":"","cachCoDuoc":"Nhận từ Chu Dật năm xưa","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"nhắc tới","importance":"normal","giaiDoan":"Manh mối giải độc","text":"Vương Lâm nhắc tiên tháp Chu Dật đưa, bên trong có xác Thanh Sương, làm đầu mối tìm cách phá Dục Tiên Dục Tử.","anchor":"Trên người hắn có tiên tháp Chu Dật đưa cho năm xưa, bên trong có xác Tiên quân Thanh Sương, đúng là Tiên quân của Vũ Tiên Giới."}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"xac-tien-quan-thanh-suong","name":"Xác Tiên quân Thanh Sương","cn":"","category":"khac","categoryLabel":"Di hài","phamCap":"Tiên quân Vũ Tiên Giới","soHuu":["Vương Lâm"],"trangThai":"nằm trong tiên tháp","blurb":"Di hài Tiên quân Thanh Sương nằm trong tiên tháp Chu Dật từng đưa cho Vương Lâm.","detail":"Xác Tiên quân Thanh Sương được xác định nằm trong tiên tháp của Vương Lâm. Vương Lâm suy đoán nếu Tiên Đế Thanh Lâm có thể khiến Thanh Sương sống lại, nàng sẽ có khả năng giúp phá Dục Tiên Dục Tử cho Tư Đồ Nam.","dinhDanh":"goc","congNang":["Là đầu mối liên hệ giữa Thanh Sương, Thanh Lâm và khả năng phá Dục Tiên Dục Tử."],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0935","denChuong":"","cachCoDuoc":"Giữ trong tiên tháp Chu Dật trao","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"nhắc tới","importance":"normal","giaiDoan":"Liên hệ Thanh Lâm","text":"Xác Thanh Sương trong tiên tháp được Vương Lâm xem là đầu mối để tìm Thanh Lâm và phá độc cho Tư Đồ Nam.","anchor":"Một khi Thanh Sương sống lại, vậy độc này phá cũng không khó!"}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"ruou-tien-trong-binh-ngoc-tia","name":"Rượu tiên trong bình ngọc tía","cn":"","category":"khac","categoryLabel":"Rượu Tiên Giới","phamCap":"Tiên Giới","soHuu":["Tư Đồ Nam"],"trangThai":"được dùng cho Vương Lâm uống","blurb":"Rượu tiên Tư Đồ Nam vô ý có được, có thể khiến tu sĩ tìm lại cảm giác say của người thường.","detail":"Rượu tiên được Tư Đồ Nam lấy ra khi thấy Vương Lâm đau khổ và rượu thường không thể khiến hắn say. Một giọt rượu này có thể giúp tu sĩ tìm lại cảm giác say, để Vương Lâm tạm buông gánh nặng trong men rượu.","dinhDanh":"goc","nguonGoc":"Tiên Giới","congNang":["Một giọt có thể khiến tu sĩ tìm lại cảm giác say của người thường."],"chuSoHuu":[{"ten":"Tư Đồ Nam","tuChuong":"@c0935","denChuong":"","cachCoDuoc":"Vô ý có được","trangThai":"đem ra cho Vương Lâm uống"}],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"dùng","importance":"normal","giaiDoan":"Cho Vương Lâm say","text":"Tư Đồ Nam lấy rượu tiên để Vương Lâm có thể say một lần sau khi bộc lộ nỗi đau tu đạo.","anchor":"Vương Lâm! Có ta ở đây, ngươi có thể say một lần!"}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"thiep-moi-cua-thien-van-tu","name":"Thiệp mời của Thiên Vận Tử","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thiên Vận Tử"],"trangThai":"đã gửi đi","blurb":"Thiệp mời do Thiên Vận Tử viết, thông báo thời điểm mở cửa động phủ Tiên nhân ở Đông Hải Triều tịch.","detail":"Thiên Vận Tử tự tay viết thiệp mời và phát tới các lão quái đủ tư cách tiến vào vùng đất Yêu Linh. Nội dung thiệp thông báo mười ngày sau mở cửa vào động phủ Tiên nhân tại Đông Hải Triều tịch.","dinhDanh":"goc","congNang":["Triệu tập các lão quái đủ tư cách vào vùng đất Yêu Linh để tham dự việc mở động phủ Tiên nhân."],"chuSoHuu":[{"ten":"Thiên Vận Tử","tuChuong":"@c0935","denChuong":"@c0935","cachCoDuoc":"Tự tay viết","trangThai":"đã phát ra"}],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"xuất hiện","importance":"major","giaiDoan":"Mở động phủ Tiên nhân","text":"Thiên Vận Tử phát thiệp mời, ấn định mười ngày sau mở cửa vào động phủ Tiên nhân ở Đông Hải Triều tịch.","anchor":"Mười ngày sau, mở cửa vào động phủ Tiên nhân ở nơi Đông Hải Triều tịch!"}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"cay-dinh-ba-cua-do-ti","name":"Cây đinh ba của Đồ Ti","aliases":["đinh ba của Thiên Vận tử","đinh ba tối đen của Thiên Vận tử"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"khong-ro","soHuu":["Thiên Vận tử"],"trangThai":"dang-co","blurb":"Cây đinh ba tối đen như mực được Thiên Vận tử dùng khi xuất hiện ở Triều tịch. Sự xuất hiện của nó gây chấn động vì Thiên Vận tử vốn hiếm khi dùng pháp bảo.","detail":"Thiên Vận tử đạp trên cây đinh ba đen tới cửa Triều tịch vào ngày thứ mười. Pháp bảo này khiến người biết hắn đều chú ý, vì thông thường hắn dựa vào tiên thuật hơn là pháp bảo.","dinhDanh":"goc","capNhatToi":"@c0936","chuSoHuu":[{"ten":"Thiên Vận tử","tuChuong":"@c0936","denChuong":"","cachCoDuoc":"đang sử dụng khi tới Triều tịch","trangThai":"dang-co"}],"tabs":{"tienTrinh":[]},"nguon":["@c0936"]},{"id":"ho-lo-cua-lao-gia","name":"Hồ lô của lão già","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo phi hành","phamCap":"khong-ro","soHuu":["Lão già ngồi trên hồ lô"],"trangThai":"dang-co","blurb":"Hồ lô dùng làm vật phi hành của lão già dự hội Triều tịch. Lão già ngồi khoanh chân trên đó và dẫn chín đồ đệ đi theo.","detail":"Hồ lô đưa lão già và chín đồ đệ bay tới phía trên Triều tịch sau khi Thiên Vận tử đến. Chương chưa nêu thêm uy lực chiến đấu của vật này.","dinhDanh":"goc","capNhatToi":"@c0936","chuSoHuu":[{"ten":"Lão già ngồi trên hồ lô","tuChuong":"@c0936","denChuong":"","cachCoDuoc":"đang cưỡi khi tới Triều tịch","trangThai":"dang-co"}],"tabs":{"tienTrinh":[]},"nguon":["@c0936"]},{"id":"chin-muoi-chin-cay-co-cua-au-duong-hoa","name":"Chín mươi chín cây cờ của Âu Dương Hoa","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Cờ hồn","phamCap":"khong-ro","soHuu":["Âu Dương Hoa"],"trangThai":"dang-co","blurb":"Bộ chín mươi chín cây cờ của đại trưởng lão Âu Dương Hoa. Khi toàn bộ được tung ra, chúng có thể hóa thành vài triệu hồn phách phủ kín trời đất.","detail":"Âu Dương Hoa sở hữu chín mươi chín cây cờ, là biểu hiện sức mạnh trụ cột của bộ lạc Luyện Hồn. Chương dùng bộ cờ này để cho thấy quy mô hồn phách mà ông có thể điều động.","dinhDanh":"goc","capNhatToi":"@c0936","congNang":["Gọi và biến ảo vài triệu hồn phách khi toàn bộ cờ được lấy ra @c0936"],"chuSoHuu":[{"ten":"Âu Dương Hoa","tuChuong":"@c0936","denChuong":"","cachCoDuoc":"sở hữu với thân phận đại trưởng lão bộ lạc Luyện Hồn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[]},"nguon":["@c0936"]},{"id":"co-cua-toc-nhan-luyen-hon","name":"Cờ của tộc nhân Luyện Hồn","cn":"","aliases":["cờ hồn của tộc nhân Luyện Hồn"],"category":"phap-bao","categoryLabel":"Cờ hồn","phamCap":"khong-ro","soHuu":["Tộc nhân bộ lạc Luyện Hồn"],"trangThai":"dang-co","blurb":"Cờ hồn phổ biến của tộc nhân bộ lạc Luyện Hồn. Vài trăm vạn người cầm cờ tiến vào quận Hỏa Yêu trong cuộc chiến đoạt quận.","detail":"Người Luyện Hồn gần như ai cũng có cờ lớn để gọi hồn phách, dung hợp thành hồn thú cắn nuốt kẻ địch. Khi đại quân xuất phát, cờ cuồn cuộn trải khắp mặt đất.","dinhDanh":"goc","capNhatToi":"@c0936","congNang":["Thả vô số hồn phách và dung hợp thành hồn thú để cắn nuốt kẻ địch @c0936"],"chuSoHuu":[{"ten":"Tộc nhân bộ lạc Luyện Hồn","tuChuong":"@c0936","denChuong":"","cachCoDuoc":"vật phổ biến của người Luyện Hồn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[]},"nguon":["@c0936"]},{"id":"tuong-da-mau-den-cua-lao-to-luyen-hon","name":"Tượng đá màu đen của lão tổ Luyện Hồn","cn":"","aliases":["tượng đá đen khắc lão tổ Luyện Hồn"],"category":"khac","categoryLabel":"Tín vật","phamCap":"khong-ro","soHuu":["Bộ lạc Luyện Hồn"],"trangThai":"dang-co","blurb":"Pho tượng đá đen khắc hình lão tổ của bộ lạc Luyện Hồn. Nó được hơn mười người khiêng trong đại quân và được tộc nhân sùng kính cuồng nhiệt.","detail":"Tượng đá màu đen là biểu tượng tín ngưỡng của bộ lạc Luyện Hồn, được gọi là hồn, vương giả và lão tổ của họ. Trong cuộc chiến đoạt quận Hỏa Yêu, tượng được đại quân khiêng theo.","dinhDanh":"goc","capNhatToi":"@c0936","chuSoHuu":[{"ten":"Bộ lạc Luyện Hồn","tuChuong":"@c0936","denChuong":"","cachCoDuoc":"tín vật truyền trong bộ lạc","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0936","loai":"nhắc tới","importance":"normal","giaiDoan":"Tín vật đại quân đoạt quận","text":"Tượng đá đen khắc hình lão tổ được đại quân Luyện Hồn khiêng theo và được tộc nhân xem là hồn của bộ lạc.","anchor":"Tượng đá này phía trên điêu khắc chính là hồn của bộ lạc Luyện Hồn bọn họ"}]},"nguon":["@c0936"]},{"id":"ngoc-gian-truyen-tin-cua-lang-thien-hau","name":"Ngọc giản truyền tin của Lăng Thiên Hậu","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm truyền tin","phamCap":"khong-ro","soHuu":["Lăng Thiên Hậu"],"trangThai":"da-dung","blurb":"Ngọc giản được Lăng Thiên Hậu truyền ra để chờ bạn tốt đã liên hệ từ trước. Vật này gắn với việc hắn gọi trợ thủ vào vùng đất Yêu Linh.","detail":"Sau khi nhận thiệp mời của Thiên Vận tử, Lăng Thiên Hậu rời sâu trong lòng đất và truyền ngọc giản. Chương cho thấy hắn đã liên hệ người trợ giúp trước khi tới Triều tịch.","dinhDanh":"goc","capNhatToi":"@c0936","chuSoHuu":[{"ten":"Lăng Thiên Hậu","tuChuong":"@c0936","denChuong":"","cachCoDuoc":"dùng để truyền tin cho trợ thủ","trangThai":"da-dung"}],"tabs":{"tienTrinh":[]},"nguon":["@c0936"]},{"id":"tinh-ngan-dieu","name":"Tinh Ngân Điêu","aliases":["hạc tím ba mắt của Tôn trưởng lão","Hạc tím ba mắt của Tôn trưởng lão"],"category":"khac","categoryLabel":"Linh thú","phamCap":"khong-ro","soHuu":["Tôn Thiện"],"trangThai":"dang-co","blurb":"Con hạc tím ba mắt nằm trên vai Tôn Thiện khi hắn tới Triều tịch. Nó có ánh mắt như điện và lộ vẻ lạnh lùng.","detail":"Tinh Ngân Điêu xuất hiện cùng Tôn Thiện trong ánh sáng vàng. Nó nằm trên vai hắn, chuyển con ngươi lạnh lùng và thỉnh thoảng nâng móng vuốt quẹt qua mặt.","dinhDanh":"goc","capNhatToi":"@c0936","chuSoHuu":[{"ten":"Tôn Thiện","tuChuong":"@c0936","denChuong":"","cachCoDuoc":"linh thú đi cùng trên vai","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0936","loai":"xuất hiện","importance":"normal","giaiDoan":"Đi cùng Tôn Thiện","text":"Tinh Ngân Điêu nằm trên vai Tôn Thiện khi hắn xuất hiện tại Triều tịch.","anchor":"Người này mặc một áo choàng dài màu tím, trên bả vai một con hạc tím ba mắt đang nằm."}]},"nguon":["@c0936"]},{"id":"lenh-bai-bay-mau","name":"Lệnh bài bảy màu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Thiên Vận tử"],"trangThai":"đang dùng","blurb":"Lệnh bài bảy màu là vật Thiên Vận tử dùng để mở Đông Hải Triều tịch. Khi bay vào trung tâm lốc xoáy, nó khiến lốc xoáy nghịch chuyển phóng đại thành hố đen dẫn vào phía sau Triều tịch.","detail":"Thiên Vận tử phất tay tạo ra lệnh bài tỏa ánh sáng bảy màu, hào quang rực rỡ tới mức khiến nhiều tu sĩ hoa mắt. Lệnh bài rơi vào nơi sâu trong Đông Hải Triều tịch, kích hoạt lốc xoáy nghịch chuyển và mở đường vào động phủ thứ năm.","nguon":["@c0937"],"dinhDanh":"goc","chuHienThoi":"Thiên Vận tử","capNhatToi":"@c0937","congNang":["Mở Đông Hải Triều tịch bằng cách bay vào trung tâm lốc xoáy và kích hoạt hố đen nghịch chuyển @c0937"],"chuSoHuu":[{"ten":"Thiên Vận tử","tuChuong":"@c0937","denChuong":"","cachCoDuoc":"đang nắm giữ khi chủ trì mở Đông Hải Triều tịch","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0937","loai":"dùng","importance":"normal","giaiDoan":"Mở Đông Hải Triều tịch","text":"Thiên Vận tử dùng lệnh bài bảy màu đưa vào lốc xoáy Triều tịch, mở ra hố đen nghịch chuyển để tiến vào động phủ thứ năm.","anchor":"Tay áo Thiên Vận tử vung lên, lập tức liền có một đạo ánh sáng bảy màu hiện lên."}]}},{"id":"phap-bao-dai-su-ty-dua-cho-tich-huyen","name":"Pháp bảo Đại sư tỷ đưa cho Tịch Huyên","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Tịch Huyên"],"trangThai":"Đang được Tịch Huyên mang theo","blurb":"Pháp bảo hộ thân do Đại sư tỷ trao cho Tịch Huyên, được nàng xem là đủ để tự bảo vệ khi tiến vào vùng đất Yêu Linh.","detail":"Trước khi nhóm nữ tu tiến vào hố đen, Tịch Huyên trấn an Hà di rằng mình có pháp bảo do Đại sư tỷ đưa cho nên đủ sức tự bảo vệ trong vùng đất Yêu Linh. Chương chưa nêu tên riêng, phẩm cấp hay công năng cụ thể của pháp bảo này.","nguon":["@c0938"]},{"id":"thach-ban-di-tien-phu-thu-tu","name":"Thạch bàn đi Tiên phủ thứ tư","cn":"","category":"khac","categoryLabel":"Vật phẩm/tín vật","phamCap":"","soHuu":["Vương Lâm","Tư Đồ Nam"],"trangThai":"Vương Lâm giao cho Tư Đồ Nam để mở đường vào Tiên phủ thứ tư.","blurb":"Tín vật thiết yếu để thông đến Tiên phủ thứ tư trong Yêu Linh chi địa. Vương Lâm giao thạch bàn cho Tư Đồ Nam kèm chỉ dẫn những cấm chế từng phá giải.","detail":"Thạch bàn là vật Vương Lâm dùng để đưa nhóm Tư Đồ Nam vào Tiên phủ thứ tư. Khi tách khỏi nhóm để đi gặp cố nhân ở Luyện Hồn bộ lạc, Vương Lâm giao thạch bàn này cho Tư Đồ Nam, đồng thời chỉ lại các vị trí cấm chế mình từng phá để nhóm cao thủ thuận lợi tiến sâu vào Tiên phủ, hướng tới khu vực trung tâm.","nguon":["@c0939"]},{"id":"lenh-bai-tien-phu-cua-vuong-lam","name":"Lệnh bài Tiên phủ của Vương Lâm","cn":"","category":"khac","categoryLabel":"Tín vật","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"Nằm trong tay Vương Lâm và được hắn biến đổi để nhóm Tư Đồ Nam vào động phủ thuận lợi.","blurb":"Lệnh bài gắn với Tiên phủ do Vương Lâm nắm giữ. Hắn chỉ cần biến đổi đôi chút là có thể giúp nhóm Tư Đồ Nam vào động phủ mà không bị công kích.","detail":"Lệnh bài Tiên phủ là tín vật trong tay Vương Lâm khi trở lại Yêu Linh chi địa. Vì Tiên phủ thứ tư vẫn còn nhiều cấm chế chưa phá, Vương Lâm dùng lệnh bài phối hợp với thạch bàn và chỉ dẫn cấm chế, giúp Tư Đồ Nam cùng các tu sĩ đi vào động phủ để tiếp tục phá cấm.","nguon":["@c0939"]},{"id":"tang-bao-cac","name":"Tàng Bảo Các","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Kho pháp bảo","phamCap":"không rõ","soHuu":["Luyện Hồn Tông","Vương Lâm","Âu Dương Hoa"],"trangThai":"đang dùng","blurb":"Tàng Bảo Các là kho pháp bảo do Vương Lâm lập trong Luyện Hồn Tông. Kho này chứa nhiều phi kiếm và pháp bảo do hắn lấy từ túi trữ vật để thưởng cho đệ tử có cống hiến.","detail":"Sau khi truyền pháp, Vương Lâm lấy ra lượng lớn phi kiếm và pháp bảo để tạo nên Tàng Bảo Các, giao Âu Dương Hoa an bài thưởng phạt cho môn nhân Luyện Hồn Tông.","dinhDanh":"goc","phanLoaiPhu":"kho pháp bảo tông môn","nguonGoc":"Do Vương Lâm lập bằng số phi kiếm và pháp bảo lấy từ túi trữ vật.","chuHienThoi":"Luyện Hồn Tông","congNang":["Làm kho thưởng pháp bảo cho đệ tử Luyện Hồn Tông có cống hiến."],"chuSoHuu":[{"ten":"Luyện Hồn Tông","tuChuong":"@c0940","denChuong":"","cachCoDuoc":"Được Vương Lâm lập trong tông môn","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0940","loai":"xuất hiện","importance":"major","giaiDoan":"Lập kho thưởng","text":"Vương Lâm lập Tàng Bảo Các trong Luyện Hồn Tông bằng nhiều phi kiếm và pháp bảo.","anchor":"lúc này đưa ra vô số phi kiếm và pháp bảo, để tạo nên Tàng Bảo Các trong Luyện Hồn Tông!"}]},"capNhatToi":"@c0940","nguon":["@c0940"]},{"id":"hon-phien","name":"Hồn Phiên","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo tu luyện / khống hồn","phamCap":"không rõ","soHuu":["Đệ tử Luyện Hồn Tông","Âu Dương Hoa"],"trangThai":"đang dùng","blurb":"Hồn Phiên là căn cơ tu vi dị dạng của đệ tử Luyện Hồn Tông. Chương này nhấn mạnh số lượng hồn phách trong Hồn Phiên của hơn trăm vạn đệ tử là cực kỳ kinh người.","detail":"Đệ tử Luyện Hồn Tông dựa vào Hồn Phiên và hồn phách để tu luyện, nên Vương Lâm mới cải tạo Tiên thuật thành cấm pháp phù hợp cho họ. Âu Dương Hoa có chín mươi chín căn Hồn Phiên thì có thể đánh với Vấn Đỉnh kỳ.","dinhDanh":"goc","phanLoaiPhu":"pháp bảo hồn phách","dacDiem":"Gắn trực tiếp với phương thức tu luyện của Luyện Hồn Tông.","congNang":["Chứa và điều động hồn phách cho đệ tử Luyện Hồn Tông tu luyện, chiến đấu."],"chuSoHuu":[{"ten":"Đệ tử Luyện Hồn Tông","tuChuong":"@c0940","denChuong":"","cachCoDuoc":"Pháp bảo căn cơ của hệ tu luyện Luyện Hồn Tông","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0940","loai":"nhắc tới","importance":"normal","giaiDoan":"Căn cơ tu luyện","text":"Hồn Phiên được nêu là nền tảng tu luyện của đệ tử Luyện Hồn Tông, khiến Vương Lâm phải phân giải Tiên thuật thành cấm pháp phù hợp.","anchor":"Vương Lâm lấy Tiên thuật làm căn bản, phân ra nhiều loại cấm pháp rồi mới truyền xuống!"}]},"capNhatToi":"@c0940","nguon":["@c0940"]},{"id":"tien-phu-ngoc-gian","name":"Tiên phủ ngọc giản","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm truyền tống / liên hệ Tiên phủ","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Tiên phủ ngọc giản là vật phẩm Vương Lâm dùng để đi tới Tiên phủ trong thời gian ngắn. Chương này hắn dùng nó để tìm Lôi Cát và lấy máu tươi Cự Ma Tộc về rèn thân Thập Tam.","detail":"Thông qua Tiên phủ ngọc giản, Vương Lâm nhanh chóng tới nơi có Lôi Cát, lấy nhiều máu rồi lập tức quay lại để tiếp tục cải tạo thân thể Thập Tam.","dinhDanh":"goc","congNang":["Giúp Vương Lâm đi tới Tiên phủ trong thời gian ngắn."],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0940","denChuong":"","cachCoDuoc":"Đang nắm giữ và sử dụng","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0940","loai":"dùng","importance":"normal","giaiDoan":"Tới Tiên phủ lấy máu","text":"Vương Lâm dùng Tiên phủ ngọc giản để tới Tiên phủ, tìm Lôi Cát và lấy máu tươi mang về.","anchor":"từ chỗ những người kia phá bỏ cấm chế tìm được Lôi Cát, trực tiếp lấy ra rất nhiều rồi lập tức quay lại"}]},"capNhatToi":"@c0940","nguon":["@c0940"]},{"id":"mau-tuoi-loi-cat-cu-ma-toc","name":"Máu tươi Lôi Cát Cự Ma Tộc","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Tài liệu luyện thể","phamCap":"không rõ","soHuu":["Vương Lâm","Lôi Cát","Thập Tam"],"trangThai":"đã dùng","blurb":"Máu tươi Lôi Cát Cự Ma Tộc được Vương Lâm lấy từ Lôi Cát để rèn thân thể Thập Tam. Nó là một trong các tài liệu khiến thân thể Thập Tam biến hóa nhanh chóng.","detail":"Vương Lâm tới Tiên phủ tìm Lôi Cát, lấy nhiều máu tươi rồi cho Thập Tam ngâm mình, mở đầu quá trình cải tạo thân thể đầy thống khổ.","dinhDanh":"goc","phanLoaiPhu":"máu tươi Cự Ma Tộc","congNang":["Dùng để ngâm mình và rèn thân thể Thập Tam."],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0940","denChuong":"@c0940","cachCoDuoc":"Lấy từ Lôi Cát tại Tiên phủ","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0940","loai":"dùng","importance":"normal","giaiDoan":"Rèn thân Thập Tam","text":"Vương Lâm lấy máu tươi Lôi Cát Cự Ma Tộc về cho Thập Tam ngâm mình.","anchor":"từ chỗ những người kia phá bỏ cấm chế tìm được Lôi Cát, trực tiếp lấy ra rất nhiều rồi lập tức quay lại"}]},"capNhatToi":"@c0940","nguon":["@c0940"]},{"id":"mau-tuoi-vuong-toc-co-than-cua-vuong-lam","name":"Máu tươi vương tộc Cổ Thần của Vương Lâm","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Tài liệu luyện thể","phamCap":"vương tộc Cổ Thần","soHuu":["Vương Lâm","Thập Tam"],"trangThai":"đã dùng","blurb":"Máu tươi vương tộc Cổ Thần của Vương Lâm được dùng trong quá trình cải tạo Thập Tam. Khi được điểm lên mi tâm, nó gây đau đớn dữ dội nhưng góp phần khiến thân thể Thập Tam tái sinh.","detail":"Đây là nguyên liệu then chốt trong việc Vương Lâm rèn thân cho đại đệ tử, kết hợp với máu Cự Ma Tộc và pháp bảo dung nhập thân thể để tạo biến hóa lớn.","dinhDanh":"goc","phanLoaiPhu":"máu tươi vương tộc Cổ Thần","vatLieu":"Máu tươi của Vương Lâm","congNang":["Điểm lên mi tâm Thập Tam để thúc đẩy quá trình rèn thân và tái sinh trong thống khổ."],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0940","denChuong":"@c0940","cachCoDuoc":"Máu tươi của chính Vương Lâm","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0940","loai":"dùng","importance":"major","giaiDoan":"Điểm mi tâm Thập Tam","text":"Vương Lâm dùng máu tươi vương tộc Cổ Thần của mình điểm lên mi tâm Thập Tam trong quá trình cải tạo thân thể.","anchor":"dùng máu tươi vương tộc Cổ Thần của chính mình điểm lên mi tâm của Thập Tam"}]},"capNhatToi":"@c0940","nguon":["@c0940"]},{"id":"tuong-da-mau-den","name":"Tượng đá màu đen","cn":"","aliases":[],"category":"khac","categoryLabel":"Tượng thờ / vật quỷ dị","phamCap":"không rõ","soHuu":["Luyện Hồn Tông","Thập Tam","Vương Lâm"],"trangThai":"quỷ dị","blurb":"Tượng đá màu đen là tượng thờ mang hình Vương Lâm, ban đầu do Thập Tam khắc thô theo trí nhớ. Qua mấy trăm năm được Luyện Hồn bộ lạc cúng bái, nó dần trở nên giống Vương Lâm như đúc và khiến chính Vương Lâm nghi vấn.","detail":"Tượng vốn chỉ là đá thường, được khắc để Lão Tổ tồn tại trong lòng người Luyện Hồn bộ lạc. Khi Vương Lâm trở lại, tượng đã có ánh mắt linh động và vẻ tang thương như trải qua ngàn năm tu đạo, khiến hắn cảm thấy tượng đang nhìn lại mình và đưa tay dò xét mi tâm.","dinhDanh":"goc","phanLoaiPhu":"tượng thờ","hinhDang":"Tượng đá màu đen khắc hình Vương Lâm.","nguonGoc":"Do Thập Tam dựa theo trí nhớ điêu khắc thành hình Vương Lâm.","dacDiem":"Qua nhiều năm cúng bái, từ tượng thô dần biến thành giống Vương Lâm như đúc.","congNang":["Làm biểu tượng tinh thần để Lão Tổ tồn tại trong lòng người Luyện Hồn bộ lạc.","Tạo cảm giác như đang nhìn lại Vương Lâm khi hắn quan sát."],"chuSoHuu":[{"ten":"Luyện Hồn Tông","tuChuong":"@c0940","denChuong":"","cachCoDuoc":"Được cúng bái qua nhiều năm tại thung lũng sau hoàng cung","trangThai":"đang thờ phụng"}],"tabs":{"tienTrinh":[{"chuong":"@c0940","loai":"xuất hiện","importance":"major","giaiDoan":"Tự biến đổi quỷ dị","text":"Tượng đá màu đen từ tượng khắc thô trở nên giống Vương Lâm như đúc sau mấy trăm năm cúng bái, rồi khiến Vương Lâm đích thân dò xét.","anchor":"bức tượng đá không ngờ lúc đầu chỉ có chút tương tự như Vương Lâm nhưng tới hôm nay đã giống Vương Lâm như đúc!"}]},"capNhatToi":"@c0940","nguon":["@c0940"]},{"id":"co-than-bi-giap","name":"Cổ Thần bì giáp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Giáp nguyên thần","soHuu":["Vương Lâm"],"trangThai":"Đang nằm trên nguyên thần Vương Lâm","blurb":"Giáp trên nguyên thần Vương Lâm, phát thanh quang chống lại lực lượng quỷ dị từ tượng đá màu đen.","detail":"Khi lực lượng như mực nước từ tượng đá màu đen tràn vào nguyên thần, Cổ Thần bì giáp trên nguyên thần Vương Lâm tỏa thanh quang để chống đỡ và phối hợp phong bế đường lui của điểm mực. Nhờ đó lôi đình do nguyên thần Thái Cổ Lôi Long dẫn động có thể đánh tan lực lượng xâm nhập.","nguon":["@c0941"]},{"id":"bau-ruou","name":"Bầu rượu","cn":"","category":"khac","categoryLabel":"Vật phẩm thường","phamCap":"không rõ","soHuu":["Vương Lâm","Đế Quân"],"trangThai":"đã dùng","blurb":"Bầu rượu được Vương Lâm và Đế Quân dùng trong đêm uống rượu bên sông.","detail":"Vương Lâm và Đế Quân uống rượu suốt đêm bên bờ sông trong tiếng đàn ngoài thuyền. Đến sáng, bên người Vương Lâm có nhiều bầu rượu trống.","dinhDanh":"goc","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0942","denChuong":"@c0942","cachCoDuoc":"dùng trong đêm uống rượu bên sông","trangThai":"đã dùng"},{"ten":"Đế Quân","tuChuong":"@c0942","denChuong":"@c0942","cachCoDuoc":"cùng Vương Lâm uống rượu","trangThai":"đã dùng"}],"capNhatToi":"@c0942","nguon":["@c0942"]},{"id":"tam-cam-la-ban","name":"Tâm Cấm la bàn","cn":"","aliases":["la bàn Tâm Cấm"],"category":"phap-bao","categoryLabel":"Pháp bảo cấm khí","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang do Vương Lâm sử dụng","blurb":"La bàn cần có của truyền nhân Phá Diệt Cấm, được Vương Lâm dùng để phá thủy khí cấm trong Tiên phủ.","detail":"Khi thủy khí trước cầu đá hóa thành biển rộng và sóng dữ, Vương Lâm lấy Tâm Cấm la bàn ra, bấm quyết điều động cấm chế rồi phá tan sóng dữ. Vật này gắn trực tiếp với truyền thừa Phá Diệt Cấm và hỗ trợ người dùng lấy cấm phá cấm.","phanLoaiPhu":"cấm khí","chuHienThoi":"Vương Lâm","congNang":["Điều động cấm chế để phá thủy khí sóng dữ trong phạm vi trăm bước trước cầu đá @c0943"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0943","denChuong":"","cachCoDuoc":"Đã mang theo khi tiến vào Tiên phủ","trangThai":"đang giữ"}],"capNhatToi":"@c0943","nguon":["@c0943"]},{"id":"huyen-kim","name":"Huyền kim","cn":"","category":"nguyen-lieu","categoryLabel":"Tài liệu luyện chế","phamCap":"không rõ","soHuu":[],"trangThai":"xuất hiện dưới dạng mười kim tượng","blurb":"Tài liệu tạo nên mười kim tượng ngoài đại điện trong Tiên phủ.","detail":"Vương Lâm nhận ra mười kim tượng ngoài đại điện đều do huyền kim tạo thành. Theo ghi chép trong ngọc giản của Tiên Đế Thanh Lâm, huyền kim là tài liệu chủ yếu để gia tăng cường độ thân thể Tiên vệ.","phanLoaiPhu":"tài liệu cường hóa thân thể khôi lỗi","congNang":["Gia tăng cường độ thân thể của Tiên vệ theo ghi chép trong ngọc giản Tiên Đế Thanh Lâm @c0943"],"capNhatToi":"@c0943","nguon":["@c0943"]},{"id":"ngoc-gian-cua-tien-de-thanh-lam","name":"Ngọc giản của Tiên Đế Thanh Lâm","cn":"","category":"khac","categoryLabel":"Ngọc giản ghi chép","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"được dùng làm nguồn tri thức","blurb":"Ngọc giản ghi chép giúp Vương Lâm nhận ra huyền kim trong Tiên phủ.","detail":"Ngọc giản của Tiên Đế Thanh Lâm chứa ghi chép về huyền kim và công dụng của nó đối với thân thể Tiên vệ. Nhờ ghi chép này, Vương Lâm nhận ra chất liệu của mười kim tượng ngoài đại điện.","congNang":["Cung cấp tri thức nhận biết huyền kim và công dụng tăng cường thân thể Tiên vệ @c0943"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0943","denChuong":"","cachCoDuoc":"Đã có trước khi nhận ra huyền kim","trangThai":"đang giữ"}],"capNhatToi":"@c0943","nguon":["@c0943"]},{"id":"thanh-dao-ky-di-trong-nguyen-than-ngan-thi","name":"Thanh đao kỳ dị trong nguyên thần ngân thi","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ @c0944","soHuu":["Ngân Y Luyện Thi"],"trangThai":"nằm trong nguyên thần ngân thi @c0944","blurb":"Thanh đao kỳ dị nằm trong nguyên thần ngân thi. Khi đánh giá ngân thi, Vương Lâm xem pháp bảo của nàng gần bằng thanh đao này nhưng vẫn không phải sức mạnh đáng sợ nhất.","detail":"Thanh đao được nhắc trong mạch Vương Lâm nhận thức về ngân thi sau khi tế luyện. So với thần thông và pháp bảo, thứ lão tổ đánh giá cao nhất ở ngân thi vẫn là độc tố trong thi thể nàng.","dinhDanh":"goc","phanLoaiPhu":"pháp bảo trong nguyên thần","chuHienThoi":"Ngân Y Luyện Thi","capNhatToi":"@c0944","tabs":{"tienTrinh":[]},"nguon":["@c0944"]},{"id":"huyen-kim-tien-binh","name":"Huyền kim Tiên binh","cn":"","aliases":[],"category":"khac","categoryLabel":"Tiên binh / khôi lỗi chiến đấu","phamCap":"đủ uy hiếp tu sĩ Khuy Niết @c0944","soHuu":["Tiên phủ"],"trangThai":"đang giao chiến với Phù Phong Tử @c0944","blurb":"Ba Tiên binh bằng huyền kim trong nhóm mười Tiên binh xuất động từ đại điện Tiên phủ. Chúng bị Phù Phong Tử tách ra làm mục tiêu trong giao chiến.","detail":"Khi mười Tôn Tiên binh hóa kim quang lao ra cản ngân thi, Phù Phong Tử lập tức chọn ba huyền kim Tiên binh. Đây là một phần cơ chế thủ hộ chiến đấu trong Tiên phủ.","dinhDanh":"goc","phanLoaiPhu":"Tiên binh huyền kim","vatLieu":"huyền kim @c0944","congNang":["Lao ra khỏi đại điện để ngăn ngân thi hấp thu độc trong hoa viên @c0944"],"chuHienThoi":"Tiên phủ","capNhatToi":"@c0944","tabs":{"tienTrinh":[]},"nguon":["@c0944"]},{"id":"huyen-thiet-tien-binh","name":"Huyền thiết Tiên binh","cn":"","aliases":[],"category":"khac","categoryLabel":"Tiên binh / khôi lỗi chiến đấu","phamCap":"đủ uy hiếp tu sĩ Khuy Niết @c0944","soHuu":["Tiên phủ"],"trangThai":"bị Đại Đầu quấn bằng huyết nhục côn @c0944","blurb":"Một Tiên binh bằng huyền thiết trong nhóm mười Tiên binh xuất động từ đại điện Tiên phủ. Nó bị Đại Đầu dùng côn huyết nhục quấn kéo về phía mình.","detail":"Huyền thiết Tiên binh thuộc hệ Tiên binh thủ hộ Tiên phủ. Trong giao chiến tại hoa viên, Đại Đầu dồn huyết nhục lên đầu và phóng côn huyết nhục từ mi tâm để khống chế nó.","dinhDanh":"goc","phanLoaiPhu":"Tiên binh huyền thiết","vatLieu":"huyền thiết @c0944","congNang":["Lao ra khỏi đại điện để ngăn ngân thi hấp thu độc trong hoa viên @c0944"],"chuHienThoi":"Tiên phủ","capNhatToi":"@c0944","tabs":{"tienTrinh":[]},"nguon":["@c0944"]},{"id":"dai-kiem-kim-quang","name":"Đại kiếm kim quang","cn":"","aliases":["Tam cửu chi kiếm"],"category":"phap-bao","categoryLabel":"Pháp bảo kiếm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Thanh đại kiếm kim quang của Vương Lâm, có thể hóa thành hai mươi bảy kiếm. Trong Tiên phủ, nó được dùng thành kiếm trận xuyên phá hắc mãng do Tiên thuật hóa ra.","detail":"Vương Lâm vỗ túi trữ vật gọi đại kiếm kim quang ra khi hắc mãng lao tới. Kiếm hóa thành hai mươi bảy thanh, kết thành kiếm võng xuyên phá công kích của bốn lão già áo xanh.","dinhDanh":"goc","phanLoaiPhu":"Kiếm trận pháp bảo","hinhDang":"Đại kiếm tỏa kim quang","uyLuc":"Có thể hóa hai mươi bảy kiếm thành kiếm võng xuyên phá hắc mãng Tiên thuật.","dacDiem":"Một kiếm phân hóa thành hai mươi bảy kiếm khi thi triển Tam cửu chi kiếm.","chuHienThoi":"Vương Lâm","capNhatToi":"@c0945","congNang":["Hóa hai mươi bảy kiếm kết thành kiếm võng @c0945","Xuyên phá hắc mãng do Tiên thuật hóa ra @c0945"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0945","denChuong":"","cachCoDuoc":"Đã ở trong túi trữ vật của Vương Lâm","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0945","loai":"dùng","importance":"normal","giaiDoan":"Phá hắc mãng","text":"Đại kiếm kim quang được Vương Lâm gọi ra, hóa hai mươi bảy kiếm thành kiếm trận xuyên phá hắc mãng.","anchor":"Thần sắc của Vương Lâm như thường, há mồm phun ra một thứ"}]},"nguon":["@c0945"]},{"id":"loi-chi-tien-gioi-toai-phien","name":"Lôi chi Tiên giới Toái phiến","aliases":["Tiên giới Toái phiến"],"cn":"","category":"phap-bao","categoryLabel":"Pháp bảo hộ mệnh","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Lôi chi Tiên giới Toái phiến là pháp bảo hộ mệnh do Viêm Lôi Tử ban cho Vương Lâm, bị Hoa Tiên đánh vỡ trong Tiên phủ.","detail":"Pháp bảo được Vương Lâm phun ra làm tấm chắn trăm trượng trước chỉ lực của Hoa Tiên. Trên Toái phiến vốn đã có vết nứt nhỏ do thần thông Thiên Vận Tử để lại, sau đó bị các đóa hoa của Hoa Tiên va chạm đánh vỡ tứ phân ngũ liệt.","dinhDanh":"goc","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0946","denChuong":"@c0946","cachCoDuoc":"Do Viêm Lôi Tử ban tặng","trangThai":"bị đánh vỡ"}],"congNang":["Tạo phòng hộ trăm trượng để chống chỉ lực của Hoa Tiên @c0946"],"dacDiem":"Có vết nứt nhỏ do thần thông Thiên Vận Tử tạo ra trước khi bị Hoa Tiên đánh vỡ.","tabs":{"tienTrinh":[{"chuong":"@c0946","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Bị Hoa Tiên đánh vỡ","phamCap":"không rõ","text":"Vương Lâm phun Lôi chi Tiên giới Toái phiến ra làm phòng hộ trăm trượng trước chỉ lực của Hoa Tiên. Các đóa hoa va chạm khiến pháp bảo hộ mệnh do Viêm Lôi Tử ban tặng tứ phân ngũ liệt.","anchor":"Theo thanh âm này xuất hiện, những đóa hoa kia liền va chạm với Tiên giới Toái phiến, tạo ra một tiếng ầm lớn."}]},"capNhatToi":"@c0946","nguon":["@c0946"]},{"id":"tam-bia-da-kim-quang-cua-phu-phong-tu","name":"Tấm bia đá kim quang của Phù Phong Tử","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Phù Phong Tử"],"trangThai":"dang-co","blurb":"Tấm bia đá kim quang được Phù Phong Tử tế ra để hỗ trợ Vương Lâm phá mai rùa trong Tiên phủ.","detail":"Phù Phong Tử tế ra một tấm bia đá lớn có nhiều ấn ký và kim quang lượn lờ, đánh vào mai rùa để phối hợp với Diệt Thần Mâu và khói nhiều màu của ngân thi.","dinhDanh":"goc","chuHienThoi":"Phù Phong Tử","chuSoHuu":[{"ten":"Phù Phong Tử","tuChuong":"@c0946","denChuong":"","cachCoDuoc":"đã sở hữu khi vào Tiên phủ","trangThai":"đang giữ"}],"congNang":["Đánh vào mai rùa để hỗ trợ phá lớp chắn trước thông đạo @c0946"],"tabs":{"tienTrinh":[{"chuong":"@c0946","loai":"dùng","importance":"normal","giaiDoan":"Hợp lực phá mai rùa","phamCap":"không rõ","text":"Phù Phong Tử tế tấm bia đá kim quang đầy ấn ký đánh vào mai rùa, góp sức cùng Vương Lâm và ngân thi phá lớp chắn.","anchor":"Cuối cùng một tiếng ầm vang lên, mai rùa đã hoàn toàn sụp đổ!"}]},"capNhatToi":"@c0946","nguon":["@c0946"]},{"id":"mai-rua-quy-xac","name":"Mai rùa / quy xác","aliases":["quy xác"],"cn":"","category":"khac","categoryLabel":"Phong bế / vật chắn","phamCap":"không rõ","soHuu":[],"trangThai":"hong","blurb":"Mai rùa là lớp chắn trước thông đạo động phủ trong Tiên phủ, bị nhóm Vương Lâm hợp lực phá vỡ.","detail":"Lớp chắn chịu hợp kích của bia đá kim quang, khói nhiều màu và Diệt Thần Mâu. Các khe nứt mở rộng dần, cuối cùng mai rùa hoàn toàn sụp đổ.","dinhDanh":"goc","congNang":["Phong bế thông đạo trước đại điện trong Tiên phủ @c0946"],"tabs":{"tienTrinh":[{"chuong":"@c0946","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Bị hợp lực phá vỡ","phamCap":"không rõ","text":"Mai rùa chịu hợp kích của bia đá kim quang, khói nhiều màu và Diệt Thần Mâu, cuối cùng hoàn toàn sụp đổ.","anchor":"Cuối cùng một tiếng ầm vang lên, mai rùa đã hoàn toàn sụp đổ!"}]},"capNhatToi":"@c0946","nguon":["@c0946"]},{"id":"khoi-nhieu-mau-cua-ngan-thi","name":"Khói nhiều màu của ngân thi","cn":"","category":"khac","categoryLabel":"Vật / thuật phun ra","phamCap":"không rõ","soHuu":["Ngân thi"],"trangThai":"bi-che-ngu","blurb":"Khói nhiều màu được ngân thi phun ra để ăn mòn mai rùa nhưng bị Hoa Tiên hóa thành hoa.","detail":"Ngân thi phun khói nhiều màu bao phủ mai rùa, làm các khe nứt trên lớp chắn mở rộng. Sau khi mai rùa vỡ, khói nhiều màu bị nữ tử áo trắng dùng một chỉ hóa thành một đóa hoa nhiều màu lơ lửng bất động.","dinhDanh":"goc","chuHienThoi":"Ngân thi","chuSoHuu":[{"ten":"Ngân thi","tuChuong":"@c0946","denChuong":"@c0946","cachCoDuoc":"do ngân thi phun ra","trangThai":"bị Hoa Tiên hóa thành hoa"}],"congNang":["Bao phủ và ăn mòn mai rùa, khiến khe nứt mở rộng @c0946"],"tabs":{"tienTrinh":[{"chuong":"@c0946","loai":"dùng","importance":"normal","giaiDoan":"Ăn mòn mai rùa","phamCap":"không rõ","text":"Ngân thi phun khói nhiều màu bao phủ mai rùa để mở rộng khe nứt, nhưng sau đó khói bị Hoa Tiên hóa thành đóa hoa nhiều màu.","anchor":"Một bàn tay trắng nõn từ chỗ tối trong đại điện vươn ra, nhẹ nhàng điểm về phía Diệt Thần Mâu một cái."}]},"capNhatToi":"@c0946","nguon":["@c0946"]},{"id":"tien-ngoc-thap","name":"Tiên ngọc tháp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Tòa tháp lóe huỳnh quang do Vương Lâm lấy ra trong lúc đối đầu nữ tử áo trắng.","detail":"Bên trong Tiên ngọc tháp có thi thể Thanh Ải đang ngủ say. Khi Vương Lâm lấy tháp ra, thi thể xuất hiện giữa hắn và nữ tử áo trắng, khiến nàng chấn động mạnh.","congNang":["Chứa thi thể Thanh Ải đang ngủ say và có thể được Vương Lâm lấy ra giữa chiến cuộc @c0947"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0947","denChuong":"","cachCoDuoc":"đã mang theo trước khi chương bắt đầu","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[]},"capNhatToi":"@c0947","nguon":["@c0947"]},{"id":"tram-cai-toc-khac-doa-hoa","name":"Trâm cài tóc khắc đóa hoa","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Nữ tử áo trắng"],"trangThai":"đang dùng","blurb":"Trâm cài tóc của nữ tử áo trắng, được dùng như pháp bảo công kích trong động phủ.","detail":"Nữ tử áo trắng tháo trâm trên tóc ném về phía Vương Lâm. Trâm lóe tử quang, phát tiếng bén nhọn, công kích nhanh đến mức Vương Lâm khó thấy bóng dáng và có thể xuyên thân hủy nguyên thần.","congNang":["Tạo tử quang công kích cực nhanh, uy hiếp thân thể và nguyên thần mục tiêu @c0947"],"chuSoHuu":[{"ten":"Nữ tử áo trắng","tuChuong":"@c0947","denChuong":"","cachCoDuoc":"vốn cài trên tóc","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[]},"capNhatToi":"@c0947","nguon":["@c0947"]},{"id":"thi-the-thanh-ai","name":"Thi thể Thanh Ải","cn":"","category":"khac","categoryLabel":"Thi thể","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"ngủ say trong Tiên ngọc tháp","blurb":"Thi thể của Thanh Ải nằm trong Tiên ngọc tháp, trở thành mấu chốt khiến nữ tử áo trắng dao động.","detail":"Thi thể Thanh Ải ngủ say bên trong Tiên ngọc tháp. Khi Vương Lâm lấy ra đặt giữa mình và nữ tử áo trắng, nàng lập tức như bị sét đánh, cho thấy thi thể này có tác động đặc biệt với nàng.","congNang":["Tác động mạnh tới tâm thần nữ tử áo trắng khi xuất hiện trước mặt nàng @c0947"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0947","denChuong":"","cachCoDuoc":"được giữ trong Tiên ngọc tháp","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[]},"capNhatToi":"@c0947","nguon":["@c0947"]},{"id":"binh-bach-ngoc","name":"Bình bạch ngọc","aliases":["bình ngọc nhỏ màu trắng"],"cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Tư Đồ Nam"],"trangThai":"vỡ thành mảnh @c0948","blurb":"Bình bạch ngọc là vật bị Tư Đồ Nam truy đuổi trong động phủ. Nó có khả năng tan vỡ rồi tái hợp, cuối cùng nổ thành mảnh trong tay Hoa Phi Hàm Yên.","detail":"Bình bạch ngọc chủ động né tránh khi bị Tư Đồ Nam truy đuổi. Nó từng tan vỡ khi bị màn sương đen hóa thành mãnh thú cắn nuốt, sau đó mảnh vỡ lại ngưng tụ thành hình rồi bay tới tay Hoa Phi Hàm Yên, nơi nó nổ tung để tạo cơ hội cho Vương Lâm và Tư Đồ Nam rút lui.","phanLoaiPhu":"vật phẩm có linh tính","hinhDang":"bình ngọc nhỏ màu trắng","congNang":["Có thể tan vỡ thành mảnh rồi tái hợp @c0948","Có thể tự bay trốn trong động phủ @c0948","Nổ thành mảnh trong tay Hoa Phi Hàm Yên để tạo thời cơ rút lui @c0948"],"dacDiem":"Có biểu hiện tự chủ rõ rệt, liên tục né tránh truy đuổi và tái hợp sau khi vỡ.","chuHienThoi":"Tư Đồ Nam","chuSoHuu":[{"ten":"Tư Đồ Nam","tuChuong":"@c0948","denChuong":"","cachCoDuoc":"Truy đuổi trong động phủ","trangThai":"tạm nắm quyền truy đuổi, sau đó vật nổ vỡ"}],"tabs":{"tienTrinh":[{"chuong":"@c0948","loai":"xuất hiện","importance":"normal","giaiDoan":"Trong động phủ","text":"Bình bạch ngọc bị Tư Đồ Nam truy đuổi, nhiều lần tan vỡ rồi tái hợp, cuối cùng nổ trong tay Hoa Phi Hàm Yên.","anchor":"không ngờ trong khoảnh khắc khi mãnh thú do màn sương đen hóa thành cắn nuốt đến lại bụp một tiếng tan vỡ"}]},"capNhatToi":"@c0948","nguon":["@c0948"]},{"id":"tinh-quang-trong-dai-dien","name":"Tinh quang trong đại điện","aliases":[],"cn":"","category":"khac","categoryLabel":"Ánh sáng đặc biệt","phamCap":"không rõ","soHuu":["Hoa Phi Hàm Yên"],"trangThai":"đã xuất hiện @c0948","blurb":"Tinh quang trong đại điện là ánh sáng mông lung do Hoa Phi Hàm Yên tạo ra. Nó chiếu rõ bóng tối đặc biệt của đại điện, giúp Vương Lâm nhìn thấy chín pho tượng.","detail":"Hoa Phi Hàm Yên vung tay tạo một luồng tinh quang mông lung trong đại điện hắc ám. Ánh sáng này không phải ánh sáng bình thường, có thể xua đi bóng tối nơi thần thức và tầm nhìn đều bị hạn chế, từ đó làm lộ chín pho tượng trong điện.","phanLoaiPhu":"ánh sáng do thuật lực tạo ra","congNang":["Chiếu sáng đại điện hắc ám đặc biệt, làm lộ chín pho tượng @c0948"],"chuHienThoi":"Hoa Phi Hàm Yên","chuSoHuu":[{"ten":"Hoa Phi Hàm Yên","tuChuong":"@c0948","denChuong":"","cachCoDuoc":"Tự tạo ra trong đại điện","trangThai":"đang sử dụng"}],"tabs":{"tienTrinh":[{"chuong":"@c0948","loai":"dùng","importance":"normal","giaiDoan":"Trong đại điện hắc ám","text":"Hoa Phi Hàm Yên tạo tinh quang để chiếu sáng đại điện, khiến Vương Lâm nhìn thấy chín pho tượng.","anchor":"tinh quang này tuyệt đối không phải ánh sáng bình thường"}]},"capNhatToi":"@c0948","nguon":["@c0948"]},{"id":"pho-tuong-tien-de-thanh-lam","name":"Pho tượng Tiên Đế Thanh Lâm","aliases":["pho tượng nam tử trung niên hoàng bào"],"cn":"","category":"khac","categoryLabel":"Pho tượng","phamCap":"không rõ","soHuu":[],"trangThai":"đặt trong đại điện hắc ám @c0948","blurb":"Pho tượng Tiên Đế Thanh Lâm là pho tượng trung tâm trong đại điện hắc ám. Hình tượng nam tử trung niên mặc hoàng bào thêu chín tử long tỏa uy áp vượt xa các cường giả Vương Lâm từng biết.","detail":"Pho tượng trung tâm khắc một nam tử trung niên oai hùng, mặc hoàng bào thêu chín tử long, phía sau có mây đen. Chỉ nhìn vào mắt pho tượng, Vương Lâm đã bị khí tức vô hình công kích đến thổ huyết, nguyên lực bị áp chế, máu dồn phá tim và thân thể bị ép khuất phục, buộc hắn phải bộc phát Cổ Thần lực phản kháng.","phanLoaiPhu":"pho tượng trung tâm trong đại điện","hinhDang":"nam tử trung niên oai hùng mặc hoàng bào thêu chín tử long, sau lưng có mây đen","uyLuc":"Uy áp từ pho tượng có thể áp chế nguyên lực của Vương Lâm và ép thân thể hắn khuất phục.","dacDiem":"Khí tức của pho tượng được Vương Lâm cảm nhận là vượt xa Thanh Thủy, Viêm Lôi Tử và Thiên Vận Tử.","congNang":["Tỏa uy áp vô hình khiến Vương Lâm thổ huyết và nguyên lực bị áp chế @c0948"],"tabs":{"tienTrinh":[{"chuong":"@c0948","loai":"xuất hiện","importance":"major","giaiDoan":"Trung tâm đại điện hắc ám","text":"Pho tượng trung tâm lộ ra trong tinh quang, tỏa uy áp khủng khiếp khiến Vương Lâm thổ huyết và phải bộc phát Cổ Thần lực chống lại.","anchor":"Pho tượng này điêu khắc một trung niên nam tử"}]},"capNhatToi":"@c0948","nguon":["@c0948"]},{"id":"chia-khoa-trong-khoi-xanh","name":"Chìa khóa trong khói xanh","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm mở động phủ","phamCap":"không rõ","soHuu":["Lăng Thiên Hậu"],"trangThai":"đã dùng @c0950","blurb":"Chìa khóa mơ hồ hiện ra trong khói xanh do Lăng Thiên Hậu gọi tới. Nó được dùng để kích hoạt hắc thạch và mở trận pháp động phủ thứ ba.","detail":"Lăng Thiên Hậu mở khe hở hư không, từ đó mảng lớn khói xanh bay ra và chìa khóa mơ hồ hiện lên. Chìa khóa này dung nhập với hắc thạch để khiến trận pháp động phủ thứ ba mở ra.","dinhDanh":"goc","phanLoaiPhu":"vật phẩm mở động phủ","hinhDang":"chìa khóa mơ hồ trong khói xanh","congNang":["Kích hoạt hắc thạch để mở trận pháp động phủ thứ ba @c0950"],"chuHienThoi":"Lăng Thiên Hậu","chuSoHuu":[{"ten":"Lăng Thiên Hậu","tuChuong":"@c0950","denChuong":"","cachCoDuoc":"Gọi ra từ khe hở hư không trong khói xanh","trangThai":"đã dùng"}],"capNhatToi":"@c0950","tabs":{"tienTrinh":[{"chuong":"@c0950","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở động phủ thứ ba","text":"Chìa khóa mơ hồ hiện trong khói xanh và được Lăng Thiên Hậu dùng để kích hoạt hắc thạch động phủ thứ ba.","anchor":"từ bên trong đó bay ra mảnh lớn khói xanh, chìa khóa mơ hồ hiện ra"}]},"nguon":["@c0950"]},{"id":"hac-thach-tran-phap-dong-phu","name":"Hắc thạch trận pháp động phủ","cn":"","aliases":["Hòn đá màu đen"],"category":"khac","categoryLabel":"Trung tâm trận pháp","phamCap":"không rõ","soHuu":["Lăng Thiên Hậu","Vương Nguy"],"trangThai":"đã kích hoạt @c0950","blurb":"Hắc thạch là trung tâm vận chuyển trận pháp trong các động phủ vùng đất Yêu Linh. Khi nhận khói xanh hoặc chưởng lực của người khai mở, nó dẫn dắt trận pháp vận chuyển và kéo theo cột sáng.","detail":"Hắc thạch xuất hiện trong các động phủ, được Lăng Thiên Hậu dùng khói xanh và chìa khóa kích hoạt ở động phủ thứ ba, cũng được Vương Nguy vỗ vào trong động phủ thứ nhất. Mỗi lần kích hoạt, hắc thạch khiến trận pháp mở ra hoặc vận chuyển.","dinhDanh":"goc","phanLoaiPhu":"trung tâm trận pháp","hinhDang":"hòn đá màu đen","congNang":["Làm trung khu vận chuyển trận pháp động phủ và liên động cột sáng @c0950"],"chuSoHuu":[{"ten":"Lăng Thiên Hậu","tuChuong":"@c0950","denChuong":"","cachCoDuoc":"Điều khiển hắc thạch trong động phủ thứ ba","trangThai":"đã kích hoạt"},{"ten":"Vương Nguy","tuChuong":"@c0950","denChuong":"","cachCoDuoc":"Kích hoạt hắc thạch trong động phủ thứ nhất","trangThai":"đã kích hoạt"}],"capNhatToi":"@c0950","tabs":{"tienTrinh":[{"chuong":"@c0950","loai":"dùng","importance":"normal","giaiDoan":"Dẫn động trận pháp","text":"Hắc thạch nhận tác động từ người khai mở, lóe hào quang và dẫn dắt trận pháp động phủ vận chuyển.","anchor":"hắc thạch này lập tức lóe ra hào quang dẫn dắt toàn bộ trận pháp vận chuyển"}]},"nguon":["@c0950"]},{"id":"co-than-dinh","name":"Cổ Thần đỉnh","cn":"","aliases":["Cổ Thần đại đỉnh"],"category":"phap-bao","categoryLabel":"Bảo vật Cổ Thần","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang thuộc Vương Lâm","blurb":"Bảo vật Cổ Thần được Vương Lâm dùng trong động phủ thứ năm để dịch chuyển cự ly ngắn. Nó giúp hắn kéo giãn khoảng cách với gió xoáy nhưng không thể thoát hoàn toàn khỏi nguy cơ.","detail":"Vương Lâm rót Cổ Thần lực vào Cổ Thần đỉnh, nhờ bảo vật này thân ảnh lập tức biến mất rồi xuất hiện ngoài khoảng trăm trượng. Trong sa mạc đen, hắn nhiều lần dùng đỉnh để giữ khoảng cách với gió xoáy đang truy kích.","phanLoaiPhu":"bảo vật Cổ Thần","chuHienThoi":"Vương Lâm","congNang":["Dịch chuyển từng đoạn ngắn khoảng trăm trượng khi được Cổ Thần lực kích phát @c0953"],"dacDiem":"Trong động phủ thứ năm chỉ giúp bảo trì khoảng cách ngắn, không thể đưa Vương Lâm thoát khỏi truy kích.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0953","denChuong":"","cachCoDuoc":"đã mang theo trước khi vào động phủ thứ năm","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0953","loai":"dùng","importance":"normal","giaiDoan":"Dịch chuyển tránh gió xoáy","text":"Vương Lâm dùng Cổ Thần đỉnh để dịch chuyển từng đoạn trăm trượng nhằm kéo giãn khoảng cách với gió xoáy.","anchor":"dựa vào bảo vật của Cổ Thần, thân ảnh của hắn lập tức biến mất","phamCap":"không rõ"}]},"capNhatToi":"@c0953","nguon":["@c0953"]},{"id":"hon-muoi-thanh-dai-kiem","name":"Hơn mười thanh đại kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo kiếm trận tiêu hao","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã tự bạo","blurb":"Nhóm đại kiếm Vương Lâm lấy ra từ túi trữ vật trong động phủ thứ năm. Chúng được lập thành kiếm trận rồi tự bạo để làm chậm gió xoáy truy kích.","detail":"Khi bị gió xoáy màu xám đuổi sát, Vương Lâm vung tay lấy hơn mười thanh đại kiếm, cho chúng gào thét lao ra tạo thành kiếm trận. Hắn kích cho toàn bộ phát ra khí tức hủy diệt và tự bạo, khiến vô số mảnh vỡ cuốn vào gió xoáy.","phanLoaiPhu":"kiếm trận tiêu hao","chuHienThoi":"Vương Lâm","congNang":["Lập kiếm trận rồi tự bạo để cản truy kích @c0953"],"uyLuc":"Vụ tự bạo khiến tốc độ gió xoáy hơi khựng lại.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0953","denChuong":"@c0953","cachCoDuoc":"lấy ra từ túi trữ vật","trangThai":"đã tự bạo"}],"tabs":{"tienTrinh":[{"chuong":"@c0953","loai":"dùng","importance":"normal","giaiDoan":"Tự bạo cản gió xoáy","text":"Vương Lâm lấy hơn mười thanh đại kiếm lập trận rồi cho tự bạo để làm chậm gió xoáy.","anchor":"lập tức có hơn mười thanh đại kiếm gào thét lao ra","phamCap":"không rõ"}]},"capNhatToi":"@c0953","nguon":["@c0953"]},{"id":"binh-nho-nut-go-truoc-ma-anh","name":"Bình nhỏ nút gỗ trước Ma ảnh","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm chưa rõ","phamCap":"không rõ","soHuu":["Ma ảnh nơi cầu gỗ"],"trangThai":"chưa rõ","blurb":"Bình nhỏ lơ lửng trước Ma ảnh nơi cầu gỗ trong động phủ thứ năm. Miệng bình có nút gỗ đóng lại, chưa lộ vật chứa bên trong.","detail":"Ở sâu trong động phủ thứ năm, trước bóng người bị sương đen và ma khí bao phủ có một bình nhỏ đang lơ lửng. Miệng bình bị nút gỗ đóng kín nên chưa thể biết bên trong chứa gì.","phanLoaiPhu":"vật phẩm chưa rõ","hinhDang":"bình nhỏ có nút gỗ","chuHienThoi":"Ma ảnh nơi cầu gỗ","dacDiem":"Lơ lửng trước Ma ảnh, miệng bình đóng kín bằng nút gỗ.","chuSoHuu":[{"ten":"Ma ảnh nơi cầu gỗ","tuChuong":"@c0953","denChuong":"","cachCoDuoc":"đặt trước người tại cầu gỗ","trangThai":"đang ở trước mặt"}],"tabs":{"tienTrinh":[{"chuong":"@c0953","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện trước Ma ảnh","text":"Bình nhỏ xuất hiện lơ lửng trước Ma ảnh, miệng bị nút gỗ đóng kín.","anchor":"Ở trước người hắn nổi lơ lửng một cái bình nhỏ","phamCap":"không rõ"}]},"capNhatToi":"@c0953","nguon":["@c0953"]},{"id":"thap-tan-ma","name":"Tháp Tán Ma","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Ma tháp","phamCap":"Không rõ","soHuu":["Tán Ma","Cổ Ma"],"trangThai":"xuất hiện trong hoang mạc cát đen","blurb":"Tòa tháp đen tràn ma khí xuất hiện trong hoang mạc cát đen của động phủ Thanh Lâm. Nó gợi lại tháp Tán Ma Vương Lâm từng biết ở vùng đất Yêu Linh.","detail":"Tháp Tán Ma có đặc tính khiến người trong đó khó đào thoát; nếu không thể thăng tiên tránh né thì có thể mất bản tính. Sự xuất hiện của nó trong động phủ Thanh Lâm khiến Vương Lâm liên hệ tới Cổ Ma và Cổ Yêu Bối La.","phanLoaiPhu":"Ma tháp giam giữ","hinhDang":"Tòa tháp cao màu đen","congNang":["Giam giữ khiến người trong đó khó đào thoát @c0956","Có thể khiến kẻ trong tháp mất bản tính nếu không thăng tiên trốn tránh @c0956"],"dacDiem":"Tràn ma khí và liên quan đến hệ Tán Ma dưới Cổ Ma.","chuSoHuu":[{"ten":"Tán Ma","tuChuong":"@c0956","denChuong":"","cachCoDuoc":"Liên hệ qua tháp Tán Ma","trangThai":"liên quan"},{"ten":"Cổ Ma","tuChuong":"@c0956","denChuong":"","cachCoDuoc":"Được suy luận là tầng trên của Tán Ma","trangThai":"liên quan"}],"tabs":{"tienTrinh":[{"chuong":"@c0956","loai":"xuất hiện","importance":"normal","giaiDoan":"Trong hoang mạc cát đen","text":"Tháp Tán Ma xuất hiện giữa hoang mạc cát đen trong động phủ Thanh Lâm và khiến Vương Lâm suy luận về Cổ Ma.","anchor":"Vật này có thần thông khiến người trong đó vô pháp đào thoát"}]},"capNhatToi":"@c0956","nguon":["@c0956"]},{"id":"thap-bat-dia-nguc-phong-tien-an","name":"Thập Bát Địa Ngục Phong Tiên Ấn","cn":"","aliases":["Phong Tiên Ấn"],"category":"phap-bao","categoryLabel":"Pháp bảo dạng ấn","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang được Vương Lâm sử dụng @c0957","blurb":"Thập Bát Địa Ngục Phong Tiên Ấn là pháp bảo dạng ấn của Vương Lâm. Khi bị bão cát vây ép, ấn được phun ra và hóa lớn như một ngọn núi nhỏ trước người hắn.","detail":"Trong trận với Minh Hải, Vương Lâm phun ra Thập Bát Địa Ngục Phong Tiên Ấn. Pháp bảo lập tức xuất hiện trước người hắn, biến lớn như một ngọn núi nhỏ và được dùng phối hợp với Rải đậu thành binh để chống thế công cát đen.","dinhDanh":"bien-the","congNang":["Phóng lớn trước người chủ nhân như một ngọn núi nhỏ trong lúc giao chiến @c0957"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0957","denChuong":"","cachCoDuoc":"đã sở hữu trước chương này","trangThai":"đang sử dụng"}],"tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"dùng","importance":"normal","giaiDoan":"chống bão cát","text":"Vương Lâm gọi Thập Bát Địa Ngục Phong Tiên Ấn ra trước người, để ấn hóa lớn như một ngọn núi nhỏ khi cát đen vây tới.","anchor":"Thập Bát Địa Ngục Phong Tiên Ấn lập tức xuất hiện, ở trước người Vương Lâm biến lớn hóa thành như một ngọn núi nhỏ."}]},"capNhatToi":"@c0957","nguon":["@c0957"]},{"id":"dai-mac-co-yen-do","name":"Sơn Hà Đồ - Đại Mạc Cô Yên","cn":"","aliases":["Đại Mạc Cô Yên đồ"],"category":"phap-bao","categoryLabel":"Trọng bảo","phamCap":"không rõ","soHuu":["Thanh Lâm"],"trangThai":"được Minh Hải nêu làm cơ hội đạt được @c0957","blurb":"Sơn Hà Đồ - Đại Mạc Cô Yên là trọng bảo liên quan Tiên Đế Thanh Lâm. Minh Hải nói Vương Lâm nếu giết được hắn thì có cơ hội đạt được vật này.","detail":"Minh Hải dùng Sơn Hà Đồ - Đại Mạc Cô Yên của Tiên Đế Thanh Lâm như phần thưởng hoặc mục tiêu trong cuộc giao chiến ở tháp đen. Chương này chỉ hé lộ tên vật và mối liên hệ với Thanh Lâm, chưa nói rõ hình dạng hay uy lực.","dinhDanh":"goc","nguonGoc":"liên quan Tiên Đế Thanh Lâm @c0957","congNang":["Được Minh Hải nêu như cơ hội đạt được sau khi giết hắn @c0957"],"chuSoHuu":[{"ten":"Thanh Lâm","tuChuong":"@c0957","denChuong":"","cachCoDuoc":"được Minh Hải gọi là vật của Tiên Đế Thanh Lâm","trangThai":"chưa rõ hiện trạng"}],"tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"nhắc tới","importance":"normal","giaiDoan":"điều kiện của Minh Hải","text":"Minh Hải nói Vương Lâm giết được hắn thì có cơ hội đạt được Sơn Hà Đồ - Đại Mạc Cô Yên của Tiên Đế Thanh Lâm.","anchor":"Giết ta, ngươi có cơ hội đạt được Sơn Hà Đồ - Đại Mạc Cô Yên của Tiên Đế Thanh Lâm!"}]},"capNhatToi":"@c0957","nguon":["@c0957"]},{"id":"phuong-truc","name":"Phương Trúc","cn":"","aliases":["kiếm nhỏ màu trắng","thanh kiếm nhỏ màu trắng","kiếm nhỏ Phương Trúc"],"category":"phap-bao","categoryLabel":"Kiếm nhỏ","phamCap":"không rõ","soHuu":["Minh Hải"],"trangThai":"được Minh Hải gọi ra @c0957","blurb":"Phương Trúc là kiếm nhỏ màu trắng dài ba tấc do Minh Hải gọi ra từ mi tâm. Minh Hải nói kiếm này năm xưa được Tiên Đế ban tặng.","detail":"Cuối chương 957, Minh Hải điểm mi tâm, phóng bạch quang hóa thành một thanh kiếm nhỏ màu trắng. Kiếm vừa xuất hiện đã tỏa kiếm khí kinh người, và Minh Hải gọi rõ tên Phương Trúc, nói nó là kiếm năm xưa Tiên Đế ban tặng.","dinhDanh":"goc","hinhDang":"kiếm nhỏ màu trắng dài ba tấc @c0957","nguonGoc":"năm xưa do Tiên Đế ban tặng theo lời Minh Hải @c0957","uyLuc":"vừa xuất hiện đã tràn ra kiếm khí kinh người @c0957","congNang":["Phóng ra kiếm khí kinh người khi được gọi ra từ mi tâm Minh Hải @c0957"],"chuSoHuu":[{"ten":"Minh Hải","tuChuong":"@c0957","denChuong":"","cachCoDuoc":"được Tiên Đế ban tặng theo lời Minh Hải","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"xuất hiện","importance":"major","giaiDoan":"Minh Hải gọi kiếm","text":"Minh Hải điểm mi tâm gọi ra kiếm nhỏ Phương Trúc và nói kiếm này năm xưa được Tiên Đế ban tặng.","anchor":"Kiếm này năm xưa Tiên Đế ban tặng, tên là Phương Trúc!"}]},"capNhatToi":"@c0957","nguon":["@c0957"]},{"id":"nut-go-den-cua-binh-ngoc","name":"Nút gỗ đen của bình ngọc","cn":"","aliases":[],"category":"khac","categoryLabel":"Nút bình","phamCap":"Không rõ","soHuu":["Người trong sương đen trên cầu gỗ động phủ"],"trangThai":"đang gắn với Bình bạch ngọc","blurb":"Nút gỗ đen là vật nút miệng Bình bạch ngọc trước người trong sương đen trên cầu gỗ. Khi thiên địa lực do Công Linh kéo tới, nó run rẩy và tụt xuống một ít.","detail":"Trong động phủ thứ năm, lúc thiên địa lực bị dẫn tới làm bình ngọc trắng rung dữ dội, nút gỗ đen ở miệng bình cũng chịu lực hút, run rẩy như sắp bị hút vào trong bình. Chương chưa giải thích lai lịch hay công dụng riêng của nút gỗ này.","phanLoaiPhu":"nút bình","hinhDang":"nút gỗ màu đen","dacDiem":"Run rẩy và tụt xuống một ít khi Bình bạch ngọc chịu tác động từ thiên địa lực.","chuHienThoi":"Người trong sương đen trên cầu gỗ động phủ","chuSoHuu":[{"ten":"Người trong sương đen trên cầu gỗ động phủ","tuChuong":"@c0958","denChuong":"","cachCoDuoc":"Xuất hiện trước người trong sương đen cùng Bình bạch ngọc","trangThai":"đang giữ"}],"congNang":["Nút miệng Bình bạch ngọc và phản ứng với lực hút khi thiên địa lực lao tới @c0958"],"tabs":{"tienTrinh":[{"chuong":"@c0958","loai":"xuất hiện","importance":"normal","giaiDoan":"Phản ứng với Công Linh","text":"Nút gỗ đen trên miệng bình run rẩy và tụt xuống một ít khi bình ngọc trắng bị thiên địa lực do Công Linh dẫn tới tác động.","anchor":"Cái nút gỗ đen nút miệng bình không ngờ run rẩy"}]},"capNhatToi":"@c0958","nguon":["@c0958"]},{"id":"manh-vo-ma-khi-trong-dau-minh-hai","name":"Mảnh vỡ ma khí trong đầu Minh Hải","cn":"","aliases":[],"category":"khac","categoryLabel":"Dị vật ma khí","phamCap":"không rõ","soHuu":["Minh Hải"],"trangThai":"bị ánh sáng bảy màu phong kín","blurb":"Mảnh vỡ ma khí nằm sâu trong vết sẹo trên trán Minh Hải. Nó liên tục tỏa khí đen dung nhập vào đầu hắn, là nguyên nhân khiến Minh Hải rơi vào trạng thái ma hóa.","detail":"Khi Xạ Thần Xa phá giáp và làm lộ thân thể thật của Minh Hải, Vương Lâm nhìn thấy trong vết sẹo trên trán hắn có một mảnh vỡ màu đen. Phấn bảy màu từ bướm Xạ Thần Xa chui vào miệng vết thương, che kín mảnh vỡ và chặn ma khí tiếp tục dung nhập, khiến Minh Hải tỉnh ngộ trước khi tự diệt.","phanLoaiPhu":"mảnh vỡ ma khí","hinhDang":"mảnh vỡ màu đen nằm trong vết sẹo trên trán","uyLuc":"Có thể phát tán ma khí làm Minh Hải ma hóa trong thời gian dài.","dacDiem":"Bị phấn bảy màu của Xạ Thần Xa bao phủ thì dòng ma khí bị chặn lại.","chuHienThoi":"Minh Hải","congNang":["Tỏa khí đen dung nhập vào đầu Minh Hải @c0959","Khi bị phấn bảy màu che kín, ma khí bị chặn và Minh Hải tỉnh khỏi ma hóa @c0959"],"chuSoHuu":[{"ten":"Minh Hải","tuChuong":"@c0959","denChuong":"@c0959","cachCoDuoc":"nằm trong vết thương trên trán trước khi chương hé lộ","trangThai":"bị phong kín trước lúc Minh Hải tự diệt"}],"tabs":{"tienTrinh":[{"chuong":"@c0959","loai":"khai phong","importance":"major","giaiDoan":"lộ nguyên nhân ma hóa","text":"Mảnh vỡ ma khí trong vết sẹo trên trán Minh Hải bị lộ ra và bị phấn bảy màu phong kín, khiến Minh Hải tỉnh khỏi ma hóa.","anchor":"Ở chỗ sâu trong có một mảnh vỡ màu đen"}]},"dinhDanh":"goc","capNhatToi":"@c0959","nguon":["@c0959"]},{"id":"tu-mau-kho-thu-cot","name":"Tử Mẫu Khô Thú cốt","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Thú cốt","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang được Vương Lâm giữ","blurb":"Tử Mẫu Khô Thú cốt là vật phẩm hiện thành đồ án trên tay phải Vương Lâm. Trong trận với Minh Hải, nó tỏa sát khí để làm nghi binh cho Thuật Định Thân.","detail":"Vương Lâm dùng đồ án Tử Mẫu Khô Thú cốt trên tay phải như một đòn tập kích sau lưng Minh Hải. Động tác này buộc Minh Hải chú ý, tạo khoảng trống để Vương Lâm thi triển Thuật Định Thân và đưa phấn bảy màu vào vết thương ma khí.","phanLoaiPhu":"thú cốt","hinhDang":"đồ án hiện trên tay phải Vương Lâm","uyLuc":"Tỏa sát khí khi được kích phát trong cận chiến.","dacDiem":"Trong chương này chủ yếu được dùng làm nghi binh phối hợp thần thông khác.","chuHienThoi":"Vương Lâm","congNang":["Tỏa sát khí khi đồ án trên tay phải lóe lên @c0959","Phối hợp động tác tập kích để tạo thời cơ thi triển Thuật Định Thân @c0959"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0959","denChuong":"","cachCoDuoc":"đã có trước chương này","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0959","loai":"dùng","importance":"normal","giaiDoan":"nghi binh sau lưng","text":"Vương Lâm kích phát Tử Mẫu Khô Thú cốt trên tay phải để tỏa sát khí, làm động tác nghi binh trước khi thi triển Thuật Định Thân.","anchor":"Trên tay phải hắn đồ án Tử Mẫu Khô Thú cốt lại lóe ra"}]},"dinhDanh":"goc","capNhatToi":"@c0959","nguon":["@c0959"]},{"id":"cac-dau-nguoi-chua-ma-khi","name":"Các đầu người chứa ma khí","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm thi thể","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã bị nghiền vỡ làm vật dẫn","blurb":"Các đầu người chứa ma khí là những vật Vương Lâm lấy ra trong tháp đen. Chúng bị nghiền vỡ để tạo lốc xoáy đỏ sậm, làm vật dẫn cho U Minh Dẫn Lộ.","detail":"Sau khi Minh Hải tự diệt và biển lửa Phần Thiên vẫn bao phủ bên ngoài, Vương Lâm vào tháp đen, lấy các đầu người đã thu được trước đó. Vì trong chúng có ma khí, hắn dùng làm vật dẫn để thi triển U Minh Dẫn Lộ, mở thông đạo tới đại điện ma khí.","phanLoaiPhu":"đầu người chứa ma khí","uyLuc":"Có thể cung cấp ma khí làm vật dẫn cho tiên thuật U Minh Dẫn Lộ.","dacDiem":"Bị nghiền nát thành lốc xoáy đỏ sậm khi sử dụng.","chuHienThoi":"Vương Lâm","congNang":["Làm vật dẫn ma khí để mở thông đạo bằng U Minh Dẫn Lộ @c0959"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0959","denChuong":"@c0959","cachCoDuoc":"thu được trước đó và lấy ra trong tháp đen","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0959","loai":"dùng","importance":"normal","giaiDoan":"dẫn đường ma khí","text":"Vương Lâm nghiền các đầu người chứa ma khí để tạo lốc xoáy đỏ sậm, dùng làm vật dẫn mở thông đạo.","anchor":"Trong cơ thể những người này đều có ma khí"}]},"dinhDanh":"goc","capNhatToi":"@c0959","nguon":["@c0959"]},{"id":"tinh-the-hinh-thoi-mau-vang","name":"Tinh thể hình thoi màu vàng","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"chưa rõ","soHuu":["Vương Lâm"],"trangThai":"đang do Vương Lâm giữ, chưa tra xét","blurb":"Tinh thể màu vàng do bóng người thần bí trên ngai vàng ném ra qua thông đạo. Vật này xuyên qua vòng xoáy sụp đổ và thanh quang thuẫn rồi dừng trước mặt Vương Lâm.","detail":"Tinh thể có hình thoi, nằm trong đạo hoàng quang được bóng người trong đại điện ném ra khi thông đạo sụp đổ. Vương Lâm thu lấy nhưng chưa dám dùng thần thức tra xét vì nguyên lực chưa khôi phục.","phanLoaiPhu":"tinh thể","hinhDang":"hình thoi, màu vàng","chuHienThoi":"Vương Lâm","congNang":["Công dụng chưa rõ, nhưng được bóng người thần bí cố ý đưa ra qua thông đạo bị quấy nhiễu. @c0960"],"chuSoHuu":[{"ten":"Bóng người thần bí trên ngai vàng","tuChuong":"@c0960","denChuong":"@c0960","cachCoDuoc":"xuất hiện trong tay và ném ra khỏi đại điện","trangThai":"đã chuyển khỏi tay"},{"ten":"Vương Lâm","tuChuong":"@c0960","denChuong":"","cachCoDuoc":"thu lấy sau khi tinh thể xuyên qua thanh quang thuẫn và dừng trước mặt","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0960","loai":"xuất hiện","importance":"normal","giaiDoan":"được ném qua thông đạo","text":"Tinh thể hình thoi màu vàng xuất hiện trong đạo hoàng quang do bóng người thần bí ném ra, xuyên qua vòng xoáy và thanh quang thuẫn trước khi dừng trước mặt Vương Lâm.","anchor":"bên trong đạo hoàng quang kia có một tinh thể hình thoi"}]},"capNhatToi":"@c0960","nguon":["@c0960"]},{"id":"nguyen-than-cua-huyen-bao-thuong-nhan","name":"Nguyên thần của Huyền Bảo Thượng Nhân","cn":"","aliases":[],"category":"khac","categoryLabel":"Nguồn tiên lực","phamCap":"chưa rõ","soHuu":["Vương Lâm"],"trangThai":"bị Vương Lâm dùng để khôi phục tiên lực","blurb":"Nguyên thần của Huyền Bảo Thượng Nhân được Vương Lâm lấy ra trong hắc tháp để bổ sung tiên lực. Nó hiện ra dưới dạng huỳnh quang trắng ngà có tiên lực tinh thuần.","detail":"Sau khi tiên lực trong cơ thể tiêu hao nhiều, Vương Lâm lấy nguyên thần Huyền Bảo Thượng Nhân ra và hấp thu tiên khí từ huỳnh quang trắng ngà. Việc này giúp tiên lực của hắn khôi phục và tăng thêm.","phanLoaiPhu":"nguyên thần","hinhDang":"huỳnh quang trắng ngà","chuHienThoi":"Vương Lâm","congNang":["Cung cấp tiên khí tinh thuần để Vương Lâm khôi phục và gia tăng tiên lực. @c0960"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0960","denChuong":"","cachCoDuoc":"giữ lại từ trước và lấy ra sử dụng trong hắc tháp","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0960","loai":"dùng","importance":"normal","giaiDoan":"bổ sung tiên lực","text":"Vương Lâm đặt huỳnh quang chứa nguyên thần Huyền Bảo Thượng Nhân trước mũi để hấp thu tiên khí, nhờ đó khôi phục và tăng thêm tiên lực.","anchor":"Trong ánh huỳnh quang này có tiên lực lượn lờ"}]},"capNhatToi":"@c0960","nguon":["@c0960"]},{"id":"ngon-lua-trong-hoang-mac-cat-den","name":"Ngọn lửa trong hoang mạc cát đen","cn":"","aliases":[],"category":"khac","categoryLabel":"Dị hỏa / nguồn nguyên lực","phamCap":"chưa rõ","soHuu":["Vương Lâm"],"trangThai":"một phần bị Vương Lâm nuốt vào luyện hóa","blurb":"Ngọn lửa bao phủ bên ngoài hắc tháp trong hoang mạc cát đen, dung nhập thiên địa nguyên lực khan hiếm của nơi này. Vương Lâm bắt một ngọn lửa nhỏ và nuốt vào để tìm cách bổ sung nguyên lực.","detail":"Do thiên địa nguyên lực trong hoang mạc cát đen rất ít và phần còn lại bị biển lửa dung nhập, Vương Lâm suy tính rằng phải đưa lửa vào nguyên thần mới có thể hấp thụ nguyên lực bên trong. Ngọn lửa gây thiêu đốt dữ dội, khiến thân thể và nguyên thần hắn chịu áp lực lớn.","phanLoaiPhu":"dị hỏa","nguonGoc":"biển lửa ngoài hắc tháp trong hoang mạc cát đen","uyLuc":"Gây thiêu đốt cực mạnh, làm tay phải Vương Lâm nứt khô và khiến thân thể đau đớn sau khi nuốt vào.","congNang":["Chứa thiên địa nguyên lực đã dung nhập vào lửa trong hoang mạc cát đen. @c0960"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0960","denChuong":"@c0960","cachCoDuoc":"bước ra khỏi hắc tháp bắt lấy một phần ngọn lửa đang lao tới","trangThai":"đã nuốt vào để luyện nguyên lực"}],"tabs":{"tienTrinh":[{"chuong":"@c0960","loai":"dùng","importance":"normal","giaiDoan":"nuốt lửa luyện nguyên lực","text":"Vương Lâm bắt một ngọn lửa nhỏ ngoài hắc tháp, nuốt vào cơ thể rồi dẫn phần lửa đã dung nhập nguyên lực xông vào nguyên thần để thử hấp thụ thiên địa nguyên lực bên trong.","anchor":"Chỉ có dung nhập vào nguyên thần mới có thể thật sự hấp thụ"}]},"capNhatToi":"@c0960","nguon":["@c0960"]},{"id":"ngoc-gian-xanh-tim-cua-hu-khong-tu","name":"Ngọc giản xanh tím của Hư Không Tử","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Chưa rõ","soHuu":["Hư Không Tử"],"trangThai":"Đang được Hư Không Tử sử dụng trong thế giới trong bình","blurb":"Ngọc giản hai màu xanh tím do Hư Không Tử cầm khi dò xét thế giới trong bình.","detail":"Ngọc giản này tỏa hào quang rộng lớn, bao phủ vô số dặm quanh Hư Không Tử khi hắn nhận định lai lịch thế giới trong bình của Thanh Lâm Tiên Đế.","nguon":["@c0962"]},{"id":"cuon-tranh-mau-xam-xanh-luc-cua-boi-la","name":"Cuốn tranh màu xám / xanh lục của Bối La","cn":"","aliases":["Cuốn tranh màu xám","Cuốn tranh màu xanh lục"],"category":"phap-bao","categoryLabel":"Pháp bảo dạng tranh","phamCap":"không rõ","soHuu":["Cổ Yêu Bối La"],"trangThai":"đã bị yêu hóa","blurb":"Cuốn tranh trong tay Cổ Yêu Bối La vốn phát tiên khí và chống cự. Sau khi Bối La dùng yêu lực phá phong ấn, tiên khí biến mất, yêu khí tràn ra và màu tranh đổi sang xanh lục.","detail":"Khi giới cuối trong bình sụp đổ, Bối La cầm cuốn tranh màu xám phát tiên khí nồng đậm. Hắn dùng yêu lực cùng bảy Yêu Tinh trong mắt phải ép phá phong ấn, dập tiếng rít không cam lòng trong tranh, khiến tiên khí chuyển thành yêu khí và màu tranh biến từ xám sang xanh lục.","dinhDanh":"goc","chuHienThoi":"Cổ Yêu Bối La","trangThaiVat":"đã bị yêu hóa","congNang":["Phóng tiên khí trước khi bị Bối La phá phong ấn @c0963","Sau khi phong ấn bị phá, tiên khí biến mất và yêu khí vô tận tràn ra @c0963"],"dacDiem":"Màu sắc chuyển từ xám sang xanh lục sau khi bị yêu lực của Bối La cải biến.","chuSoHuu":[{"ten":"Cổ Yêu Bối La","tuChuong":"@c0963","denChuong":"","cachCoDuoc":"Cầm trong tay khi giới cuối trong bình sụp đổ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0963","loai":"khai phong","importance":"major","giaiDoan":"Tiên khí chuyển yêu khí","text":"Bối La dùng yêu lực và bảy Yêu Tinh phá phong ấn trên cuốn tranh, khiến tiên khí tiêu tán và yêu khí tràn ra. Màu tranh đổi từ xám sang xanh lục.","anchor":"Tiếng rít gào kia tiêu tan, cuốn tranh vốn phát ra tiên khí nồng đậm"}]},"capNhatToi":"@c0963","nguon":["@c0963"]},{"id":"ao-giap-den-cua-tan-dao","name":"Áo giáp đen của Tàn Đao","cn":"","aliases":["Áo giáp đen của Tán Ma"],"category":"phap-bao","categoryLabel":"Giáp ma đạo","phamCap":"không rõ","soHuu":["Tàn Đao"],"trangThai":"đang dùng","blurb":"Áo giáp tối đen lộ ra khi sương ma quanh Tàn Đao bị biển lửa ép lùi. Trên giáp có hoa văn phức tạp và ma khí âm u, cuối chương phát ra ma khí thành hai lốc xoáy đen.","detail":"Áo giáp gắn với thân phận Tàn Đao hiện đã thành Tán Ma. Khi hắn dang hai tay, ma khí dày đặc từ áo giáp phát ra và hình thành hai cơn lốc xoáy màu đen trên hai cánh tay.","dinhDanh":"goc","chuHienThoi":"Tàn Đao","trangThaiVat":"đang dùng","congNang":["Phát ra ma khí nồng đậm và hình thành hai cơn lốc xoáy đen trên hai cánh tay Tàn Đao @c0963"],"dacDiem":"Tối đen, có hoa văn phức tạp và ma khí âm u bao phủ.","chuSoHuu":[{"ten":"Tàn Đao","tuChuong":"@c0963","denChuong":"","cachCoDuoc":"Đang mặc khi hiện thân trong động phủ Tiên Đế","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0963","loai":"dùng","importance":"normal","giaiDoan":"Ma khí tụ lốc","text":"Áo giáp đen của Tàn Đao phát ra ma khí nồng đậm và tụ thành hai cơn lốc xoáy màu đen trên hai cánh tay hắn.","anchor":"Vừa nhìn liền có thể thấy ngay được đó là một áo giáp tối đen"}]},"capNhatToi":"@c0963","nguon":["@c0963"]},{"id":"thanh-khi-cua-phu-toc","name":"Thánh khí của Phù Tộc","cn":"","category":"khac","categoryLabel":"Thánh khí","phamCap":"Không rõ","soHuu":["Phù Tộc","Tán Ma"],"trangThai":"đang được Tán Ma mượn","blurb":"Thánh khí của Phù Tộc được Tán Ma mượn để vùi lấp Tiên Trì. Nó gắn trực tiếp với bẫy hiến tế Cổ Ma dưới nơi chôn Thanh Lâm.","detail":"Tán Ma nói hắn mượn thánh khí của Phù Tộc để vùi lấp Tiên Trì, biến nơi này thành bẫy lốc xoáy nhằm hiến tế máu thịt và hồn phách đoàn người cho Cổ Ma.","congNang":["Vùi lấp Tiên Trì @c0964"],"chuSoHuu":[{"ten":"Phù Tộc","tuChuong":"@c0964","denChuong":"","cachCoDuoc":"Sở hữu thánh khí","trangThai":"chủ gốc"},{"ten":"Tán Ma","tuChuong":"@c0964","denChuong":"","cachCoDuoc":"Mượn thánh khí để vùi lấp Tiên Trì","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0964","loai":"xuất hiện","importance":"normal","giaiDoan":"Vùi lấp Tiên Trì","text":"Tán Ma nói hắn mượn thánh khí của Phù Tộc để vùi lấp Tiên Trì.","anchor":"mượn thánh khí của Phù Tộc, vùi lấp Tiên Trì"}]},"capNhatToi":"@c0964","nguon":["@c0964"]},{"id":"vat-phong-an-phia-sau-thu-dao","name":"Vật phong ấn phía sau Thu Dao","cn":"","category":"khac","categoryLabel":"Vật phong ấn","phamCap":"Không rõ","soHuu":["Thanh Lâm"],"trangThai":"đang phong ấn Thu Dao","blurb":"Vật phong ấn chưa rõ tên ở phía sau Thu Dao. Bối La nhìn thấy nó thì kinh sợ và cho rằng ngay cả thời đỉnh cao cũng không cứu được nàng.","detail":"Sau khi nhận ra nữ tử mờ ảo là lão bằng hữu, Bối La nhìn thấy vật phong ấn phía sau nàng và lập tức bỏ ý cứu. Hắn nhận định Thanh Lâm quá độc, dùng vật ấy khiến ngay cả sức mạnh đỉnh cao của hắn cũng không thể giải cứu.","congNang":["Phong ấn Thu Dao dưới Tiên Trì @c0964"],"chuSoHuu":[{"ten":"Thanh Lâm","tuChuong":"@c0964","denChuong":"","cachCoDuoc":"Dùng để phong ấn Thu Dao","trangThai":"vật phong ấn"}],"tabs":{"tienTrinh":[{"chuong":"@c0964","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ vật phong ấn","text":"Bối La nhìn thấy vật phong ấn phía sau Thu Dao và cho rằng ngay cả thời đỉnh cao cũng không thể cứu nàng ra.","anchor":"Không ngờ lấy vật ấy để phong ấn, với sức mạnh của ta"}]},"capNhatToi":"@c0964","nguon":["@c0964"]},{"id":"soi-gan-do-tham","name":"Sợi gân đỏ thẫm","cn":"","category":"khac","categoryLabel":"Phong ấn / vật khóa","phamCap":"không rõ","soHuu":["Thanh Lâm"],"trangThai":"đang phong ấn Thu Dao @c0966","blurb":"Sợi gân đỏ thẫm khóa hai chân Thu Dao trong Táng Tiên Trì và duy trì phong ấn ngăn nàng thoát ra.","detail":"Vật khóa này quấn ở hai chân Thu Dao, phát hồng quang tạo quầng sáng trói nàng lại. Khi Thu Dao định nhấc Táng Tiên Trì lên, sợi gân đỏ thẫm hiện vô số dấu ấn tinh quang, ngưng tụ thành cấm chế phân thân Thanh Lâm.","phanLoaiPhu":"vật khóa phong ấn","hinhDang":"sợi gân màu đỏ thẫm","congNang":["Khóa hai chân Thu Dao và kéo nàng trở lại khi phong ấn bị chấn động @c0966","Phát dấu ấn tinh quang để ngưng tụ cấm chế phân thân Thanh Lâm @c0966"],"chuSoHuu":[{"ten":"Thanh Lâm","tuChuong":"@c0966","denChuong":"","cachCoDuoc":"để lại trong Táng Tiên Trì làm phong ấn","trangThai":"đang duy trì phong ấn"}],"tabs":{"tienTrinh":[{"chuong":"@c0966","loai":"xuất hiện","importance":"normal","giaiDoan":"Hiện rõ khi Thu Dao bị khóa trong Táng Tiên Trì.","text":"Sợi gân đỏ thẫm dưới chân Thu Dao phát hồng quang, tạo quầng sáng trói nàng và gọi ra dấu ấn phong ấn.","anchor":"sợi gân màu đỏ thẫm dưới chân nữ tử bỗng phát ra hồng quang"}]},"capNhatToi":"@c0966","nguon":["@c0966"]},{"id":"cam-che-phan-than-thanh-lam","name":"Cấm chế phân thân Thanh Lâm","cn":"","category":"khac","categoryLabel":"Cấm chế phân thân / phong ấn","phamCap":"không rõ","soHuu":["Thanh Lâm"],"trangThai":"đang ngăn Thu Dao thoát khỏi Táng Tiên Trì @c0966","blurb":"Cấm chế phân thân Thanh Lâm là bóng người kim bào do dấu ấn trên sợi gân đỏ thẫm ngưng tụ, chuyên ngăn Thu Dao thoát khỏi phong ấn.","detail":"Bóng người này không phải Thanh Lâm thật, không có thần trí, ký ức hay thần thông bản thể. Nó chỉ còn bản năng duy nhất là ngăn thánh tổ Thu Dao của Phù Tộc thoát khỏi Táng Tiên Trì.","phanLoaiPhu":"cấm chế phân thân","nguonGoc":"Thanh Lâm lưu lại trong Táng Tiên Trì","congNang":["Duy trì phong ấn Thu Dao trong Táng Tiên Trì @c0966","Ngưng tụ thành bóng người kim bào có khí tức áp đảo để ngăn Thu Dao thoát ra @c0966"],"chuSoHuu":[{"ten":"Thanh Lâm","tuChuong":"@c0966","denChuong":"","cachCoDuoc":"cấm chế do Thanh Lâm năm đó lưu lại","trangThai":"đang vận hành"}],"tabs":{"tienTrinh":[{"chuong":"@c0966","loai":"xuất hiện","importance":"major","giaiDoan":"Hiện thân khi Thu Dao định nhấc Táng Tiên Trì.","text":"Cấm chế phân thân Thanh Lâm từ dấu ấn trên sợi gân đỏ thẫm ngưng tụ thành bóng người kim bào để ngăn Thu Dao thoát ra.","anchor":"một cấm chế phân thân năm đó hắn lưu lại trong Táng Tiên Trì"}]},"capNhatToi":"@c0966","nguon":["@c0966"]},{"id":"chu-tuoc-thanh-tuong","name":"Chu Tước Thánh Tượng","cn":"","category":"khac","categoryLabel":"Thánh tượng tông môn","phamCap":"Không rõ","soHuu":["Chu Tước Thánh Tông"],"trangThai":"đang tồn tại","blurb":"Chu Tước Thánh Tượng là các pho tượng Chu Tước trên chín Chu Tước Thánh Tinh, biểu tượng của toàn bộ Chu Tước Thánh Tinh.","detail":"Các Thánh Tượng hằng ngày tỏa sức mạnh lửa để đệ tử Chu Tước Thánh Tông tu luyện. Khi Chu Tước Chi Biến bùng phát, chúng hút toàn bộ lửa trên tinh cầu rồi hóa thành cột lửa lao ra tinh vực.","phanLoaiPhu":"Thánh tượng, biểu tượng tông môn","hinhDang":"Tượng Chu Tước khổng lồ","chuHienThoi":"Chu Tước Thánh Tông","congNang":["Tỏa sức mạnh lửa cho đệ tử Chu Tước Thánh Tông tu luyện @c0967","Hút lửa toàn tinh cầu và dẫn phát cột lửa trong Chu Tước Chi Biến @c0967"],"dacDiem":"Là biểu tượng của Chu Tước Thánh Tinh và trung tâm nghi thức tu luyện hằng ngày.","capNhatToi":"@c0967","tabs":{"tienTrinh":[{"chuong":"@c0967","loai":"xuất hiện","importance":"normal","giaiDoan":"Bùng phát Chu Tước Chi Biến","text":"Chu Tước Thánh Tượng vừa là biểu tượng của Chu Tước Thánh Tinh vừa là nơi phát sinh biến động hút lửa và tạo cột lửa trong Chu Tước Chi Biến.","anchor":"Đây chính là biểu tượng cho toàn bộ Chu Tước Thánh Tinh"}]},"nguon":["@c0967"]},{"id":"thu-cot-mau-do-cua-thu-dao","name":"Thú Cốt màu đỏ của Thu Dao","aliases":["Thú Cốt"],"cn":"","category":"phap-bao","categoryLabel":"Vật dẫn thần thông","phamCap":"Không rõ","soHuu":["Thu Dao"],"trangThai":"bị suy yếu linh tính","blurb":"Thú Cốt màu đỏ của Thu Dao là vật dẫn thần thông từ ký hiệu nơi mi tâm nàng hóa ra, mang sát khí cực mạnh.","detail":"Thú Cốt có hình dáng dữ tợn giống Tử Mẫu Đạo Khô của Vương Lâm nhưng khác màu sắc và pháp thuật ẩn chứa. Nó bị tinh quang của phân thân Thanh Lâm xuyên thấu, rút khí đỏ và làm mất linh tính.","phanLoaiPhu":"Vật dẫn thần thông","hinhDang":"Thú Cốt màu đỏ dữ tợn","chuHienThoi":"Thu Dao","uyLuc":"Tỏa sát khí ngợp trời khi được Thu Dao phóng ra.","dacDiem":"Hình dáng giống Tử Mẫu Đạo Khô nhưng màu sắc và pháp thuật khác biệt.","congNang":["Từ ký hiệu mi tâm Thu Dao hóa ra để công kích phân thân Thanh Lâm @c0967","Mang sát khí ngợp trời và chứa quy tắc thần thông của Thu Dao @c0967"],"chuSoHuu":[{"ten":"Thu Dao","tuChuong":"@c0967","denChuong":"","cachCoDuoc":"Từ ký hiệu nơi mi tâm hóa ra","trangThai":"đang sở hữu nhưng vật bị suy yếu linh tính"}],"capNhatToi":"@c0967","tabs":{"tienTrinh":[{"chuong":"@c0967","loai":"dùng","importance":"normal","giaiDoan":"Tấn công Thanh Lâm","text":"Thu Dao phóng Thú Cốt màu đỏ từ mi tâm để tấn công phân thân Thanh Lâm, nhưng nó bị tinh quang xuyên thấu và mất linh tính.","anchor":"liền có một ký hiệu cực kỳ phức tạp lóe ra, ngay lập tức hóa thành một Thú Cốt màu đỏ"}]},"nguon":["@c0967"]},{"id":"tinh-the-phong-an-trong-thu-cot","name":"Tinh thể phong ấn trong Thú Cốt","cn":"","category":"khac","categoryLabel":"Tinh thể phong ấn","phamCap":"Không rõ","soHuu":["Thanh Lâm"],"trangThai":"mới hiện ra","blurb":"Tinh thể phong ấn trong Thú Cốt là kết quả sau khi tinh điểm của Thanh Lâm rút khí đỏ trong Thú Cốt của Thu Dao.","detail":"Tinh thể rực rỡ to bằng nắm tay hiện ra bên trong Thú Cốt và bùng hào quang như kiếm sắc, biểu hiện việc quy tắc thần thông của Thu Dao bị chuyển thành thuật phong ấn.","phanLoaiPhu":"Tinh thể, kết quả phong ấn","hinhDang":"Tinh thể rực rỡ to bằng nắm tay","chuHienThoi":"Thanh Lâm","congNang":["Biểu hiện quá trình thần thông trong Thú Cốt bị chuyển thành phong ấn @c0967","Tỏa hào quang như kiếm sắc sau khi khí đỏ bị rút ra @c0967"],"capNhatToi":"@c0967","tabs":{"tienTrinh":[{"chuong":"@c0967","loai":"xuất hiện","importance":"normal","giaiDoan":"Hóa ra từ Thú Cốt","text":"Sau khi tinh quang của Thanh Lâm rút khí đỏ trong Thú Cốt, tinh thể phong ấn rực rỡ hiện ra và tỏa hào quang sắc bén.","anchor":"bên trong Thú Cốt kia liền có một tinh thể rực rỡ to bằng nắm tay"}]},"nguon":["@c0967"]},{"id":"tang-tien-tri","name":"Táng Tiên Trì","cn":"","aliases":["ao đen","Táng Tiên Trì danh chấn Tiên Giới"],"category":"phap-bao","categoryLabel":"Trọng vật Tiên Giới","phamCap":"không rõ","soHuu":["Tiên Giới","Thu Dao"],"trangThai":"sụp đổ @c0969","blurb":"Táng Tiên Trì là ao đen danh chấn Tiên Giới, nơi giam ép Thu Dao bằng vô số hồn phách.","detail":"Trong chương này, Thu Dao dẫn động vô số hồn phách bên trong Táng Tiên Trì để đồng quy vu tận. Ao đen rộng mười trượng hiện hình, đầy máu đen và tiên khí âm trầm, rồi nứt vỡ sụp đổ, tạo lực công kích đánh tan mọi người trong Tiên Phủ.","hinhDang":"ao đen rộng mười trượng, bên trong đầy máu đen và tiên khí âm trầm","uyLuc":"Khi sụp đổ, lực công kích phá phong ấn quanh động phủ và đánh tan toàn bộ người trong Tiên Phủ.","chuHienThoi":"Thu Dao","congNang":["Giam ép Thu Dao bằng vô số hồn phách trong Táng Tiên Trì @c0969","Khi sụp đổ tạo lực công kích quét ngang Tiên Phủ và phá phong ấn Tán Ma @c0969"],"chuSoHuu":[{"ten":"Thu Dao","tuChuong":"@c0969","denChuong":"@c0969","cachCoDuoc":"hợp nhất với Táng Tiên Trì suốt vô số năm","trangThai":"dẫn động đồng quy vu tận"}],"tabs":{"tienTrinh":[{"chuong":"@c0969","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Thu Dao đồng quy vu tận","text":"Thu Dao dẫn động hồn phách trong Táng Tiên Trì để cùng hủy diệt. Táng Tiên Trì hiện hình rồi sụp đổ, tạo lực công kích đánh tan mọi người trong Tiên Phủ.","anchor":"Táng Tiên Trì danh chấn Tiên Giới này ầm một tiếng sụp đổ","phamCap":"không rõ"}]},"dinhDanh":"goc","capNhatToi":"@c0969","nguon":["@c0969"]},{"id":"thanh-binh-chi-bao-cua-phu-toc","name":"Thánh Bình chí bảo của Phù Tộc","cn":"","aliases":["Thánh Bình"],"category":"phap-bao","categoryLabel":"Chí bảo","phamCap":"chí bảo","soHuu":["Phù Tộc"],"trangThai":"không rõ @c0969","blurb":"Thánh Bình là chí bảo của Phù Tộc từng bị Thanh Lâm nhắm tới trong đại chiến với Tiên Giới.","detail":"Thu Dao kể Thanh Lâm từng vì muốn cướp đoạt Thánh Bình chí bảo của Phù Tộc mà giết vô số cao thủ trong cuộc đại chiến giữa Phù Tộc và Tiên Giới.","nguonGoc":"chí bảo Phù Tộc","chuHienThoi":"Phù Tộc","congNang":["Là chí bảo của Phù Tộc, từng khiến Thanh Lâm muốn cướp đoạt @c0969"],"tabs":{"tienTrinh":[{"chuong":"@c0969","loai":"nhắc tới","importance":"normal","giaiDoan":"Thu Dao kể đại chiến","text":"Thu Dao nhắc Thanh Lâm từng muốn cướp đoạt Thánh Bình chí bảo của Phù Tộc trong đại chiến với Tiên Giới.","anchor":"muốn cướp đoạt Thánh Bình chí bảo của tộc ta","phamCap":"chí bảo"}]},"dinhDanh":"goc","capNhatToi":"@c0969","nguon":["@c0969"]},{"id":"thanh-quang-hai-mat-cua-thu-dao","name":"Thanh quang hai mắt của Thu Dao","cn":"","aliases":["hai luồng thanh quang"],"category":"khac","categoryLabel":"Truyền thừa","phamCap":"không rõ","soHuu":["Thu Dao","Vương Lâm"],"trangThai":"đã trao cho Vương Lâm @c0969","blurb":"Thanh quang hai mắt của Thu Dao là vật truyền thừa nàng rút ra và trao cho Vương Lâm trước khi Táng Tiên Trì sụp đổ.","detail":"Thu Dao rút hai luồng thanh quang thay thế hai mắt, hợp làm một và ném cho Vương Lâm. Qua đó, nàng truyền cho hắn sức mạnh ký hiệu Phù Tộc và phương pháp chế tác Khô Phù.","hinhDang":"hai luồng thanh quang hợp làm một","chuHienThoi":"Vương Lâm","congNang":["Truyền sức mạnh ký hiệu Phù Tộc cho Vương Lâm @c0969","Chứa thần niệm về phương pháp chế tác Khô Phù @c0969"],"chuSoHuu":[{"ten":"Thu Dao","tuChuong":"@c0969","denChuong":"@c0969","cachCoDuoc":"thanh quang thay thế hai mắt của nàng","trangThai":"đã trao"},{"ten":"Vương Lâm","tuChuong":"@c0969","denChuong":"","cachCoDuoc":"được Thu Dao ném thanh quang cho","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0969","loai":"đổi chủ","importance":"normal","giaiDoan":"Thu Dao trao cho Vương Lâm","text":"Thu Dao rút hai luồng thanh quang thay thế hai mắt, hợp lại và ném cho Vương Lâm. Thanh quang truyền sức mạnh ký hiệu cùng Khô Phù Thuật cho hắn.","anchor":"hai luồng thanh quang bên trong thay thế cho hai mắt bị nàng rút ra","phamCap":"không rõ"}]},"dinhDanh":"goc","capNhatToi":"@c0969","nguon":["@c0969"]},{"id":"tinh-the-mau-vang","name":"Tinh thể màu vàng","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm","Thanh Lâm"],"trangThai":"đã dung nhập phân thân Thanh Lâm","blurb":"Tinh thể màu vàng là vật mà nam tử thần bí từng đưa cho Vương Lâm. Trong chương này, phân thân Thanh Lâm hóa tinh quang dung nhập vào tinh thể ấy.","detail":"Khi thân ảnh Vương Lâm sắp tiêu tán, một đạo tinh quang phá cấm chế xuyên vào túi trữ vật của hắn và nhập vào tinh thể màu vàng. Vương Lâm nhận ra đó là phân thân của Thanh Lâm, khiến tinh thể này trở thành vật chứa hoặc điểm tiếp nhận phân thân Thanh Lâm.","dinhDanh":"goc","chuHienThoi":"Vương Lâm","congNang":["Tiếp nhận phân thân Thanh Lâm hóa thành tinh quang."],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0970","denChuong":"","cachCoDuoc":"Được nam tử thần bí trong đại điện từng đưa cho trước đó.","trangThai":"đang giữ trong túi trữ vật"},{"ten":"Thanh Lâm","tuChuong":"@c0970","denChuong":"","cachCoDuoc":"Phân thân hóa tinh quang dung nhập vào tinh thể.","trangThai":"phân thân nhập vào"}],"tabs":{"tienTrinh":[{"chuong":"@c0970","loai":"khai phong","importance":"major","giaiDoan":"Phân thân nhập tinh thể","text":"Phân thân Thanh Lâm phá cấm chế, xuyên vào túi trữ vật Vương Lâm và dung nhập tinh thể màu vàng mà nam tử bí ẩn từng đưa.","anchor":"dung nhập vào trong tinh thể màu vàng mà nam tử bí ẩn ở đại điện đưa cho"}]},"capNhatToi":"@c0970","nguon":["@c0970"]},{"id":"linh-dang-cua-thanh-lam","name":"Linh đăng của Thanh Lâm","cn":"","category":"khac","categoryLabel":"Trận đăng","phamCap":"không rõ","soHuu":["Thanh Lâm"],"trangThai":"chỉ còn mười hai ngọn cháy","blurb":"Linh đăng trong trận pháp chín mươi chín giá nến tại đại điện tím, liên hệ trực tiếp tới trạng thái của Thanh Lâm. Trong chương này hai mươi ba ngọn bị dập tắt khiến ông trọng thương.","detail":"Tại đại điện tím, sau khi sáu mươi tư ngọn đã tắt từ trước, luồng gió ký hiệu tiếp tục dập tắt hai mươi ba ngọn trong số ba mươi lăm ngọn còn cháy. Thanh Lâm phun máu đen và chỉ còn mười hai ngọn, đồng thời tự hỏi thời gian của mình còn đủ hay không.","dinhDanh":"goc","chuHienThoi":"Thanh Lâm","dacDiem":"Số linh đăng còn cháy gắn với sinh cơ hoặc thời gian còn lại của Thanh Lâm.","congNang":["Duy trì hoặc phản ánh trạng thái tồn tại của Thanh Lâm trong đại điện tím."],"chuSoHuu":[{"ten":"Thanh Lâm","tuChuong":"@c0970","denChuong":"","cachCoDuoc":"Gắn với trận pháp trong đại điện tím của động phủ Tiên Đế.","trangThai":"còn mười hai ngọn"}],"tabs":{"tienTrinh":[{"chuong":"@c0970","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Hai mươi ba ngọn tắt","text":"Hai mươi ba linh đăng bị dập tắt, khiến Thanh Lâm phun máu và chỉ còn mười hai ngọn cháy.","anchor":"Hai mươi ba ngọn đã tắt… Chỉ còn lại mười hai ngọn"}]},"capNhatToi":"@c0970","nguon":["@c0970"]},{"id":"hai-mat-thu-dao","name":"Hai mắt Thu Dao","cn":"","category":"khac","categoryLabel":"Nguồn lực bị đoạt","phamCap":"không rõ","soHuu":["Thu Dao","Thanh Lâm"],"trangThai":"bị Thanh Lâm lấy đi","blurb":"Hai mắt của Thu Dao được Thanh Lâm nói là nơi chứa Thái Sơ Lực. Vì sợ sức mạnh ấy hủy diệt Tiên Giới và Phong Giới, ông đã lấy hai mắt nàng.","detail":"Trong hồi ức, Thanh Lâm nói khi ở bên Thu Dao, nàng từng cho ông mượn sức mạnh trong hai mắt. Sau khi biết đó là Thái Sơ Lực của Chưởng Tôn, ông lấy hai mắt Thu Dao rồi phong ấn nàng vào Táng Tiên Trì thay vì giết.","dinhDanh":"goc","chuHienThoi":"Thanh Lâm","congNang":["Chứa Thái Sơ Lực có thể hủy diệt Tiên Giới và Phong Giới theo lời Thanh Lâm."],"chuSoHuu":[{"ten":"Thu Dao","tuChuong":"@c0970","denChuong":"@c0970","cachCoDuoc":"Bộ phận vốn thuộc Thu Dao.","trangThai":"bị lấy đi"},{"ten":"Thanh Lâm","tuChuong":"@c0970","denChuong":"","cachCoDuoc":"Lấy hai mắt Thu Dao để ngăn Thái Sơ Lực tản ra.","trangThai":"đã đoạt"}],"tabs":{"tienTrinh":[{"chuong":"@c0970","loai":"đổi chủ","importance":"major","giaiDoan":"Thanh Lâm lấy mắt","text":"Thanh Lâm nói ông lấy hai mắt Thu Dao vì trong đó có Thái Sơ Lực, sau đó phong ấn nàng trong Táng Tiên Trì.","anchor":"Ta lấy hai mắt ngươi, ngươi đau đớn, ta còn đau đớn hơn"}]},"capNhatToi":"@c0970","nguon":["@c0970"]},{"id":"thanh-khi-thu-dao-tang","name":"Thanh khí Thu Dao tặng","cn":"","category":"khac","categoryLabel":"Vật chứa tri thức","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Thanh khí do Thu Dao tặng cho Vương Lâm, chứa tri thức giúp hắn hiểu Khô Phù.","detail":"Vương Lâm lấy thanh khí ra kiểm tra bằng thần thức sau khi nhớ tới Tháp Sơn và Thu Dao. Thanh khí vận chuyển không ngừng, giúp hắn nhận ra bản chất Khô Phù, các loại phong, băng, độn, giải và phương pháp kích phát tương tự ấn quyết.","dinhDanh":"goc","phanLoaiPhu":"Vật chứa tri thức phù pháp","nguonGoc":"Thu Dao trao cho Vương Lâm","dacDiem":"Thanh khí vận chuyển không ngừng bên trong.","congNang":["Truyền tri thức về Khô Phù và phương pháp kích phát cho Vương Lâm @c0971"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0971","denChuong":"","cachCoDuoc":"Thu Dao tặng trước đó, chương này được lấy ra nghiên cứu.","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0971","loai":"xuất hiện","importance":"normal","giaiDoan":"Dùng để hiểu Khô Phù","text":"Vương Lâm dùng thần thức kiểm tra thanh khí và từ đó hiểu tri thức về Khô Phù.","anchor":"đám thanh khí này không phải là đứng im, mà không ngừng vận chuyển"}]},"capNhatToi":"@c0971","nguon":["@c0971"]},{"id":"manh-giay-mau-vang-ve-ky-hieu-phuc-tap","name":"Mảnh giấy màu vàng vẽ ký hiệu phức tạp","cn":"","aliases":["lá bùa vàng","Khô Phù loại độn"],"category":"khac","categoryLabel":"Lá bùa","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã kích phát","blurb":"Lá bùa vàng cũ của Vương Lâm, trên vẽ ký hiệu phức tạp và được xác định là Khô Phù loại độn.","detail":"Vương Lâm lấy mảnh giấy vàng từ túi trữ vật, nhớ rằng trước đây từng thu được hai chiếc ở La Thiên Tinh Vực. Sau khi đối chiếu tri thức trong thanh khí, hắn dùng máu và ấn quyết kích phát, thấy lốc xoáy đen cùng bóng chim giống đại bàng, rồi xác định đây là Khô Phù loại độn đã mở.","dinhDanh":"goc","phanLoaiPhu":"Lá bùa Khô Phù","hinhDang":"Mảnh giấy màu vàng có ký hiệu phức tạp, cũ kỹ.","nguonGoc":"Vương Lâm từng thu được ở La Thiên Tinh Vực.","congNang":["Khi được kích phát có thể phát huy hiệu quả độn, giúp vật được gắn phù dịch chuyển cực nhanh @c0971"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0971","denChuong":"","cachCoDuoc":"Đã có trong túi trữ vật từ trước, chương này lấy ra đối chiếu và kích phát.","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0971","loai":"khai phong","importance":"normal","giaiDoan":"Kích phát Khô Phù độn","text":"Vương Lâm lấy mảnh giấy vàng có ký hiệu phức tạp ra và kích phát để xác định nó là Khô Phù loại độn.","anchor":"lập tức lấy một mảnh giấy màu vàng, trên đó có vẽ ký hiệu rất phức tạp"}]},"capNhatToi":"@c0971","nguon":["@c0971"]},{"id":"thanh-dai-kiem-tu-sat-vuc-gioi","name":"Thanh đại kiếm từ Sát Vực Giới","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang dùng thử phù","blurb":"Một thanh đại kiếm Vương Lâm lấy từ Sát Vực Giới để thử công năng Khô Phù loại độn.","detail":"Vương Lâm lấy ra một thanh đại kiếm từng thu được từ một trong chín mươi chín Sát Vực Giới. Khi đặt Khô Phù loại độn lên thân kiếm và bấm ấn quyết, thanh kiếm biến mất rồi hiện ra cách mười trượng, giúp hắn kiểm chứng tốc độ đáng sợ của phù.","dinhDanh":"goc","phanLoaiPhu":"Vũ khí thử phù","nguonGoc":"Một trong chín mươi chín Sát Vực Giới","congNang":["Làm vật thử để kiểm chứng hiệu quả dịch chuyển của Khô Phù loại độn @c0971"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0971","denChuong":"","cachCoDuoc":"Lấy từ một trong chín mươi chín Sát Vực Giới trước đó.","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0971","loai":"dùng","importance":"normal","giaiDoan":"Thử Khô Phù loại độn","text":"Vương Lâm dùng thanh đại kiếm từ Sát Vực Giới để thử Khô Phù loại độn và thấy nó dịch chuyển mười trượng.","anchor":"Thanh kiếm này được lấy từ một trong chín mươi chín Sát Vực Giới"}]},"capNhatToi":"@c0971","nguon":["@c0971"]},{"id":"kho-phu","name":"Khô Phù","cn":"","category":"phap-bao","categoryLabel":"Phù bảo mệnh","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm cất giữ @c0972","blurb":"Phù bảo mệnh được Vương Lâm gỡ khỏi thanh đại kiếm dưới biển. Hắn xem đây là thêm một phương pháp bảo mệnh khi gặp nguy hiểm.","detail":"Vương Lâm thu hồi thanh đại kiếm, gỡ Khô Phù trên đó xuống rồi cất vào túi trữ vật. Hắn nhận ra Khô Phù được luyện tốt nhất bằng da mi tâm mãnh thú hung ác, trong đó hồn phách và tinh huyết của mãnh thú phải được tụ lại trước khi lấy da.","dinhDanh":"goc","phanLoaiPhu":"phù bảo mệnh","chuHienThoi":"Vương Lâm","congNang":["Giúp Vương Lâm có thêm một phương pháp bảo mệnh khi gặp nguy hiểm @c0972"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0972","denChuong":"","cachCoDuoc":"Gỡ khỏi thanh đại kiếm sau khi thu hồi dưới biển","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0972","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Vương Lâm thu giữ","text":"Vương Lâm gỡ Khô Phù khỏi thanh đại kiếm, cất vào túi trữ vật và xem nó là một thủ đoạn bảo mệnh.","phamCap":"Không rõ","anchor":"Có Khô Phù này, nếu gặp nguy hiểm, ta lại có thêm một phương pháp bảo mệnh"}]},"capNhatToi":"@c0972","nguon":["@c0972"]},{"id":"phong-than-hoa-ma-phien","name":"Phong Thần Hóa Ma Phiên","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Pháp khí Cổ Yêu, bản mô phỏng bằng yêu khí","soHuu":["Phong Yêu"],"trangThai":"Ba cây cờ lục do yêu khí biến hóa đã tự bạo trong giao chiến với Diệt Thần Mâu","blurb":"Pháp khí Cổ Yêu do Phong Yêu mô phỏng bằng yêu khí toàn thân, hiện thành ba cây cờ lục để triệu hư ảnh Cổ Thần và Cổ Ma. Bản trong chương không phải bản thể thật nên uy lực kém xa nguyên bản.","detail":"Phong Thần Hóa Ma Phiên được Phong Yêu thi triển khi bị Vương Lâm ép vào thế liều mạng. Ba cây cờ lục do yêu khí biến hóa có thể gọi ra hư ảnh một lục tinh Cổ Thần và hai lục tinh Cổ Ma, tạo thế phong tỏa và công kích mạnh, đồng thời kích động cấm chế vùng biển khiến nước biển co rút thành hình người khổng lồ đang ngủ. Phong Yêu tự biết đây chỉ là bản mô phỏng từ yêu khí, không phải pháp khí cổ xưa chân chính, nên khi bị Diệt Thần Mâu khắc chế đã cho ba cờ tự bạo hóa thành cự long xanh để cản đường nhưng vẫn bị đánh tan.","nguon":["@c0973"]},{"id":"ngoc-gian-ban-do-dong-phu-tien-de","name":"Ngọc giản bản đồ động phủ Tiên Đế","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản Vương Lâm từng thu được ở vùng đất Yêu Linh, chứa bản đồ liên quan động phủ Tiên Đế. Chương này xác nhận bản đồ trong ngọc giản mô tả đúng động phủ trước mắt.","detail":"Ngọc giản này làm từ tiên ngọc, ngoài bản đồ còn liên hệ tới phương pháp luyện chế Tiên Vệ và khẩu quyết Định Thân Thuật. Khi đứng ở ngoại vi động phủ Tiên Đế, Vương Lâm lấy ra đối chiếu và nhận ra bản đồ trong ngọc giản chính là động phủ trước mắt.","dinhDanh":"goc","congNang":["Lưu giữ bản đồ mô tả động phủ Tiên Đế ở vùng đất Yêu Linh @c0975","Gắn với nội dung phương pháp luyện chế Tiên Vệ và khẩu quyết Định Thân Thuật @c0975"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0975","denChuong":"","cachCoDuoc":"Từng thu được ở vùng đất Yêu Linh","trangThai":"dang-giu"}],"capNhatToi":"@c0975","tabs":{"tienTrinh":[{"chuong":"@c0975","loai":"xuất hiện","importance":"normal","giaiDoan":"Xác nhận bản đồ","text":"Vương Lâm lấy ngọc giản ra đối chiếu và xác nhận bản đồ trong đó mô tả đúng động phủ Tiên Đế trước mắt.","anchor":"Cái bản đồ kia miêu tả, chính là động phủ ở trước mắt"}]},"nguon":["@c0975"]},{"id":"nguyen-than-cua-nhung-nguoi-da-bi-vuong-lam-giet","name":"Nguyên thần của những người đã bị Vương Lâm giết","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Tài nguyên tu luyện","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Các nguyên thần Vương Lâm cất giữ từ những kẻ từng bị hắn giết. Trong động phủ thiếu thiên địa nguyên lực, hắn nuốt chúng để thúc đẩy phá bình cảnh Khuy Niết Trung Kỳ.","detail":"Khi bế quan trong hố sâu do Táng Tiên Trì lưu lại, Vương Lâm vận chuyển nguyên lực ba ngày nhưng nơi này không đủ thiên địa nguyên lực. Tới ngày thứ tư, hắn lấy ra vài nguyên thần của những người từng bị mình giết và nuốt xuống để tăng lực đột phá.","dinhDanh":"goc","congNang":["Bổ sung lực lượng cho Vương Lâm trong hoàn cảnh thiếu thiên địa nguyên lực, hỗ trợ hắn phá bình cảnh @c0975"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0975","denChuong":"@c0975","cachCoDuoc":"Thu được từ những người từng bị hắn giết","trangThai":"da-dung"}],"capNhatToi":"@c0975","tabs":{"tienTrinh":[{"chuong":"@c0975","loai":"dùng","importance":"normal","giaiDoan":"Nuốt để đột phá","text":"Vương Lâm lấy các nguyên thần đã cất giữ ra nuốt nhằm bổ sung lực lượng để phá bình cảnh trong động phủ thiếu thiên địa nguyên lực.","anchor":"lập tức lấy ra từ bên trong một vài nguyên thần của những người đã bị hắn giết"}]},"nguon":["@c0975"]},{"id":"thai-co-tu-thanh-khi","name":"Thái Cổ Tứ Thánh Khí","cn":"","category":"than-khi","categoryLabel":"Thánh khí","phamCap":"truyền thuyết","soHuu":["Tứ Thánh Tông"],"trangThai":"khong-ro","blurb":"Trọng khí truyền thuyết của Tứ Thánh Tông, từng đủ khiến Tu Chân Liên Minh và Côn Hư Cảnh e ngại.","detail":"Thái Cổ Tứ Thánh Khí là trọng khí có thể khai thiên lập địa của Tứ Thánh Tông. Khi Thanh Long Thánh Hoàng mất tích và Huyền Vũ Thánh Hoàng phản bội, uy lực phối hợp bị suy giảm mạnh, nhưng vẫn đủ khiến Tu Chân Liên Minh và Côn Hư Cảnh không dám ép Tứ Thánh Tông đồng quy vu tận.","phanLoaiPhu":"thánh khí truyền thuyết","nguonGoc":"Tứ Thánh Tông","uyLuc":"Có thể khai thiên lập địa và là lá bài khiến các thế lực địch kiêng kị khả năng đồng quy vu tận.","dacDiem":"Uy lực cần bốn mạch Thánh Tông phối hợp; khi Thanh Long mất tích và Huyền Vũ phản bội thì suy giảm mạnh.","chuHienThoi":"Tứ Thánh Tông","congNang":["Phối hợp để đánh một trận với Côn Hư Cảnh @c0976","Tạo uy hiếp đồng quy vu tận khiến Tu Chân Liên Minh và Côn Hư Cảnh không dám ép Tứ Thánh Tông đến đường cùng @c0976"],"chuSoHuu":[{"ten":"Tứ Thánh Tông","tuChuong":"@c0976","denChuong":"","cachCoDuoc":"trọng khí truyền thừa của tông","trangThai":"khong-ro"}],"tabs":{"tienTrinh":[{"chuong":"@c0976","loai":"xuất hiện","importance":"major","giaiDoan":"hồi thuật đại chiến Tứ Thánh Tông","text":"Thái Cổ Tứ Thánh Khí được lộ là trọng khí khai thiên lập địa của Tứ Thánh Tông và là lá bài khiến địch thủ kiêng kị.","anchor":"bên trong Tứ Thánh Tông còn có Thái Cổ Tứ Thánh Khí có thể khai thiên lập địa","phamCap":"truyền thuyết"}]},"dinhDanh":"goc","capNhatToi":"@c0976","nguon":["@c0976"]},{"id":"nguyen-than-bi-vuong-lam-thu-giu","name":"Nguyên thần bị Vương Lâm thu giữ","cn":"","category":"nguyen-lieu","categoryLabel":"Tài nguyên tu luyện","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Nguồn nguyên thần Vương Lâm lấy từ túi trữ vật ra nuốt để bổ sung nguyên lực trong lúc xung kích tu vi.","detail":"Vương Lâm liên tục lấy nguyên thần ra nuốt, dùng chúng để tích lũy nguyên lực sau khi nguyên lực của hắn đã mang hỏa diễm. Khi đạt Khuy Niết Hậu Kỳ mà chưa thỏa mãn, hắn lấy toàn bộ nguyên thần còn lại ra nuốt để tiếp tục xung kích.","phanLoaiPhu":"nguyên thần","uyLuc":"Có thể chuyển hóa thành nguyên lực để hỗ trợ Vương Lâm đột phá và tiếp tục tăng trưởng tu vi.","dacDiem":"Được cất trong túi trữ vật của Vương Lâm và bị tiêu hao trong quá trình đột phá.","chuHienThoi":"Vương Lâm","congNang":["Bổ sung nguyên lực cho Vương Lâm khi xung kích Khuy Niết Hậu Kỳ @c0976"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c0976","denChuong":"@c0976","cachCoDuoc":"đã thu giữ trước đó và cất trong túi trữ vật","trangThai":"đã dùng để tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c0976","loai":"dùng","importance":"normal","giaiDoan":"xung kích Khuy Niết","text":"Vương Lâm lấy toàn bộ nguyên thần còn lại trong túi trữ vật ra nuốt để tiếp tục tăng nguyên lực.","anchor":"lập tức từ trong túi trữ vật lấy ra toàn bộ những nguyên thần còn lại","phamCap":"không rõ"}]},"dinhDanh":"goc","capNhatToi":"@c0976","nguon":["@c0976"]},{"id":"chuong-dong-trong-mat-that-tong-bo-tu-chan-lien-minh","name":"Chuông đồng trong mật thất tổng bộ Tu Chân Liên Minh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":[],"trangThai":"Đang đặt trong mật thất ở tổng bộ Tu Chân Liên Minh","blurb":"Chuông đồng trong mật thất tổng bộ Tu Chân Liên Minh phát ra âm thanh cảnh báo khi tâm thần Vương Lâm đảo qua nơi này.","detail":"Khi tâm thần Vương Lâm quét qua mật thất trong tổng bộ Tu Chân Liên Minh, nam tử trung niên đang tọa thiền không trực tiếp phát hiện ra hắn, nhưng chiếc chuông phía trên lập tức vang lên âm thanh trong trẻo, khiến nam tử trung niên mở mắt. Vật này thể hiện công năng cảnh báo trước sự xâm nhập hoặc lướt qua của tâm thần lạ.","nguon":["@c0977"]}]};
